import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Bot, Send, Sparkles, TrendingUp, TrendingDown, Target, Shield, BarChart3, MessageSquare, Zap, ArrowRight, RefreshCw } from 'lucide-react';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { useNavigate } from 'react-router-dom';
import { API_BASE_URL } from '../config';

const SUGGESTIONS = [
  { text: "Should I buy RELIANCE?", icon: <TrendingUp size={14} /> },
  { text: "What's the target for TCS?", icon: <Target size={14} /> },
  { text: "Is INFY risky right now?", icon: <Shield size={14} /> },
  { text: "Show RSI for HDFCBANK", icon: <BarChart3 size={14} /> },
  { text: "What's the sentiment on ZOMATO?", icon: <MessageSquare size={14} /> },
  { text: 'Compare TCS vs INFY', icon: <Sparkles size={14} /> },
];

function formatBody(body) {
  // Simple markdown-like formatting 
  return body
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/\n/g, '<br/>');
}

export default function AICopilot() {
  const { user } = useUser();
  const navigate = useNavigate();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const chatEndRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const sendMessage = async (text) => {
    if (!text.trim()) return;
    
    const userMsg = { role: 'user', content: text, timestamp: new Date().toLocaleTimeString() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const res = await axios.post(`${API_BASE_URL}/api/copilot/chat?user_id=${user?.id || 1}`, {
        message: text,
      });

      const copilotResponse = res.data;
      let txHash = null;
      let blockHash = null;

      try {
        // Log prediction to blockchain
        if (copilotResponse.symbol) {
          const logRes = await axios.post(`${API_BASE_URL}/api/predictions/log`, {
            ticker: copilotResponse.symbol,
            predictionText: copilotResponse.body,
            targetPrice: copilotResponse.price,
            timeframe: 'short-term'
          });
          if (logRes.data.success) {
            txHash = logRes.data.txHash;
            blockHash = logRes.data.hash;
          }
        }
      } catch (logErr) {
        console.error("Blockchain logging failed", logErr);
      }

      const aiMsg = {
        role: 'assistant',
        title: copilotResponse.title,
        verdict: copilotResponse.verdict,
        body: copilotResponse.body,
        symbol: copilotResponse.symbol,
        price: copilotResponse.price,
        change_pct: copilotResponse.change_pct,
        confidence: copilotResponse.confidence,
        timestamp: new Date().toLocaleTimeString(),
        txHash,
        blockHash
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (err) {
      setMessages(prev => [...prev, {
        role: 'assistant',
        title: 'ΓÜá∩╕Å Error',
        body: 'Failed to get response. Please try again.',
        verdict: 'ERROR',
        timestamp: new Date().toLocaleTimeString(),
      }]);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    sendMessage(input);
  };

  const verdictColor = (verdict) => {
    const v = verdict?.toUpperCase();
    if (['BUY', 'BULLISH', 'STRONG BUY', 'SUCCESS'].includes(v)) return 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20';
    if (['SELL', 'BEARISH', 'ERROR'].includes(v)) return 'text-red-400 bg-red-500/10 border-red-500/20';
    if (['WAIT', 'HOLD', 'MODERATE'].includes(v)) return 'text-amber-400 bg-amber-500/10 border-amber-500/20';
    return 'text-blue-400 bg-blue-500/10 border-blue-500/20';
  };

  return (
    <div className="space-y-6">
      {/* Hero Header */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="relative overflow-hidden rounded-2xl p-8"
        style={{ background: 'linear-gradient(135deg, rgba(139,92,246,0.15), rgba(0,212,170,0.08))' }}
      >
        <div className="absolute top-0 right-0 w-64 h-64 bg-purple-500/10 rounded-full blur-[100px]" />
        <div className="relative flex items-center gap-4">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-purple-500 to-blue-500 flex items-center justify-center shadow-xl shadow-purple-500/20">
            <Bot className="w-8 h-8 text-white" />
          </div>
          <div>
            <h1 className="text-3xl font-black text-white mb-1">AI Trade Copilot</h1>
            <p className="text-zinc-400 text-sm">Ask anything about stocks ΓÇö get instant AI-powered analysis, targets & sentiment</p>
          </div>
          <div className="ml-auto hidden md:flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 rounded-xl">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
            <span className="text-xs font-bold text-emerald-400 uppercase tracking-wider">AI Online</span>
          </div>
        </div>
      </motion.div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Chat Area */}
        <div className="lg:col-span-3 glass-panel flex flex-col" style={{ minHeight: '65vh' }}>
          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6" style={{ maxHeight: '55vh' }}>
            {messages.length === 0 && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="h-full flex flex-col items-center justify-center text-center py-16"
              >
                <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-500/20 to-blue-500/20 flex items-center justify-center mb-6">
                  <Sparkles className="w-10 h-10 text-purple-400" />
                </div>
                <h3 className="text-xl font-bold text-white mb-2">Start a Conversation</h3>
                <p className="text-zinc-500 text-sm max-w-md mb-8">
                  Ask me about any stock ΓÇö buy/sell analysis, price targets, risk assessment, technical analysis, or market sentiment.
                </p>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3 max-w-2xl">
                  {SUGGESTIONS.map((s, i) => (
                    <button
                      key={i}
                      onClick={() => sendMessage(s.text)}
                      className="flex items-center gap-2 px-4 py-3 bg-white/[0.03] border border-white/[0.06] rounded-xl text-sm text-zinc-400 hover:text-white hover:bg-white/[0.06] hover:border-white/10 transition-all text-left group"
                    >
                      <span className="text-primary group-hover:scale-110 transition-transform">{s.icon}</span>
                      <span className="truncate">{s.text}</span>
                    </button>
                  ))}
                </div>
              </motion.div>
            )}

            <AnimatePresence>
              {messages.map((msg, i) => (
                <motion.div
                  key={i}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.05 }}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  {msg.role === 'user' ? (
                    <div className="max-w-lg bg-primary/10 border border-primary/20 rounded-2xl rounded-br-md px-5 py-3">
                      <p className="text-sm text-white">{msg.content}</p>
                      <p className="text-[10px] text-zinc-500 mt-1">{msg.timestamp}</p>
                    </div>
                  ) : (
                    <div className="max-w-2xl w-full">
                      <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl rounded-bl-md overflow-hidden">
                        {/* Header */}
                        <div className="flex items-center justify-between px-5 py-3 border-b border-white/[0.04]">
                          <div className="flex items-center gap-3">
                            <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-blue-500 flex items-center justify-center">
                              <Bot size={14} className="text-white" />
                            </div>
                            <span className="text-sm font-bold text-white">{msg.title || 'NexusAI'}</span>
                          </div>
                          {msg.verdict && (
                            <span className={`text-[10px] font-black uppercase tracking-wider px-2.5 py-1 rounded-full border ${verdictColor(msg.verdict)}`}>
                              {msg.verdict}
                            </span>
                          )}
                        </div>
                        
                        {/* Price Bar */}
                        {msg.price > 0 && (
                          <div className="px-5 py-2 bg-white/[0.02] flex items-center gap-4 border-b border-white/[0.04]">
                            <span className="text-xs text-zinc-500">Price</span>
                            <span className="text-sm font-bold text-white font-mono">Γé╣{msg.price?.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                            <span className={`text-xs font-bold ${msg.change_pct >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                              {msg.change_pct >= 0 ? 'Γû▓' : 'Γû╝'} {Math.abs(msg.change_pct)?.toFixed(2)}%
                            </span>
                            {msg.confidence && (
                              <div className="ml-auto flex items-center gap-1.5">
                                <Sparkles size={10} className="text-amber-400" />
                                <span className="text-[10px] text-amber-400 font-bold">{msg.confidence}% confidence</span>
                              </div>
                            )}
                          </div>
                        )}

                        {/* Body */}
                        <div className="px-5 py-4">
                          <div 
                            className="text-sm text-zinc-300 leading-relaxed prose-sm"
                            dangerouslySetInnerHTML={{ __html: formatBody(msg.body || '') }}
                          />
                        </div>

                        {/* Actions */}
                        {msg.symbol && msg.symbol !== 'NIFTY' && (
                          <div className="px-5 py-3 border-t border-white/[0.04] flex gap-2">
                            <button
                              onClick={() => navigate(`/stock/${msg.symbol}`)}
                              className="flex items-center gap-1.5 px-3 py-1.5 bg-primary/10 text-primary text-xs font-bold rounded-lg hover:bg-primary/20 transition-colors"
                            >
                              View Chart <ArrowRight size={12} />
                            </button>
                          </div>
                        )}

                        <div className="px-5 py-2 border-t border-white/[0.04]">
                          <p className="text-[9px] text-zinc-600">{msg.timestamp} ΓÇó AI-generated analysis for educational purposes only</p>
                          {msg.blockHash && (
                            <div className="mt-2 flex items-center gap-1.5 bg-primary/10 border border-primary/20 px-2 py-1 rounded w-fit">
                              <Shield size={10} className="text-primary" />
                              <span className="text-[9px] text-primary font-bold">Blockchain Verified: {msg.blockHash.substring(0, 10)}...</span>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  )}
                </motion.div>
              ))}
            </AnimatePresence>

            {loading && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="flex items-center gap-3 text-zinc-500"
              >
                <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-purple-500 to-blue-500 flex items-center justify-center">
                  <Bot size={14} className="text-white animate-pulse" />
                </div>
                <div className="flex gap-1">
                  <div className="w-2 h-2 bg-zinc-600 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <div className="w-2 h-2 bg-zinc-600 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <div className="w-2 h-2 bg-zinc-600 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
                <span className="text-xs text-zinc-600">Analyzing market data...</span>
              </motion.div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input */}
          <div className="border-t border-white/[0.06] p-4">
            <form onSubmit={handleSubmit} className="flex gap-3">
              <div className="flex-1 relative">
                <input
                  ref={inputRef}
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="Ask about any stock... e.g. 'Should I buy RELIANCE?'"
                  className="w-full bg-white/[0.03] border border-white/[0.08] focus:border-primary/40 rounded-xl py-3.5 px-5 text-sm text-white focus:outline-none focus:ring-2 focus:ring-primary/10 transition-all placeholder:text-zinc-600"
                  disabled={loading}
                />
              </div>
              <button
                type="submit"
                disabled={loading || !input.trim()}
                className="px-6 py-3.5 bg-gradient-to-r from-purple-500 to-blue-500 text-white rounded-xl font-bold text-sm flex items-center gap-2 hover:opacity-90 transition-opacity disabled:opacity-30 shadow-lg shadow-purple-500/20"
              >
                <Send size={16} />
                Send
              </button>
            </form>
          </div>
        </div>

        {/* Right Sidebar */}
        <div className="space-y-4">
          {/* Quick Actions */}
          <div className="glass-panel p-5">
            <h3 className="text-xs font-black text-zinc-500 uppercase tracking-widest mb-4">Quick Commands</h3>
            <div className="space-y-2">
              {SUGGESTIONS.map((s, i) => (
                <button
                  key={i}
                  onClick={() => sendMessage(s.text)}
                  className="w-full flex items-center gap-3 px-3 py-2.5 text-left bg-white/[0.02] border border-white/[0.04] rounded-lg text-xs text-zinc-400 hover:text-white hover:bg-white/[0.05] transition-all group"
                >
                  <span className="text-primary">{s.icon}</span>
                  <span className="truncate">{s.text}</span>
                  <ArrowRight size={12} className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity text-zinc-600" />
                </button>
              ))}
            </div>
          </div>

          {/* Disclaimer */}
          <div className="glass-panel p-5">
            <div className="flex items-start gap-3">
              <Shield size={16} className="text-amber-400 mt-0.5 shrink-0" />
              <div>
                <p className="text-[11px] text-zinc-500 leading-relaxed">
                  AI Copilot provides analysis for <strong className="text-zinc-400">educational purposes only</strong>. 
                  Always do your own research before making investment decisions. Past performance Γëá future returns.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ShieldAlert, Activity, Server, Zap, RefreshCw, XCircle, AlertTriangle, CheckCircle, Clock, LineChart as LineChartIcon } from 'lucide-react';
import axios from 'axios';
import { API_BASE_URL } from '../config';
import { useUser } from '../context/UserContext';
import useSocket from '../hooks/useSocket';
import { Navigate } from 'react-router-dom';
import { useToast } from '../components/Toast';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

export default function AdminDashboard() {
  const { user } = useUser();
  const socket = useSocket();
  const { addToast } = useToast();
  const [liveStats, setLiveStats] = useState([]);
  const [telemetryBuffer, setTelemetryBuffer] = useState(null);
  const [analyticsLoad, setAnalyticsLoad] = useState(null);
  const [simulatorLoad, setSimulatorLoad] = useState(null);
  const [queueStats, setQueueStats] = useState(null);
  
  // Scale validation states
  const [scaleTarget, setScaleTarget] = useState(1000);
  const [scaleDuration, setScaleDuration] = useState(30);
  const [scaleRampUp, setScaleRampUp] = useState(10);
  const [loadTestStats, setLoadTestStats] = useState(null);
  const [isScaleActionLoading, setIsScaleActionLoading] = useState(false);

  const [adminData, setAdminData] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isClearingCache, setIsClearingCache] = useState(false);
  const [isOperatingQueue, setIsOperatingQueue] = useState(null);

  // Standard fetch function
  const fetchAdminData = async () => {
    if (!user || (!user.isAdmin && user.username !== 'admin')) return;
    try {
      const [brokerRes, queueRes, scaleRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/api/admin/broker-stats`),
        axios.get(`${API_BASE_URL}/api/admin/queues`),
        axios.get(`${API_BASE_URL}/api/admin/scale/status`)
      ]);
      setAdminData(brokerRes.data);
      if (queueRes.data?.queues) {
        setQueueStats(queueRes.data.queues);
      }
      if (scaleRes.data) {
        setLoadTestStats(scaleRes.data);
      }
    } catch (err) {
      console.error('Failed to fetch admin stats', err);
    }
  };

  const fetchQueueData = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/admin/queues`);
      if (res.data?.queues) {
        setQueueStats(res.data.queues);
      }
    } catch (err) {
      console.error('Failed to fetch queue stats', err);
    }
  };

  // Poll for data
  useEffect(() => {
    if (!user || (!user.isAdmin && user.username !== 'admin')) return;
    
    setIsLoading(true);
    fetchAdminData().finally(() => setIsLoading(false));

    const interval = setInterval(() => {
      fetchAdminData();
    }, 10000); // Poll every 10s as a fallback

    return () => clearInterval(interval);
  }, [user]);

  // WebSocket for Real-Time Telemetry
  useEffect(() => {
    if (!socket || !user || (!user.isAdmin && user.username !== 'admin')) return;
    
    socket.emit('join_admin');
    
    const handleTelemetry = (data) => {
       setLiveStats(data.stats);
       if (data.analyticsLoad) setAnalyticsLoad(data.analyticsLoad);
       if (data.simulatorLoad) setSimulatorLoad(data.simulatorLoad);
       if (data.queueStats) setQueueStats(data.queueStats);
       if (data.activeLoadTest) setLoadTestStats(data.activeLoadTest);
    };
    
    socket.on('admin_telemetry_update', handleTelemetry);
    
    return () => {
       socket.off('admin_telemetry_update', handleTelemetry);
    };
  }, [socket, user]);

  useEffect(() => {
    if (adminData?.data && liveStats.length === 0) {
       setLiveStats(adminData.data);
    }
    if (adminData?.buffer) {
       setTelemetryBuffer(adminData.buffer);
    }
  }, [adminData]);

  // Controls Handlers
  const handleQueueAction = async (action, queueName) => {
    if (action === 'clean') {
      const confirmClean = window.confirm(`Are you sure you want to clean completed/failed jobs from ${queueName}? Active and delayed jobs will not be affected.`);
      if (!confirmClean) return;
    }

    setIsOperatingQueue({ action, queueName });
    try {
      const res = await axios.post(`${API_BASE_URL}/api/admin/queues/${action}`, { queueName });
      addToast('success', res.data.message || `Queue action ${action} completed successfully.`);
      fetchQueueData();
    } catch (err) {
      addToast('error', err.response?.data?.error || `Failed to perform ${action} on ${queueName}`);
    } finally {
      setIsOperatingQueue(null);
    }
  };

  const handleClearCache = async () => {
    setIsClearingCache(true);
    try {
       const res = await axios.post(`${API_BASE_URL}/api/admin/broker/clear-cache`);
       addToast('success', res.data.message || 'Cache Cleared');
       fetchAdminData();
    } catch (err) {
       addToast('error', 'Failed to clear cache');
    } finally {
       setIsClearingCache(false);
    }
  };

  const handleDisconnect = async (broker_name) => {
    try {
       const res = await axios.post(`${API_BASE_URL}/api/admin/broker/disconnect`, { broker_name });
       addToast('success', res.data.message || 'Broker Disconnected');
       fetchAdminData();
    } catch (err) {
       addToast('error', 'Failed to disconnect broker');
    }
  };

  // Scale stress test action handlers
  const handleStartScaleTest = async () => {
    const confirmStart = window.confirm(`Proceed with scale stress-test simulating ${scaleTarget} clients for ${scaleDuration} seconds? This creates high network and processor load.`);
    if (!confirmStart) return;

    setIsScaleActionLoading(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/admin/scale/start`, {
        duration: scaleDuration * 1000,
        connections: scaleTarget,
        rampUp: scaleRampUp * 1000
      });
      addToast('success', res.data.message || 'Scale simulation initiated.');
    } catch (err) {
      addToast('error', err.response?.data?.error || 'Failed to start scale test');
    } finally {
      setIsScaleActionLoading(false);
    }
  };

  const handleStopScaleTest = async () => {
    setIsScaleActionLoading(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/admin/scale/stop`);
      addToast('success', res.data.message || 'Scale simulation stopped.');
    } catch (err) {
      addToast('error', err.response?.data?.error || 'Failed to stop scale test');
    } finally {
      setIsScaleActionLoading(false);
    }
  };

  if (!user || (!user.isAdmin && user.username !== 'admin')) {
    return <Navigate to="/explore" />;
  }

  if (isLoading && liveStats.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <RefreshCw className="w-8 h-8 text-primary animate-spin" />
      </div>
    );
  }

  const getHealthColor = (score) => {
    if (score >= 90) return 'text-emerald-400 border-emerald-500/20 bg-emerald-500/10';
    if (score >= 70) return 'text-amber-400 border-amber-500/20 bg-amber-500/10';
    return 'text-rose-400 border-rose-500/20 bg-rose-500/10';
  };

  return (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="space-y-8 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-extrabold text-white flex items-center gap-3">
            <ShieldAlert className="w-8 h-8 text-rose-500" />
            Operations Command Center
          </h1>
          <p className="text-zinc-500 mt-2 font-medium">Real-time broker telemetry, gateway health, and systemic diagnostics.</p>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleClearCache}
             disabled={isClearingCache}
             className="px-4 py-2 bg-white/[0.05] border border-white/[0.1] rounded-xl text-sm font-bold text-white hover:bg-white/[0.1] transition-all flex items-center gap-2">
             <RefreshCw className={`w-4 h-4 ${isClearingCache ? 'animate-spin' : ''}`} /> Clear Idempotency Cache
           </button>
        </div>
      </div>

      {/* Broker Health Matrix */}
      <h2 className="text-xl font-bold text-white flex items-center gap-2 mb-4"><Server className="w-5 h-5 text-primary" /> Active Broker Gateways</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
        {liveStats.map((broker) => (
          <div key={broker.activeAdapter} className="glass-panel p-6 border-t-4 border-t-white/[0.1] relative overflow-hidden group">
            
            {/* Header */}
            <div className="flex justify-between items-start mb-6">
              <div>
                 <h3 className="text-lg font-black text-white">{broker.activeAdapter}</h3>
                 <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded-md ${broker.isSandbox ? 'bg-orange-500/20 text-orange-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
                    {broker.isSandbox ? 'SANDBOX' : 'LIVE PRODUCTION'}
                 </span>
              </div>
              <div className={`p-2 rounded-xl border ${getHealthColor(broker.healthScore)} flex flex-col items-center justify-center min-w-[50px]`}>
                 <span className="text-[10px] uppercase font-black opacity-80">Score</span>
                 <span className="text-lg font-black font-mono-data">{broker.healthScore}</span>
              </div>
            </div>

            {/* Metrics */}
            <div className="space-y-4 mb-6">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium text-zinc-500 flex items-center gap-2"><Clock className="w-4 h-4" /> Latency</span>
                <span className={`text-sm font-bold font-mono-data ${broker.metrics.latencyMs > 500 ? 'text-rose-400' : 'text-emerald-400'}`}>
                   {broker.metrics.latencyMs}ms
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium text-zinc-500 flex items-center gap-2"><Activity className="w-4 h-4" /> Queue Depth</span>
                <span className={`text-sm font-bold font-mono-data ${broker.metrics.queueSize > 5 ? 'text-amber-400' : 'text-zinc-300'}`}>
                   {broker.metrics.queueSize} req
                </span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium text-zinc-500 flex items-center gap-2"><Zap className="w-4 h-4" /> 429 Cooldown</span>
                <span className={`text-sm font-bold ${broker.metrics.isCoolingDown ? 'text-rose-400' : 'text-emerald-400'}`}>
                   {broker.metrics.isCoolingDown ? 'ACTIVE' : 'CLEAR'}
                </span>
              </div>
              
              {/* Angel One specific metrics */}
              {broker.activeAdapter === 'Angel One' && (
                <div className="flex items-center justify-between mt-2 pt-2 border-t border-white/[0.05]">
                  <span className="text-sm font-medium text-zinc-500 flex items-center gap-2"><Server className="w-4 h-4" /> TOTP Generator</span>
                  <span className={`text-sm font-bold ${broker.metrics.totpValid ? 'text-emerald-400' : 'text-rose-400'}`}>
                     {broker.metrics.totpValid ? 'SYNCED' : 'OFFLINE'}
                  </span>
                </div>
              )}
            </div>

            {/* Controls */}
            <div className="pt-4 border-t border-white/[0.06] flex gap-2">
               <button 
                 onClick={() => handleDisconnect(broker.activeAdapter)}
                 className="flex-1 py-2 bg-rose-500/10 hover:bg-rose-500/20 border border-rose-500/20 rounded-lg text-rose-400 text-xs font-bold transition-all flex items-center justify-center gap-2">
                 <XCircle className="w-3 h-3" /> Force Disconnect
               </button>
            </div>

          </div>
        ))}
      </div>

      {/* System Diagnostics & Alerts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
         {/* Live Alerts Stream */}
         <div className="lg:col-span-2 glass-panel p-6 border-l-4 border-l-primary">
            <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2"><AlertTriangle className="w-5 h-5 text-amber-400" /> Live System Alerts</h3>
            <div className="space-y-3">
               {liveStats.some(b => b.metrics.isCoolingDown) && (
                 <div className="p-3 bg-rose-500/10 border border-rose-500/20 rounded-xl flex gap-3 items-center">
                    <XCircle className="w-5 h-5 text-rose-400 flex-shrink-0" />
                    <p className="text-sm text-zinc-300"><span className="text-white font-bold">Rate Limit Spikes Detected:</span> One or more brokers are actively throttling requests. Gateway is delaying outgoing syncs.</p>
                 </div>
               )}
               {liveStats.some(b => b.isSandbox && b.activeAdapter !== 'Groww' && b.activeAdapter !== 'Angel One') && (
                 <div className="p-3 bg-amber-500/10 border border-amber-500/20 rounded-xl flex gap-3 items-center">
                    <AlertTriangle className="w-5 h-5 text-amber-400 flex-shrink-0" />
                    <p className="text-sm text-zinc-300"><span className="text-white font-bold">Sandbox Degradation:</span> Live credentials for primary brokers are missing or failed. Users are routed to mocked feeds.</p>
                 </div>
               )}
               <div className="p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl flex gap-3 items-center">
                  <CheckCircle className="w-5 h-5 text-emerald-400 flex-shrink-0" />
                  <p className="text-sm text-zinc-300"><span className="text-white font-bold">Gateway Stabilized:</span> WebSocket supervisor reports 0 zombie feeds. Idempotency cache holding firm.</p>
               </div>
            </div>
         </div>

         {/* Analytics Engine Load Stub */}
         <div className="glass-panel p-6 border border-white/[0.04]">
             <h3 className="text-lg font-bold text-white mb-6">Analytics Engine</h3>
             {analyticsLoad ? (
                <div className="space-y-5">
                    <div>
                       <p className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-1">Compute Latency</p>
                       <p className={`text-2xl font-black font-mono-data ${analyticsLoad.computeLatencyMs > 10 ? 'text-amber-400' : 'text-emerald-400'}`}>
                          {analyticsLoad.computeLatencyMs.toFixed(2)}ms
                       </p>
                    </div>
                    <div>
                       <p className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-1">Tick Throughput</p>
                       <p className="text-2xl font-black text-white font-mono-data">{analyticsLoad.updatesPerSecond} TPS</p>
                    </div>
                    <div>
                       <p className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-1">Status</p>
                       <p className="text-lg font-black text-emerald-400 font-mono-data">STREAMING DELTAS</p>
                    </div>
                </div>
             ) : (
                <div className="flex items-center justify-center h-full text-zinc-500 text-sm">Awaiting Engine Telemetry...</div>
             )}
         </div>

         {/* Paper Simulator Stub */}
         <div className="glass-panel p-6 border border-white/[0.04]">
             <h3 className="text-lg font-bold text-white mb-6">Simulator Engine</h3>
             {simulatorLoad ? (
                <div className="space-y-5">
                    <div>
                       <p className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-1">Execution Latency</p>
                       <p className={`text-2xl font-black font-mono-data ${simulatorLoad.executionLatency > 5 ? 'text-amber-400' : 'text-emerald-400'}`}>
                          {simulatorLoad.executionLatency.toFixed(2)}ms
                       </p>
                    </div>
                    <div>
                       <p className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-1">Simulated TPS</p>
                       <p className="text-2xl font-black text-white font-mono-data">{simulatorLoad.simulatedTPS} TPS</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Traders</p>
                          <p className="text-lg font-black text-blue-400 font-mono-data">{simulatorLoad.activePaperTraders}</p>
                       </div>
                       <div>
                          <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-widest mb-1">Violations</p>
                          <p className="text-lg font-black text-rose-400 font-mono-data">{simulatorLoad.riskViolations}</p>
                       </div>
                    </div>
                </div>
             ) : (
                <div className="flex items-center justify-center h-full text-zinc-500 text-sm">Awaiting Engine Telemetry...</div>
             )}
         </div>
      </div>

      {/* BullMQ Async Workers & Queues */}
      <h2 className="text-xl font-bold text-white flex items-center gap-2 mb-4 mt-8">
        <Activity className="w-5 h-5 text-primary" /> BullMQ Background Workers
      </h2>
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6 mb-8">
        {queueStats ? (
          Object.entries(queueStats).map(([name, stats]) => {
            const isOffline = stats === 'offline';
            const isActive = isOperatingQueue?.queueName === name;
            return (
              <div key={name} className="glass-panel p-6 border-t-4 border-t-white/[0.1] relative overflow-hidden group">
                {/* Header */}
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <h3 className="text-lg font-black text-white">{name}</h3>
                    <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-1 rounded-md ${isOffline ? 'bg-rose-500/20 text-rose-400' : 'bg-emerald-500/20 text-emerald-400'}`}>
                      {isOffline ? 'OFFLINE' : 'OPERATIONAL'}
                    </span>
                  </div>
                  {!isOffline && (
                    <div className="p-2 rounded-xl border border-white/10 bg-white/5 flex flex-col items-center justify-center min-w-[50px]">
                      <span className="text-[10px] uppercase font-black text-zinc-400">Fail %</span>
                      <span className="text-sm font-black font-mono-data text-white">{stats.failedPercentage}%</span>
                    </div>
                  )}
                </div>

                {/* Metrics */}
                {isOffline ? (
                  <div className="text-zinc-500 text-sm py-4">Queue manager reports Redis is offline or queue is disconnected.</div>
                ) : (
                  <div className="space-y-3 mb-6">
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-zinc-400">Active</span>
                      <span className="font-bold text-emerald-400 font-mono-data">{stats.active}</span>
                    </div>
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-zinc-400">Waiting</span>
                      <span className="font-bold text-amber-400 font-mono-data">{stats.waiting}</span>
                    </div>
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-zinc-400">Delayed</span>
                      <span className="font-bold text-blue-400 font-mono-data">{stats.delayed}</span>
                    </div>
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-zinc-400">Completed</span>
                      <span className="font-bold text-zinc-300 font-mono-data">{stats.completed}</span>
                    </div>
                    <div className="flex items-center justify-between text-sm">
                      <span className="text-zinc-400">Failed</span>
                      <span className={`font-bold font-mono-data ${stats.failed > 0 ? 'text-rose-400' : 'text-zinc-300'}`}>{stats.failed}</span>
                    </div>
                  </div>
                )}

                {/* Actions */}
                {!isOffline && (
                  <div className="pt-4 border-t border-white/[0.06] flex flex-wrap gap-2">
                    <button
                      onClick={() => handleQueueAction('retry', name)}
                      disabled={isOperatingQueue !== null || stats.failed === 0}
                      className={`flex-1 py-1.5 rounded-lg border text-xs font-bold transition-all text-center flex items-center justify-center gap-1 ${
                        stats.failed > 0
                          ? 'bg-emerald-500/10 hover:bg-emerald-500/20 border-emerald-500/20 text-emerald-400'
                          : 'bg-zinc-800/20 border-zinc-700/30 text-zinc-500 cursor-not-allowed'
                      }`}
                    >
                      Retry Failed
                    </button>
                    <button
                      onClick={() => handleQueueAction('clean', name)}
                      disabled={isOperatingQueue !== null || (stats.completed === 0 && stats.failed === 0)}
                      className={`flex-1 py-1.5 rounded-lg border text-xs font-bold transition-all text-center flex items-center justify-center gap-1 ${
                        stats.completed > 0 || stats.failed > 0
                          ? 'bg-rose-500/10 hover:bg-rose-500/20 border-rose-500/20 text-rose-400'
                          : 'bg-zinc-800/20 border-zinc-700/30 text-zinc-500 cursor-not-allowed'
                      }`}
                    >
                      Clean
                    </button>
                    <button
                      onClick={() => handleQueueAction('trigger-test', name)}
                      disabled={isOperatingQueue !== null}
                      className="w-full py-1.5 bg-white/[0.05] hover:bg-white/[0.1] border border-white/[0.1] rounded-lg text-white text-xs font-bold transition-all text-center flex items-center justify-center gap-1"
                    >
                      {isActive && isOperatingQueue?.action === 'trigger-test' ? (
                        <RefreshCw className="w-3 h-3 animate-spin" />
                      ) : (
                        'Trigger Test Job'
                      )}
                    </button>
                  </div>
                )}
              </div>
            );
          })
        ) : (
          <div className="col-span-4 text-center py-8 text-zinc-500 text-sm">
            Fetching worker queue telemetry...
          </div>
        )}
      </div>

      {/* WebSocket Scale Testing & Load Simulator */}
      <h2 className="text-xl font-bold text-white flex items-center gap-2 mb-4 mt-8">
        <Activity className="w-5 h-5 text-primary" /> WebSocket Scale Testing & Load Simulator
      </h2>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
        {/* Controls Card */}
        <div className="glass-panel p-6 border-t-4 border-t-white/[0.1] space-y-4">
          <h3 className="text-lg font-bold text-white mb-2">Simulation Controls</h3>
          
          <div className="space-y-3">
            <div>
              <label className="text-xs text-zinc-400 font-bold uppercase tracking-widest block mb-1">Target Connections</label>
              <input
                type="number"
                value={scaleTarget}
                onChange={(e) => setScaleTarget(parseInt(e.target.value) || 1000)}
                disabled={loadTestStats?.status === 'running'}
                className="w-full bg-white/[0.03] border border-white/[0.1] rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-primary/50"
              />
            </div>
            
            <div>
              <label className="text-xs text-zinc-400 font-bold uppercase tracking-widest block mb-1">Test Duration (s)</label>
              <input
                type="number"
                value={scaleDuration}
                onChange={(e) => setScaleDuration(parseInt(e.target.value) || 30)}
                disabled={loadTestStats?.status === 'running'}
                className="w-full bg-white/[0.03] border border-white/[0.1] rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-primary/50"
              />
            </div>

            <div>
              <label className="text-xs text-zinc-400 font-bold uppercase tracking-widest block mb-1">Ramp Up Time (s)</label>
              <input
                type="number"
                value={scaleRampUp}
                onChange={(e) => setScaleRampUp(parseInt(e.target.value) || 10)}
                disabled={loadTestStats?.status === 'running'}
                className="w-full bg-white/[0.03] border border-white/[0.1] rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-primary/50"
              />
            </div>
          </div>

          <div className="pt-4 border-t border-white/[0.06] flex gap-2">
            {loadTestStats?.status === 'running' ? (
              <button
                onClick={handleStopScaleTest}
                disabled={isScaleActionLoading}
                className="w-full py-3 bg-rose-500/10 hover:bg-rose-500/20 border border-rose-500/20 rounded-xl text-rose-400 text-sm font-bold transition-all flex items-center justify-center gap-2"
              >
                <XCircle className="w-4 h-4" /> Stop Simulator
              </button>
            ) : (
              <button
                onClick={handleStartScaleTest}
                disabled={isScaleActionLoading}
                className="w-full py-3 bg-emerald-500/10 hover:bg-emerald-500/20 border border-emerald-500/20 rounded-xl text-emerald-400 text-sm font-bold transition-all flex items-center justify-center gap-2"
              >
                <RefreshCw className={`w-4 h-4 ${isScaleActionLoading ? 'animate-spin' : ''}`} /> Run Simulation
              </button>
            )}
          </div>
        </div>

        {/* Telemetry Overview Card */}
        <div className="glass-panel p-6 border-t-4 border-t-white/[0.1] lg:col-span-2 relative overflow-hidden">
          <h3 className="text-lg font-bold text-white mb-6">Real-Time Simulator Telemetry</h3>
          
          {loadTestStats ? (
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              <div>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-1">Simulator Status</p>
                <p className={`text-xl font-black uppercase ${
                  loadTestStats.status === 'running' ? 'text-emerald-400 animate-pulse' :
                  loadTestStats.status === 'completed' ? 'text-blue-400' : 'text-zinc-400'
                }`}>{loadTestStats.status}</p>
              </div>

              <div>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-1">Simulated Clients</p>
                <p className="text-xl font-black text-white font-mono-data">
                  {loadTestStats.activeConnections} <span className="text-xs text-zinc-500">/ {loadTestStats.targetConnections}</span>
                </p>
              </div>

              <div>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-1">Fan-Out Latency</p>
                <p className={`text-xl font-black font-mono-data ${loadTestStats.avgLatencyMs > 200 ? 'text-rose-400' : 'text-emerald-400'}`}>
                  {loadTestStats.avgLatencyMs}ms
                </p>
              </div>

              <div>
                <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mb-1">Errors / Drops</p>
                <p className={`text-xl font-black font-mono-data ${loadTestStats.errors > 0 ? 'text-rose-400' : 'text-white'}`}>
                  {loadTestStats.errors} <span className="text-xs text-zinc-500">({loadTestStats.disconnects} dc)</span>
                </p>
              </div>

              {/* Progress Bar */}
              {loadTestStats.status === 'running' && (
                <div className="col-span-4 pt-4">
                  <div className="flex justify-between text-xs text-zinc-500 mb-1">
                    <span>Elapsed: {loadTestStats.elapsedSeconds}s</span>
                    <span>Target: {scaleDuration}s</span>
                  </div>
                  <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                    <div
                      className="h-full bg-emerald-500 transition-all duration-300"
                      style={{ width: `${(loadTestStats.elapsedSeconds / scaleDuration) * 100}%` }}
                    />
                  </div>
                </div>
              )}
            </div>
          ) : (
            <div className="flex items-center justify-center h-full text-zinc-500 text-sm">
              No active or past scale test telemetry available. Click Run Simulation to start.
            </div>
          )}
        </div>
      </div>

      {/* Historical Buffer Charts */}
      <div className="glass-panel p-6 border-t-4 border-t-blue-500 mt-6">
        <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
          <LineChartIcon className="w-5 h-5 text-blue-400" /> API Latency Timeline (Last 60 Minutes)
        </h3>
        <div className="h-[300px] w-full">
          {telemetryBuffer && (
            <ResponsiveContainer width="100%" height="100%">
              <LineChart margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                <XAxis
                  dataKey="timestamp"
                  type="category"
                  allowDuplicatedCategory={false}
                  stroke="#52525b"
                  tickFormatter={(t) => new Date(t).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                />
                <YAxis stroke="#52525b" />
                <Tooltip contentStyle={{ backgroundColor: '#18181b', borderColor: '#27272a' }} labelFormatter={(l) => new Date(l).toLocaleTimeString()} />
                {Object.keys(telemetryBuffer)
                  .filter((k) => telemetryBuffer[k][1].length > 0)
                  .map((broker, i) => (
                    <Line
                      dataKey="latency"
                      data={telemetryBuffer[broker][1]}
                      name={broker}
                      key={broker}
                      stroke={i === 0 ? '#10b981' : i === 1 ? '#3b82f6' : '#f59e0b'}
                      dot={false}
                      strokeWidth={2}
                    />
                  ))}
              </LineChart>
            </ResponsiveContainer>
          )}
          {!telemetryBuffer && (
            <div className="w-full h-full flex items-center justify-center text-zinc-500 font-bold">Waiting for telemetry buffer...</div>
          )}
        </div>
      </div>
    </motion.div>
  );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Link, TrendingUp, Shield, HelpCircle, ChevronRight, CheckCircle2, AlertCircle, Building2, Globe, Activity, LayoutGrid, ArrowRight, RefreshCw, ShieldAlert, XCircle } from 'lucide-react';
import axiosInstance from '../utils/axiosSetup';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import { API_BASE_URL } from '../config';

const BROKERS = [
  { id: 'kite', name: 'Zerodha Kite', logo: 'ZK', color: 'bg-orange-500', iconColor: 'text-orange-500' },
  { id: 'upstox', name: 'Upstox Pro', logo: 'UP', color: 'bg-blue-600', iconColor: 'text-blue-600' },
  { id: 'groww', name: 'Groww', logo: 'G', color: 'bg-emerald-500', iconColor: 'text-emerald-500' },
  { id: 'angel', name: 'Angel One', logo: 'A1', color: 'bg-blue-800', iconColor: 'text-blue-800' },
];

export default function BrokerLink() {
  const { user, refreshUser, brokerConnected } = useUser();
  const toast = useToast();
  const navigate = useNavigate();
  const [selectedBroker, setSelectedBroker] = useState(null);
  const [connectionState, setConnectionState] = useState('idle'); // idle, connecting, authenticating, connected, failed
  const [connectionError, setConnectionError] = useState(null);
  const [isSandboxMode, setIsSandboxMode] = useState(false);

  const handleLink = async (broker) => {
    if (connectionState === 'connecting' || connectionState === 'authenticating') return;
    
    if (!user) {
        toast.error("Please login to connect a broker");
        return;
    }
    setSelectedBroker(broker);
    setConnectionState('connecting');
    setConnectionError(null);
    
    try {
      // Simulate multiple loading phases
      await new Promise(resolve => setTimeout(resolve, 800));
      setConnectionState('authenticating');

      // Direct integration with backend via centralized axios instance
      const res = await axiosInstance.post(`/api/broker/connect?user_id=${user.id}`, {
        broker_name: broker.name,
        api_key: `AK-${Math.random().toString(36).substring(7).toUpperCase()}`,
        api_secret: `AS-${Math.random().toString(36).substring(7).toUpperCase()}`,
        client_id: `CID-${Math.random().toString(36).substring(7).toUpperCase()}`
      });
      
      const { access_token, refresh_token, expires_at, is_sandbox } = res.data;
      if (access_token) {
        localStorage.setItem('broker_access_token', access_token);
        localStorage.setItem('broker_refresh_token', refresh_token);
        localStorage.setItem('broker_expires_at', expires_at);
        setIsSandboxMode(is_sandbox || false);
        // Force socket to reconnect and pick up new token
        window.dispatchEvent(new Event('broker_token_updated'));
      }
      
      // Simulate OAuth redirect delay
      setTimeout(async () => {
        await refreshUser();
        setConnectionState('connected');
      }, 1500);
    } catch (err) {
      setConnectionError(err.customMessage || err.message || "Broker gateway connection failed. Please check your network.");
      setConnectionState('failed');
    }
  };

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="max-w-6xl mx-auto space-y-10 pb-20">
      
      {/* Hero Link Section */}
      <div className="relative rounded-[40px] overflow-hidden border border-white/[0.08] bg-gradient-to-br from-[#060b18] via-surface to-surface p-10 md:p-16 shadow-[0_50px_100px_rgba(0,0,0,0.5)]">
        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/10 rounded-full blur-[150px] pointer-events-none" />
        <div className="absolute bottom-0 left-0 w-[300px] h-[300px] bg-secondary/10 rounded-full blur-[100px] pointer-events-none" />
        
        <div className="relative z-10 flex flex-col md:flex-row items-center gap-16">
          <div className="max-w-xl text-center md:text-left">
            <div className="flex items-center justify-center md:justify-start gap-4 mb-6">
               <span className="px-3 py-1 bg-primary/15 text-primary border border-primary/20 text-[10px] font-black uppercase tracking-widest rounded-full">Secure API Gateway</span>
               {brokerConnected ? (
                 <span className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest flex items-center gap-1.5 bg-emerald-500/10 px-3 py-1 rounded-full border border-emerald-500/20"><CheckCircle2 className="w-3.5 h-3.5" /> Broker Active</span>
               ) : (
                 <span className="text-[10px] text-zinc-600 font-bold uppercase tracking-widest flex items-center gap-1.5"><Shield className="w-3.5 h-3.5" /> ISO 27001 Certified</span>
               )}
            </div>
            <h1 className="text-4xl md:text-6xl font-black text-white leading-tight mb-8">
              Bridge your <span className="text-gradient">Broker API</span> to Nexus AI
            </h1>
            <div className="space-y-8">
              <p className="text-zinc-500 text-lg leading-relaxed font-medium">
                Sync your external demat account with Nexus AI for seamless live trade execution and portfolio tracking.
              </p>
              <div className="grid grid-cols-2 gap-y-4 gap-x-8 text-sm font-bold text-zinc-400">
                 <div className="flex items-center gap-3"><CheckCircle2 className="w-5 h-5 text-emerald-400" /> T-Zero Latency</div>
                 <div className="flex items-center gap-3"><CheckCircle2 className="w-5 h-5 text-emerald-400" /> Auto CDSL E-DIS</div>
                 <div className="flex items-center gap-3"><CheckCircle2 className="w-5 h-5 text-emerald-400" /> Tax Shield Reports</div>
                 <div className="flex items-center gap-3"><CheckCircle2 className="w-5 h-5 text-emerald-400" /> Multi-Leg Orders</div>
              </div>
            </div>
          </div>

          <div className="flex-1 w-full max-w-md">
            <div className="glass-panel p-10 space-y-8 relative border-white/[0.08] shadow-2xl backdrop-blur-3xl rounded-[32px]">
                <div className="flex justify-between items-center mb-2">
                   <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Select Provider</h3>
                   <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                </div>
                
                <div className="grid grid-cols-2 gap-5">
                   {BROKERS.map((broker) => (
                      <motion.button
                        key={broker.id}
                        whileHover={{ y: -6, scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        onClick={() => handleLink(broker)}
                        className={`p-7 rounded-[28px] border transition-all flex flex-col items-center gap-4 group relative overflow-hidden ${
                            selectedBroker?.id === broker.id 
                            ? 'bg-primary/20 border-primary shadow-[0_20px_50px_rgba(0,212,170,0.15)]' 
                            : 'bg-white/[0.02] border-white/[0.06] hover:bg-white/[0.05] hover:border-primary/30'
                        }`}
                      >
                         <div className={`w-14 h-14 ${broker.color} rounded-2xl flex items-center justify-center font-black text-2xl text-white shadow-xl group-hover:rotate-6 transition-transform relative z-10`}>
                            {broker.logo}
                         </div>
                         <span className="text-[10px] font-black text-white uppercase tracking-widest relative z-10 group-hover:text-primary transition-colors">{broker.name}</span>
                         <div className="absolute inset-0 bg-gradient-to-tr from-primary/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                      </motion.button>
                   ))}
                </div>
                
                <div className="mt-8 pt-8 border-t border-white/[0.04] text-center">
                   <p className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest leading-relaxed">By bridging your account, you authorize Nexus AI to access your trading credentials for execution.</p>
                </div>
            </div>
          </div>
        </div>
      </div>

      {/* Linking Modal */}
      <AnimatePresence>
        {(connectionState !== 'idle') && (
          <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
             <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="absolute inset-0 bg-black/95 backdrop-blur-2xl" />
             <motion.div 
               initial={{ scale: 0.9, opacity: 0, y: 40 }} 
               animate={{ scale: 1, opacity: 1, y: 0 }}
               exit={{ scale: 0.9, opacity: 0, y: 40 }}
               className="relative w-full max-w-lg bg-[#0a0f1a] border border-white/[0.08] rounded-[48px] overflow-hidden p-12 text-center shadow-[0_50px_100px_rgba(0,0,0,0.8)]"
             >
                {(connectionState === 'connecting' || connectionState === 'authenticating') ? (
                    <div className="space-y-12 py-10">
                        <div className="relative mx-auto w-36 h-36 flex items-center justify-center">
                            <RefreshCw className="w-24 h-24 text-primary opacity-20 animate-spin" />
                            <div className="absolute w-20 h-20 bg-primary/10 rounded-3xl flex items-center justify-center border border-primary/30 backdrop-blur-md shadow-[0_0_40px_rgba(0,212,170,0.2)]">
                                <span className="font-black text-3xl text-primary">{selectedBroker?.logo}</span>
                            </div>
                        </div>
                        <div>
                            <h3 className="text-4xl font-black text-white mb-3">
                                {connectionState === 'connecting' ? 'Establishing Tunnel' : 'Syncing Engine'}
                            </h3>
                            <p className="text-zinc-500 font-bold uppercase tracking-[0.3em] text-[10px]">
                                {connectionState === 'connecting' ? `Connecting to ${selectedBroker?.name}` : `Authorizing Secure API Key`}
                            </p>
                        </div>
                    </div>
                ) : connectionState === 'failed' ? (
                    <div className="space-y-10">
                        <div className="w-28 h-28 bg-rose-500/10 rounded-[32px] flex items-center justify-center mx-auto border-2 border-rose-500/30 relative">
                            <XCircle className="w-14 h-14 text-rose-500" />
                        </div>
                        <div>
                            <h3 className="text-4xl font-black text-white">Connection Failed</h3>
                            <p className="text-rose-400 text-sm mt-4 px-6 font-bold">{connectionError}</p>
                        </div>
                        <div className="flex flex-col gap-3">
                           <button 
                              onClick={() => handleLink(selectedBroker)}
                              className="w-full py-5 bg-primary/10 text-primary border border-primary/20 font-black uppercase tracking-widest rounded-3xl hover:bg-primary/20 transition-all shadow-lg"
                           >
                               Retry Connection
                           </button>
                           <button 
                              onClick={() => setConnectionState('idle')}
                              className="w-full py-4 bg-white/[0.04] text-zinc-400 font-bold uppercase tracking-widest rounded-3xl hover:bg-white/[0.08] hover:text-white transition-all"
                           >
                               Cancel
                           </button>
                        </div>
                    </div>
                ) : (
                    <div className="space-y-10">
                        <div className="w-28 h-28 bg-emerald-500/10 rounded-[32px] flex items-center justify-center mx-auto border-2 border-emerald-500/30 shadow-[0_0_60px_rgba(16,185,129,0.25)] relative">
                            <CheckCircle2 className="w-14 h-14 text-emerald-400" />
                            <div className="absolute -top-2 -right-2 w-6 h-6 bg-emerald-500 rounded-full flex items-center justify-center border-4 border-[#0a0f1a]">
                               <div className="w-2 h-2 bg-white rounded-full animate-ping" />
                            </div>
                        </div>
                        <div>
                            <h3 className="text-4xl font-black text-white">Bridge Active</h3>
                            <p className="text-zinc-500 text-base mt-4 px-6 leading-relaxed">Your {selectedBroker?.name} account is now integrated for Live execution with Nexus AI orchestration.</p>
                        </div>
                        <div className="pt-4 grid grid-cols-2 gap-5">
                             <div className="p-5 bg-white/[0.02] border border-white/[0.04] rounded-3xl text-left">
                                <p className="text-[10px] font-black text-zinc-600 uppercase mb-2 tracking-widest">API Status</p>
                                <p className="text-sm font-bold text-emerald-400 flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500" /> CONNECTED</p>
                             </div>
                             <div className="p-5 bg-white/[0.02] border border-white/[0.04] rounded-3xl text-left">
                                <p className="text-[10px] font-black text-zinc-600 uppercase mb-2 tracking-widest">Environment</p>
                                <p className={`text-sm font-bold ${isSandboxMode ? 'text-orange-400' : 'text-amber-400'}`}>
                                   {isSandboxMode ? 'SANDBOX (DEMO)' : 'PRODUCTION'}
                                </p>
                             </div>
                        </div>
                        <button 
                           onClick={() => { setConnectionState('idle'); navigate('/portfolio'); }}
                           className="w-full mt-6 py-5 bg-primary text-black font-black uppercase tracking-widest rounded-3xl hover:bg-emerald-400 transition-all hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center gap-3 shadow-lg shadow-primary/20"
                        >
                            Open Trading Deck <ArrowRight className="w-6 h-6" />
                        </button>
                    </div>
                )}
             </motion.div>
          </div>
        )}
      </AnimatePresence>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="glass-panel p-8 space-y-6 group hover:border-primary/30 transition-all">
              <div className="w-12 h-12 bg-white/[0.04] border border-white/10 rounded-2xl flex items-center justify-center group-hover:bg-primary/10 transition-colors">
                  <Globe className="w-6 h-6 text-zinc-400 group-hover:text-primary transition-colors" />
              </div>
              <h4 className="text-xl font-extrabold text-white">Cross-Chain Trading</h4>
              <p className="text-zinc-500 text-sm leading-relaxed">Execute across multiple brokers and exchanges simultaneously with unified margin management.</p>
          </div>
          <div className="glass-panel p-8 space-y-6 group hover:border-primary/30 transition-all">
              <div className="w-12 h-12 bg-white/[0.04] border border-white/10 rounded-2xl flex items-center justify-center group-hover:bg-primary/10 transition-colors">
                  <Activity className="w-6 h-6 text-zinc-400 group-hover:text-primary transition-colors" />
              </div>
              <h4 className="text-xl font-extrabold text-white">Smart Routing</h4>
              <p className="text-zinc-500 text-sm leading-relaxed">Nexus AI automatically routes orders to the broker offering the lowest slippage and best liquidity.</p>
          </div>
          <div className="glass-panel p-8 space-y-6 group hover:border-primary/30 transition-all">
              <div className="w-12 h-12 bg-white/[0.04] border border-white/10 rounded-2xl flex items-center justify-center group-hover:bg-primary/10 transition-colors">
                  <LayoutGrid className="w-6 h-6 text-zinc-400 group-hover:text-primary transition-colors" />
              </div>
              <h4 className="text-xl font-extrabold text-white">Live Audit trail</h4>
              <p className="text-zinc-500 text-sm leading-relaxed">Real-time exchange confirmation and digital contract notes synced directly to your Nexus ledger.</p>
          </div>
      </div>

    </motion.div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ShieldCheck, Building2, Clock, FileText, RefreshCw, CheckCircle2, XCircle, Key, Lock, Copy, ExternalLink, AlertTriangle, ChevronRight, Hash, Smartphone, Globe, User } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useToast } from '../components/Toast';
import { useUser } from '../context/UserContext';
import axios from 'axios';
import { API_BASE_URL } from '../config';

export default function CDSLDashboard() {
  const toast = useToast();
  const { user, isLiveMode } = useUser();
  const [demat, setDemat] = useState(null);
  const [holdings, setHoldings] = useState([]);
  const [authHistory, setAuthHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [bulkTpin, setBulkTpin] = useState('');
  const [bulkMode, setBulkMode] = useState(false);
  const [selectedForBulk, setSelectedForBulk] = useState([]);
  const [bulkLoading, setBulkLoading] = useState(false);

  const fetchData = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const [dematRes, historyRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/api/cdsl/demat-info?user_id=${user.id}`),
        axios.get(`${API_BASE_URL}/api/cdsl/history?user_id=${user.id}`)
      ]);
      setDemat(dematRes.data.demat);
      setHoldings(dematRes.data.holdings || []);
      setAuthHistory(historyRes.data.history || []);
    } catch (err) {
      console.error('CDSL fetch error', err);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { 
    fetchData(); 
  }, [fetchData, isLiveMode]);

  const toggleBulkSelect = (symbol) => {
    setSelectedForBulk(prev => 
      prev.includes(symbol) ? prev.filter(s => s !== symbol) : [...prev, symbol]
    );
  };

  const handleBulkAuthorize = async () => {
    if (bulkTpin.length < 6 || !user) { toast.error('Enter valid T-PIN'); return; }
    if (selectedForBulk.length === 0) { toast.error('Select at least one holding'); return; }
    
    setBulkLoading(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/cdsl/bulk-authorize?user_id=${user.id}`, {
        symbols: selectedForBulk,
        tpin: bulkTpin
      });
      toast.success(res.data.message);
      setBulkMode(false);
      setBulkTpin('');
      setSelectedForBulk([]);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Bulk authorization failed');
    } finally {
      setBulkLoading(false);
    }
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
    toast.success('Copied');
  };

  const activeAuths = holdings.filter(h => h.authorized);
  const pendingAuths = holdings.filter(h => !h.authorized);

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8 pb-20">
      
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-extrabold text-white flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500/20 to-indigo-500/20 border border-white/[0.06] flex items-center justify-center">
              <ShieldCheck className="w-5 h-5 text-blue-400" />
            </div>
            CDSL E-DIS Dashboard
            <button onClick={fetchData} className="p-1.5 hover:bg-white/5 rounded-lg transition-colors">
              <RefreshCw className={`w-4 h-4 text-zinc-600 ${loading ? 'animate-spin' : ''}`} />
            </button>
          </h1>
          <p className="text-sm text-zinc-500 mt-1 ml-[52px]">Managing demat authorizations for {user?.full_name || user?.username}</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => setBulkMode(!bulkMode)}
            className={`flex items-center gap-2 text-xs font-black px-4 py-2.5 rounded-xl border uppercase tracking-widest transition-all ${
              bulkMode ? 'bg-blue-500 text-white border-blue-500' : 'bg-blue-500/10 text-blue-400 border-blue-500/20 hover:bg-blue-500/20'
            }`}
          >
            <ShieldCheck className="w-4 h-4" /> Bulk Authorize
          </button>
          <a 
            href="https://edis.cdslindia.com" 
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-2 text-xs font-black text-zinc-400 bg-white/[0.04] hover:bg-white/[0.08] px-4 py-2.5 rounded-xl border border-white/[0.08] uppercase tracking-widest transition-all"
          >
            <ExternalLink className="w-4 h-4" /> CDSL Portal
          </a>
        </div>
      </div>

      {loading ? (
        <div className="space-y-4">
          {[1,2,3].map(i => <div key={i} className="skeleton h-28 rounded-2xl" />)}
        </div>
      ) : (
        <>
          {/* Demat Account Card */}
          {demat && (
            <div className="glass-panel overflow-hidden">
              <div className="bg-gradient-to-r from-[#0d1225] to-[#101830] p-6 border-b border-white/[0.06]">
                <div className="flex items-center gap-3 mb-5">
                  <Building2 className="w-5 h-5 text-blue-400" />
                  <h2 className="text-sm font-black text-white uppercase tracking-widest">Demat Account Details</h2>
                  <span className={`ml-auto px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border ${
                    demat.demat_status === 'Active' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' : 'bg-red-500/10 text-red-400 border-red-500/20'
                  }`}>
                    {demat.demat_status}
                  </span>
                </div>
                
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                  {[
                    { label: 'DP ID', value: demat.dp_id, copyable: true },
                    { label: 'BO ID (Client)', value: demat.bo_id, copyable: true },
                    { label: 'Client ID', value: demat.client_id },
                    { label: 'Depository', value: demat.depository, badge: true },
                    { label: 'POA Status', value: demat.poa_status, badge: true, badgeColor: 'amber' },
                    { label: 'Registered Mobile', value: demat.registered_mobile },
                    { label: 'Registered Email', value: demat.registered_email },
                    { label: 'PAN', value: demat.pan },
                  ].map((item, idx) => (
                    <div key={idx} className="p-3 bg-white/[0.03] rounded-xl border border-white/[0.04]">
                      <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest mb-1">{item.label}</p>
                      {item.badge ? (
                        <span className={`inline-block px-2 py-0.5 text-[10px] font-bold rounded-md ${
                          item.badgeColor === 'amber' ? 'bg-amber-500/10 text-amber-400' : 'bg-blue-500/10 text-blue-400'
                        }`}>{item.value}</span>
                      ) : (
                        <p className="text-xs font-bold text-white font-mono-data flex items-center gap-1.5">
                          {item.value}
                          {item.copyable && (
                            <button onClick={() => copyToClipboard(item.value)} className="text-zinc-700 hover:text-primary transition-colors">
                              <Copy className="w-3 h-3" />
                            </button>
                          )}
                        </p>
                      )}
                    </div>
                  ))}
                </div>
              </div>

              {/* Nominee */}
              <div className="p-4 flex items-center gap-3 bg-white/[0.02]">
                <User className="w-4 h-4 text-zinc-600" />
                <span className="text-[10px] text-zinc-600 font-bold uppercase tracking-widest">Nominee:</span>
                <span className="text-xs text-white font-bold">{demat.nominee}</span>
              </div>
            </div>
          )}

          {/* Bulk Authorize Panel */}
          <AnimatePresence>
            {bulkMode && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                className="glass-panel p-6 border-2 border-blue-500/20 overflow-hidden"
              >
                <div className="flex items-center gap-3 mb-4">
                  <AlertTriangle className="w-5 h-5 text-amber-400" />
                  <h3 className="text-sm font-bold text-white">Bulk CDSL Authorization</h3>
                  <span className="text-[10px] text-zinc-600">ΓÇö Select holdings below and enter T-PIN to authorize all</span>
                </div>
                
                <div className="flex items-center gap-4">
                  <div className="flex-1 relative">
                    <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                    <input
                      type="password"
                      placeholder="Enter T-PIN"
                      maxLength={6}
                      value={bulkTpin}
                      onChange={(e) => setBulkTpin(e.target.value.replace(/\D/g, ''))}
                      className="w-full bg-white/[0.03] border border-white/[0.08] rounded-xl py-3 pl-11 pr-4 text-white font-mono-data tracking-widest focus:border-blue-500/50 outline-none"
                    />
                  </div>
                  <button
                    onClick={handleBulkAuthorize}
                    disabled={bulkTpin.length < 6 || selectedForBulk.length === 0 || bulkLoading}
                    className="px-6 py-3 bg-blue-500 text-white font-bold rounded-xl hover:bg-blue-600 transition-all disabled:opacity-40 flex items-center gap-2"
                  >
                    {bulkLoading ? <RefreshCw className="w-4 h-4 animate-spin" /> : <ShieldCheck className="w-4 h-4" />}
                    Authorize {selectedForBulk.length} Stock{selectedForBulk.length !== 1 ? 's' : ''}
                  </button>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {/* Holdings Authorization Status */}
          <div className="glass-panel overflow-hidden">
            <div className="p-5 border-b border-white/[0.06] flex items-center justify-between">
              <h2 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                <Key className="w-4 h-4 text-zinc-500" />
                Holdings Authorization Status
              </h2>
              <div className="flex items-center gap-3 text-[10px] font-bold uppercase tracking-widest">
                <span className="text-emerald-400 flex items-center gap-1"><CheckCircle2 className="w-3 h-3" /> {activeAuths.length} Authorized</span>
                <span className="text-amber-400 flex items-center gap-1"><Clock className="w-3 h-3" /> {pendingAuths.length} Pending</span>
              </div>
            </div>

            {holdings.length === 0 ? (
              <div className="p-12 text-center">
                <Lock className="w-12 h-12 text-zinc-700 mx-auto mb-4" />
                <h3 className="text-lg font-bold text-zinc-400">No Holdings Found</h3>
                <p className="text-sm text-zinc-600 mt-1">Acquire assets to manage authorizations here.</p>
                <Link to="/" className="inline-block mt-4 px-5 py-2.5 bg-primary/10 border border-primary/20 text-primary text-sm font-bold rounded-xl hover:bg-primary/20 transition-all no-underline">
                  Explore Equities
                </Link>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="border-b border-white/[0.06] text-zinc-500 text-[10px] uppercase tracking-widest">
                      {bulkMode && <th className="py-4 px-5 font-bold w-10"></th>}
                      <th className="py-4 px-5 font-bold">Symbol</th>
                      <th className="py-4 px-5 font-bold">ISIN</th>
                      <th className="py-4 px-5 font-bold text-right">Qty</th>
                      <th className="py-4 px-5 font-bold text-center">Auth Status</th>
                      <th className="py-4 px-5 font-bold text-right">Auth Qty</th>
                      <th className="py-4 px-5 font-bold text-right">Expiry</th>
                      <th className="py-4 px-5 font-bold">DIS Slip</th>
                    </tr>
                  </thead>
                  <tbody>
                    {holdings.map((h, i) => (
                      <tr key={i} className="border-b border-white/[0.04] hover:bg-white/[0.02] transition-colors">
                        {bulkMode && (
                          <td className="py-3.5 px-5">
                            <input 
                              type="checkbox"
                              checked={selectedForBulk.includes(h.symbol)}
                              onChange={() => toggleBulkSelect(h.symbol)}
                              disabled={h.authorized}
                              className="accent-blue-500 w-4 h-4 cursor-pointer disabled:opacity-30"
                            />
                          </td>
                        )}
                        <td className="py-3.5 px-5">
                          <Link to={`/stock/${h.symbol}`} className="font-bold text-white hover:text-primary transition-colors text-sm no-underline">{h.symbol}</Link>
                          <p className="text-[9px] text-zinc-600">{h.exchange} ΓÇó {h.segment}</p>
                        </td>
                        <td className="py-3.5 px-5 text-[11px] font-mono-data text-zinc-400">{h.isin}</td>
                        <td className="py-3.5 px-5 text-right font-bold text-white font-mono-data">{h.quantity}</td>
                        <td className="py-3.5 px-5 text-center">
                          {h.authorized ? (
                            <span className="px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 inline-flex items-center gap-1">
                              <CheckCircle2 className="w-3 h-3" /> Authorized
                            </span>
                          ) : (
                            <span className="px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider bg-amber-500/10 text-amber-400 border border-amber-500/20 inline-flex items-center gap-1">
                              <Clock className="w-3 h-3" /> Pending
                            </span>
                          )}
                        </td>
                        <td className="py-3.5 px-5 text-right font-mono-data text-sm">
                          {h.authorized ? <span className="text-emerald-400 font-bold">{h.authorized_qty}</span> : <span className="text-zinc-600">ΓÇö</span>}
                        </td>
                        <td className="py-3.5 px-5 text-right">
                          {h.authorized ? (
                            <div>
                              <p className="text-[10px] font-mono-data text-zinc-400">{h.authorized_until?.replace('T', ' ')?.slice(0,19)}</p>
                              <p className="text-[9px] text-emerald-400 font-bold">{h.remaining_hours}h remaining</p>
                            </div>
                          ) : (
                            <span className="text-zinc-600 text-[10px]">ΓÇö</span>
                          )}
                        </td>
                        <td className="py-3.5 px-5">
                          {h.dis_slip_no ? (
                            <p className="text-[10px] font-mono-data text-zinc-400">{h.dis_slip_no}</p>
                          ) : (
                            <span className="text-zinc-700 text-[10px]">ΓÇö</span>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>

          {/* Authorization History */}
          <div className="glass-panel overflow-hidden">
            <div className="p-5 border-b border-white/[0.06]">
              <h2 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2">
                <FileText className="w-4 h-4 text-zinc-500" />
                DIS Slip History ({authHistory.length})
              </h2>
            </div>

            {authHistory.length === 0 ? (
              <div className="p-12 text-center">
                <FileText className="w-12 h-12 text-zinc-700 mx-auto mb-4" />
                <h3 className="text-lg font-bold text-zinc-400">No DIS slips generated yet</h3>
                <p className="text-sm text-zinc-600 mt-1">Authorization records will appear here after T-PIN verification</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="border-b border-white/[0.06] text-zinc-500 text-[10px] uppercase tracking-widest">
                      <th className="py-4 px-5 font-bold">DIS Slip No.</th>
                      <th className="py-4 px-5 font-bold">Symbol</th>
                      <th className="py-4 px-5 font-bold">ISIN</th>
                      <th className="py-4 px-5 font-bold text-right">Qty</th>
                      <th className="py-4 px-5 font-bold">DP ID</th>
                      <th className="py-4 px-5 font-bold text-center">Status</th>
                      <th className="py-4 px-5 font-bold text-right">Auth Date</th>
                      <th className="py-4 px-5 font-bold text-right">Expiry</th>
                    </tr>
                  </thead>
                  <tbody>
                    {authHistory.map((h, i) => (
                      <tr key={i} className="border-b border-white/[0.04] hover:bg-white/[0.02] transition-colors">
                        <td className="py-3.5 px-5 text-[11px] font-mono-data text-blue-400 font-bold">{h.dis_slip_no}</td>
                        <td className="py-3.5 px-5 font-bold text-white text-sm">{h.symbol}</td>
                        <td className="py-3.5 px-5 text-[11px] font-mono-data text-zinc-400">{h.isin}</td>
                        <td className="py-3.5 px-5 text-right font-bold text-zinc-300 font-mono-data">{h.quantity}</td>
                        <td className="py-3.5 px-5 text-[11px] font-mono-data text-zinc-500">{h.dp_id}</td>
                        <td className="py-3.5 px-5 text-center">
                          <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border ${
                            h.status === 'ACTIVE' 
                              ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20' 
                              : 'bg-zinc-500/10 text-zinc-400 border-zinc-500/20'
                          }`}>
                            {h.status}
                          </span>
                        </td>
                        <td className="py-3.5 px-5 text-right text-[10px] font-mono-data text-zinc-500">{h.authorized_at?.slice(0,19)}</td>
                        <td className="py-3.5 px-5 text-right text-[10px] font-mono-data text-zinc-500">{h.expiry?.slice(0,19)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </>
      )}
    </motion.div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Users, TrendingUp, Star, Shield, Zap, Target, Award, ChevronRight, BarChart2, Clock, Trophy, CheckCircle, AlertTriangle, Loader2, Copy, UserPlus } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, Cell } from 'recharts';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import { API_BASE_URL } from '../config';

const STYLE_COLORS = {
  Momentum: '#f59e0b', Value: '#8b5cf6', 'Day Trading': '#ef4444', Dividend: '#10b981',
  Algorithmic: '#0ea5e9', 'Swing Trading': '#ec4899', Growth: '#6366f1', Options: '#f97316',
};

const RISK_CONFIG = {
  LOW: { color: '#10b981', bg: 'bg-emerald-500/10', label: 'Low Risk' },
  MEDIUM: { color: '#f59e0b', bg: 'bg-amber-500/10', label: 'Medium Risk' },
  HIGH: { color: '#ef4444', bg: 'bg-rose-500/10', label: 'High Risk' },
};

export default function CopyTrading() {
  const { user } = useUser();
  const toast = useToast();
  const [traders, setTraders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedTrader, setSelectedTrader] = useState(null);
  const [followModal, setFollowModal] = useState(null);
  const [allocation, setAllocation] = useState(10);
  const [following, setFollowing] = useState(false);
  const [sortBy, setSortBy] = useState('return');

  useEffect(() => { fetchTraders(); }, []);

  const fetchTraders = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/copytrading/traders`);
      setTraders(res.data.traders);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const handleFollow = async (traderId) => {
    setFollowing(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/copytrading/follow`, {
        trader_id: traderId, allocation_pct: allocation,
      }, { params: { user_id: user?.id || 1 } });
      toast.success(res.data.message);
      setFollowModal(null);
