import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Activity, Search, Zap, ArrowUpRight, ArrowDownRight, BarChart2, Eye, RefreshCw, AlertTriangle, Layers } from 'lucide-react';
import axios from 'axios';
import { API_BASE_URL } from '../config';
import useSocket from '../hooks/useSocket';
import SimulatedBadge from '../components/SimulatedBadge';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, BarChart, Bar, Cell } from 'recharts';

const fadeUp = { hidden: { opacity: 0, y: 20 }, show: { opacity: 1, y: 0, transition: { duration: 0.5 } } };

export default function Microstructure() {
  const [symbol, setSymbol] = useState('RELIANCE');
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchInput, setSearchInput] = useState('RELIANCE');
  const { socket, isConnected, data: socketData } = useSocket('microstructure_update');

  const fetchData = (sym) => {
    setLoading(true);
    axios.get(`${API_BASE_URL}/api/microstructure/${sym}`)
      .then(res => { setData(res.data); setSymbol(sym); })
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { 
    fetchData('RELIANCE'); 
  }, []);

  useEffect(() => {
    if (socket && isConnected && symbol) {
      socket.emit('subscribe_microstructure', symbol);
    }
  }, [socket, isConnected, symbol]);

  useEffect(() => {
    if (socketData && socketData.symbol === symbol) {
      setData(prev => {
        if (!prev) return prev;
        const newTape = [socketData.new_trade, ...prev.trade_tape].slice(0, 50);
        return {
          ...prev,
          current_price: socketData.current_price,
          order_book: socketData.order_book,
          trade_tape: newTape
        };
      });
    }
  }, [socketData, symbol]);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchInput.trim()) fetchData(searchInput.trim().toUpperCase());
  };

  if (loading) {
    return (
      <div className="h-96 flex items-center justify-center flex-col gap-4">
        <RefreshCw className="w-8 h-8 text-emerald-400 animate-spin" />
        <p className="text-zinc-400 font-bold animate-pulse text-sm">Analyzing order flow...</p>
      </div>
    );
  }

  return (
    <motion.div variants={fadeUp} initial="hidden" animate="show" className="space-y-8">
      {/* Header */}
      <div className="relative overflow-hidden rounded-[28px] border border-white/[0.06] bg-gradient-to-br from-[#040d08] via-surface to-surface p-8 md:p-12">
        <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-emerald-500/10 rounded-full blur-[150px] pointer-events-none" />
        <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-emerald-500/20 to-teal-500/20 border border-emerald-500/20 flex items-center justify-center">
              <Layers className="w-7 h-7 text-emerald-400" />
            </div>
            <div>
              <h1 className="text-3xl md:text-4xl font-black text-white">Market Microstructure</h1>
              <p className="text-zinc-500 text-sm mt-0.5">Bloomberg-grade order flow analytics on your dashboard</p>
              <div className="mt-2">
                <SimulatedBadge title="The order book, trade tape and signals on this page are generated for demonstration and are not a live exchange feed." />
              </div>
            </div>
          </div>
          <form onSubmit={handleSearch} className="flex gap-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input value={searchInput} onChange={e => setSearchInput(e.target.value.toUpperCase())} placeholder="Symbol..."
                className="bg-white/[0.03] border border-white/[0.08] rounded-xl px-4 pl-10 py-3 text-sm font-bold text-white focus:outline-none focus:border-emerald-500/40 w-48" />
            </div>
            <button type="submit" className="px-6 py-3 bg-emerald-500/15 border border-emerald-500/30 text-emerald-400 font-black text-xs uppercase tracking-widest rounded-xl hover:bg-emerald-500/25 transition-all">
              Scan
            </button>
          </form>
        </div>
      </div>

      {data && (
        <>
          {/* Signal Cards */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            {[
              { label: 'Order Imbalance', value: data.signals?.order_imbalance, color: data.signals?.order_imbalance?.includes('BUY') ? 'emerald' : data.signals?.order_imbalance?.includes('SELL') ? 'red' : 'zinc' },
              { label: 'Spread Quality', value: data.spread?.quality, color: data.spread?.quality === 'TIGHT' ? 'emerald' : data.spread?.quality === 'WIDE' ? 'red' : 'amber' },
              { label: 'Spread Trend', value: data.signals?.spread_trend, color: data.signals?.spread_trend === 'TIGHTENING' ? 'emerald' : data.signals?.spread_trend === 'WIDENING' ? 'red' : 'zinc' },
              { label: 'Block Alert', value: data.signals?.large_order_alert ? '≡ƒÜ¿ ACTIVE' : 'None', color: data.signals?.large_order_alert ? 'amber' : 'zinc' },
            ].map((s, i) => (
              <div key={i} className="glass-panel p-5 border border-white/[0.04]">
                <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-3">{s.label}</p>
                <p className={`text-sm font-black text-${s.color}-400 uppercase tracking-wider`}>{s.value}</p>
              </div>
            ))}
          </div>

          {/* Order Book Depth + Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Order Book Visualization */}
            <div className="glass-panel p-6 border border-white/[0.04]">
              <h3 className="text-xs font-black text-white uppercase tracking-widest mb-5 flex items-center gap-2">
                <Layers className="w-4 h-4 text-emerald-400" /> Level 2 Order Book ΓÇö {data.symbol}
              </h3>
              <div className="space-y-1.5">
                {/* Asks (reversed) */}
                {[...data.order_book?.asks || []].reverse().map((a, i) => (
                  <div key={`a${i}`} className="flex items-center gap-2 relative h-8">
                    <div className="absolute right-0 top-0 h-full bg-red-500/8 rounded-r"
                      style={{ width: `${Math.min(100, (a.quantity / 50000) * 100)}%` }} />
                    <span className="text-[10px] font-mono text-zinc-500 w-8 text-right z-10">{a.orders}</span>
                    <span className="text-xs font-bold text-red-400 font-mono-data w-20 z-10">Γé╣{a.price?.toLocaleString()}</span>
                    <span className="text-[10px] text-zinc-500 font-mono-data z-10 flex-1 text-right">{a.quantity?.toLocaleString()}</span>
                  </div>
                ))}
                
                {/* Spread Line */}
                <div className="flex items-center gap-3 py-2 border-y border-white/[0.06]">
                  <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Spread</span>
                  <span className="text-xs font-black text-white font-mono-data">Γé╣{data.spread?.absolute}</span>
                  <span className="text-[9px] font-bold text-zinc-500">({data.spread?.percentage}%)</span>
                  <span className="text-lg font-black text-white ml-auto font-mono-data">Γé╣{data.current_price?.toLocaleString()}</span>
                </div>
                
                {/* Bids */}
                {data.order_book?.bids?.map((b, i) => (
                  <div key={`b${i}`} className="flex items-center gap-2 relative h-8">
                    <div className="absolute left-0 top-0 h-full bg-emerald-500/8 rounded-l"
                      style={{ width: `${Math.min(100, (b.quantity / 50000) * 100)}%` }} />
                    <span className="text-[10px] font-mono text-zinc-500 w-8 text-right z-10">{b.orders}</span>
                    <span className="text-xs font-bold text-emerald-400 font-mono-data w-20 z-10">Γé╣{b.price?.toLocaleString()}</span>
                    <span className="text-[10px] text-zinc-500 font-mono-data z-10 flex-1 text-right">{b.quantity?.toLocaleString()}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Liquidity Metrics */}
            <div className="space-y-6">
              <div className="glass-panel p-6 border border-white/[0.04]">
                <h3 className="text-xs font-black text-white uppercase tracking-widest mb-5 flex items-center gap-2">
                  <Activity className="w-4 h-4 text-sky-400" /> Liquidity Metrics
                </h3>
                <div className="grid grid-cols-2 gap-3">
                  {[
                    { label: 'Bid Depth', value: data.liquidity?.total_bid_depth?.toLocaleString(), color: 'emerald' },
                    { label: 'Ask Depth', value: data.liquidity?.total_ask_depth?.toLocaleString(), color: 'red' },
                    { label: 'Bid/Ask Ratio', value: data.liquidity?.bid_ask_ratio, color: data.liquidity?.bid_ask_ratio > 1 ? 'emerald' : 'red' },
                    { label: 'VWAP', value: `Γé╣${data.liquidity?.vwap?.toLocaleString()}`, color: 'violet' },
                    { label: 'Avg Trade Size', value: data.liquidity?.avg_trade_size, color: 'amber' },
                    { label: 'Impact Cost (1Cr)', value: `${data.liquidity?.impact_cost_1cr}%`, color: 'cyan' },
                  ].map((m, i) => (
                    <div key={i} className="p-3 rounded-xl bg-white/[0.02] border border-white/[0.04]">
                      <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">{m.label}</p>
                      <p className={`text-sm font-black text-${m.color}-400 font-mono-data`}>{m.value}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Hidden Liquidity Alert */}
              {data.signals?.hidden_liquidity && (
                <div className="glass-panel p-4 border border-amber-500/20 bg-amber-500/5 flex items-center gap-3">
                  <Eye className="w-5 h-5 text-amber-400" />
                  <div>
                    <p className="text-xs font-black text-amber-400">Hidden Liquidity Detected</p>
                    <p className="text-[10px] text-zinc-500 font-bold">Iceberg orders detected ΓÇö large orders being hidden below surface</p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Order Flow Imbalance Timeline */}
          <div className="glass-panel p-6 border border-white/[0.04]">
            <h3 className="text-xs font-black text-white uppercase tracking-widest mb-6 flex items-center gap-2">
              <BarChart2 className="w-4 h-4 text-violet-400" /> Order Flow Imbalance (OFI)
            </h3>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data.ofi_timeline} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#ffffff08" vertical={false} />
                  <XAxis dataKey="time" stroke="#52525b" tick={{ fill: '#71717a', fontSize: 9 }} minTickGap={20} />
                  <YAxis stroke="#52525b" tick={{ fill: '#71717a', fontSize: 10 }} />
                  <ReferenceLine y={0} stroke="#ffffff15" strokeDasharray="3 3" />
                  <Tooltip content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      const d = payload[0].payload;
                      return (
                        <div className="bg-[#0a0a12]/95 backdrop-blur-xl border border-white/10 p-4 rounded-2xl shadow-2xl">
                          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2">{d.time}</p>
                          <p className={`text-sm font-black ${d.ofi >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>OFI: {d.ofi}%</p>
                          <p className="text-xs text-zinc-500">Buy: {d.buy_volume?.toLocaleString()} | Sell: {d.sell_volume?.toLocaleString()}</p>
                        </div>
                      );
                    }
                    return null;
                  }} />
                  <Bar dataKey="ofi" radius={[3, 3, 0, 0]}>
                    {data.ofi_timeline?.map((entry, index) => (
                      <Cell key={index} fill={entry.ofi >= 0 ? '#10b981' : '#ef4444'} fillOpacity={0.6} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Trade Tape */}
          <div className="glass-panel p-6 border border-white/[0.04]">
            <h3 className="text-xs font-black text-white uppercase tracking-widest mb-5 flex items-center gap-2">
              <Zap className="w-4 h-4 text-amber-400" /> Live Trade Tape
            </h3>
            <div className="overflow-x-auto max-h-[400px] overflow-y-auto">
              <table className="w-full">
                <thead className="sticky top-0 bg-surface">
                  <tr className="border-b border-white/[0.06]">
                    {['Time', 'Side', 'Price', 'Qty', 'Value', 'Type'].map(h => (
                      <th key={h} className="text-[9px] font-black text-zinc-600 uppercase tracking-widest py-3 px-3 text-left">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {data.trade_tape?.map((t, i) => (
                    <tr key={i} className={`border-b border-white/[0.02] hover:bg-white/[0.02] transition-colors ${t.is_block ? 'bg-amber-500/[0.03]' : ''}`}>
                      <td className="py-2.5 px-3 text-[10px] text-zinc-500 font-mono">{t.time}</td>
                      <td className="py-2.5 px-3">
                        <span className={`text-[9px] font-black px-2 py-0.5 rounded ${t.side === 'BUY' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-red-500/10 text-red-400'}`}>{t.side}</span>
                      </td>
                      <td className="py-2.5 px-3 text-xs font-bold text-white font-mono-data">Γé╣{t.price?.toLocaleString()}</td>
                      <td className="py-2.5 px-3 text-xs text-zinc-400 font-mono-data">{t.quantity?.toLocaleString()}</td>
                      <td className="py-2.5 px-3 text-xs text-zinc-400 font-mono-data">Γé╣{t.value?.toLocaleString()}</td>
                      <td className="py-2.5 px-3">
                        {t.is_block && <span className="text-[8px] font-black px-2 py-0.5 rounded bg-amber-500/10 text-amber-400 uppercase tracking-widest">BLOCK</span>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}
    </motion.div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Target, Plus, Minus, Trash2, Zap, TrendingUp, TrendingDown, Shield, AlertTriangle, BarChart2, Loader2, Info, ChevronRight } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine } from 'recharts';
import axios from 'axios';
import { API_BASE_URL } from '../config';

export default function OptionsBuilder() {
  const [symbol, setSymbol] = useState('NIFTY');
  const [chain, setChain] = useState(null);
  const [templates, setTemplates] = useState([]);
  const [legs, setLegs] = useState([]);
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(true);
  const [analyzing, setAnalyzing] = useState(false);
  const [chainView, setChainView] = useState('both'); // calls, puts, both

  useEffect(() => { fetchChain(); fetchTemplates(); }, [symbol]);

  const fetchChain = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/options/chain/${symbol}`);
      setChain(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const fetchTemplates = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/options/strategies/templates`);
      setTemplates(res.data.templates);
    } catch (e) { console.error(e); }
  };

  const addLeg = (type, strike, premium, position) => {
    setLegs(prev => [...prev, { option_type: type, strike, premium, position, quantity: 1 }]);
    setAnalysis(null);
  };

  const removeLeg = (index) => {
    setLegs(prev => prev.filter((_, i) => i !== index));
    setAnalysis(null);
  };

  const analyzeStrategy = async () => {
    if (legs.length === 0) return;
    setAnalyzing(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/options/strategy/analyze`, {
        symbol, legs, lot_size: chain?.lot_size || 50,
      });
      setAnalysis(res.data);
    } catch (e) { console.error(e); }
    finally { setAnalyzing(false); }
  };

  const applyTemplate = (template) => {
    if (!chain) return;
    const atm = chain.atm_strike;
    const interval = chain.strikes.length > 1 ? Math.abs(chain.strikes[1].strike - chain.strikes[0].strike) : 50;
    const newLegs = [];
    
    const getStrike = (offset) => atm + offset * interval;
    const getPremium = (strike, type) => {
      const found = chain.strikes.find(s => s.strike === strike);
      return found ? (type === 'CALL' ? found.ce_premium : found.pe_premium) : 50;
    };

    if (template.name === 'Long Straddle') {
      newLegs.push({ option_type: 'CALL', strike: atm, premium: getPremium(atm, 'CALL'), position: 'BUY', quantity: 1 });
      newLegs.push({ option_type: 'PUT', strike: atm, premium: getPremium(atm, 'PUT'), position: 'BUY', quantity: 1 });
    } else if (template.name === 'Short Straddle') {
      newLegs.push({ option_type: 'CALL', strike: atm, premium: getPremium(atm, 'CALL'), position: 'SELL', quantity: 1 });
      newLegs.push({ option_type: 'PUT', strike: atm, premium: getPremium(atm, 'PUT'), position: 'SELL', quantity: 1 });
    } else if (template.name === 'Bull Call Spread') {
      newLegs.push({ option_type: 'CALL', strike: atm, premium: getPremium(atm, 'CALL'), position: 'BUY', quantity: 1 });
      newLegs.push({ option_type: 'CALL', strike: getStrike(2), premium: getPremium(getStrike(2), 'CALL'), position: 'SELL', quantity: 1 });
    } else if (template.name === 'Bear Put Spread') {
      newLegs.push({ option_type: 'PUT', strike: atm, premium: getPremium(atm, 'PUT'), position: 'BUY', quantity: 1 });
      newLegs.push({ option_type: 'PUT', strike: getStrike(-2), premium: getPremium(getStrike(-2), 'PUT'), position: 'SELL', quantity: 1 });
    } else if (template.name === 'Iron Condor') {
      newLegs.push({ option_type: 'PUT', strike: getStrike(-3), premium: getPremium(getStrike(-3), 'PUT'), position: 'BUY', quantity: 1 });
      newLegs.push({ option_type: 'PUT', strike: getStrike(-2), premium: getPremium(getStrike(-2), 'PUT'), position: 'SELL', quantity: 1 });
      newLegs.push({ option_type: 'CALL', strike: getStrike(2), premium: getPremium(getStrike(2), 'CALL'), position: 'SELL', quantity: 1 });
      newLegs.push({ option_type: 'CALL', strike: getStrike(3), premium: getPremium(getStrike(3), 'CALL'), position: 'BUY', quantity: 1 });
    }
    
    setLegs(newLegs);
    setAnalysis(null);
  };

  const SYMBOLS = ['NIFTY', 'BANKNIFTY', 'RELIANCE', 'TCS', 'INFY', 'HDFCBANK', 'SBIN', 'TATAMOTORS'];

  if (loading) return <div className="py-20 text-center"><Loader2 className="w-8 h-8 text-primary mx-auto animate-spin" /></div>;

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-black text-white flex items-center gap-3">
          <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-orange-500/20 to-red-500/20 border border-orange-500/20 flex items-center justify-center">
            <Target className="w-6 h-6 text-orange-400" />
          </div>
          Options Strategy Builder
        </h1>
        <p className="text-zinc-500 mt-2 text-sm">Visual P&L payoff diagrams ΓÇó Multi-leg strategies ΓÇó Exclusive to NexusAI</p>
      </div>

      {/* Symbol Selector */}
      <div className="flex gap-2 overflow-x-auto pb-1 hide-scrollbar">
        {SYMBOLS.map(sym => (
          <button key={sym} onClick={() => { setSymbol(sym); setLegs([]); setAnalysis(null); }}
            className={`px-4 py-2 text-xs font-black uppercase tracking-widest rounded-xl shrink-0 transition-all ${
              symbol === sym ? 'bg-orange-500/10 text-orange-400 border border-orange-500/20' : 'bg-white/[0.03] text-zinc-600 border border-white/[0.06] hover:text-white'
            }`}>{sym}</button>
        ))}
      </div>

      {/* Strategy Templates */}
      <div>
        <h2 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-3 flex items-center gap-2">
          <Zap size={14} className="text-orange-400" /> Quick Strategies
        </h2>
        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          {templates.map((t, i) => (
            <motion.button key={t.name} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              onClick={() => applyTemplate(t)}
              className="glass-panel p-4 text-left hover:border-orange-500/20 transition-all group">
              <div className="flex items-center gap-2 mb-2">
                <span className="text-lg">{t.icon}</span>
                <span className={`text-[9px] font-black px-2 py-0.5 rounded uppercase tracking-widest ${
                  t.difficulty === 'BEGINNER' ? 'bg-emerald-500/10 text-emerald-400' :
                  t.difficulty === 'INTERMEDIATE' ? 'bg-amber-500/10 text-amber-400' :
                  t.difficulty === 'ADVANCED' ? 'bg-purple-500/10 text-purple-400' :
                  'bg-rose-500/10 text-rose-400'
                }`}>{t.difficulty}</span>
              </div>
              <p className="text-xs font-black text-white mb-1 group-hover:text-orange-400 transition-colors">{t.name}</p>
              <p className="text-[10px] text-zinc-600 line-clamp-2">{t.description}</p>
              <div className="mt-2 flex items-center gap-2">
                <span className="text-[9px] font-bold text-zinc-700">{t.market_view}</span>
              </div>
            </motion.button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Options Chain */}
        <div className="lg:col-span-2 glass-panel overflow-hidden">
          <div className="p-4 border-b border-white/[0.04] flex items-center justify-between">
            <div className="flex items-center gap-3">
              <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em]">Options Chain</h3>
              {chain && <span className="text-xs font-bold text-white font-mono-data">Spot: Γé╣{chain.spot_price.toLocaleString()}</span>}
              {chain && <span className="text-[10px] text-zinc-600 font-mono-data">Lot: {chain.lot_size}</span>}
            </div>
            <div className="flex gap-1">
              {['calls', 'both', 'puts'].map(v => (
                <button key={v} onClick={() => setChainView(v)}
                  className={`px-3 py-1 text-[10px] font-black uppercase tracking-widest rounded-lg transition-all ${
                    chainView === v ? 'bg-white/[0.08] text-white' : 'text-zinc-600 hover:text-white'
                  }`}>{v}</button>
              ))}
            </div>
          </div>
          
          <div className="overflow-x-auto max-h-[500px] overflow-y-auto">
            <table className="w-full text-xs">
              <thead className="sticky top-0 bg-surface z-10">
                <tr className="border-b border-white/[0.04]">
                  {(chainView !== 'puts') && (
                    <>
                      <th className="p-2 text-[9px] font-black text-zinc-600 tracking-widest text-center">OI</th>
                      <th className="p-2 text-[9px] font-black text-zinc-600 tracking-widest text-center">IV</th>
                      <th className="p-2 text-[9px] font-black text-emerald-400 tracking-widest text-center">CE Γé╣</th>
                      <th className="p-2 text-[9px] font-black text-emerald-400 tracking-widest text-center">BUY</th>
                      <th className="p-2 text-[9px] font-black text-rose-400 tracking-widest text-center">SELL</th>
                    </>
                  )}
                  <th className="p-2 text-[9px] font-black text-amber-400 tracking-widest text-center bg-white/[0.02]">STRIKE</th>
                  {(chainView !== 'calls') && (
                    <>
                      <th className="p-2 text-[9px] font-black text-emerald-400 tracking-widest text-center">BUY</th>
                      <th className="p-2 text-[9px] font-black text-rose-400 tracking-widest text-center">SELL</th>
                      <th className="p-2 text-[9px] font-black text-red-400 tracking-widest text-center">PE Γé╣</th>
                      <th className="p-2 text-[9px] font-black text-zinc-600 tracking-widest text-center">IV</th>
                      <th className="p-2 text-[9px] font-black text-zinc-600 tracking-widest text-center">OI</th>
                    </>
                  )}
                </tr>
              </thead>
              <tbody>
                {chain?.strikes.map((s, i) => (
                  <tr key={i} className={`border-b border-white/[0.02] hover:bg-white/[0.02] transition-all ${
                    s.is_atm ? 'bg-amber-500/[0.04] border-l-2 border-l-amber-500' : ''
                  }`}>
                    {(chainView !== 'puts') && (
                      <>
                        <td className="p-2 text-center text-zinc-600 font-mono-data">{(s.ce_oi / 1000).toFixed(0)}K</td>
                        <td className="p-2 text-center text-zinc-500 font-mono-data">{s.ce_iv}%</td>
                        <td className="p-2 text-center font-bold text-emerald-400 font-mono-data">{s.ce_premium}</td>
                        <td className="p-2 text-center">
                          <button onClick={() => addLeg('CALL', s.strike, s.ce_premium, 'BUY')}
                            className="w-7 h-7 rounded-lg bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 transition-all flex items-center justify-center mx-auto">
                            <Plus size={12} />
                          </button>
                        </td>
                        <td className="p-2 text-center">
                          <button onClick={() => addLeg('CALL', s.strike, s.ce_premium, 'SELL')}
                            className="w-7 h-7 rounded-lg bg-rose-500/10 text-rose-400 hover:bg-rose-500/20 transition-all flex items-center justify-center mx-auto">
                            <Minus size={12} />
                          </button>
                        </td>
                      </>
                    )}
                    <td className={`p-2 text-center font-black font-mono-data bg-white/[0.02] ${s.is_atm ? 'text-amber-400' : 'text-white'}`}>
                      {s.strike}
                      {s.is_atm && <span className="text-[8px] ml-1 text-amber-500">ATM</span>}
                    </td>
                    {(chainView !== 'calls') && (
                      <>
                        <td className="p-2 text-center">
                          <button onClick={() => addLeg('PUT', s.strike, s.pe_premium, 'BUY')}
                            className="w-7 h-7 rounded-lg bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 transition-all flex items-center justify-center mx-auto">
                            <Plus size={12} />
                          </button>
                        </td>
                        <td className="p-2 text-center">
                          <button onClick={() => addLeg('PUT', s.strike, s.pe_premium, 'SELL')}
                            className="w-7 h-7 rounded-lg bg-rose-500/10 text-rose-400 hover:bg-rose-500/20 transition-all flex items-center justify-center mx-auto">
                            <Minus size={12} />
                          </button>
                        </td>
                        <td className="p-2 text-center font-bold text-red-400 font-mono-data">{s.pe_premium}</td>
                        <td className="p-2 text-center text-zinc-500 font-mono-data">{s.pe_iv}%</td>
                        <td className="p-2 text-center text-zinc-600 font-mono-data">{(s.pe_oi / 1000).toFixed(0)}K</td>
                      </>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Strategy Builder Panel */}
        <div className="space-y-4">
          <div className="glass-panel p-5">
            <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Target size={14} className="text-orange-400" /> Your Strategy
            </h3>
            
            {legs.length === 0 ? (
              <div className="py-8 text-center">
                <Target className="w-10 h-10 text-zinc-700 mx-auto mb-3" />
                <p className="text-xs text-zinc-600">Click BUY/SELL on the chain or use Quick Strategies above</p>
              </div>
            ) : (
              <div className="space-y-2">
                {legs.map((leg, i) => (
                  <motion.div key={i} initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }}
                    className={`flex items-center gap-3 p-3 rounded-xl border ${
                      leg.position === 'BUY' ? 'bg-emerald-500/[0.03] border-emerald-500/10' : 'bg-rose-500/[0.03] border-rose-500/10'
                    }`}>
                    <span className={`text-[9px] font-black px-2 py-0.5 rounded uppercase ${
                      leg.position === 'BUY' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'
                    }`}>{leg.position}</span>
                    <span className={`text-xs font-bold ${leg.option_type === 'CALL' ? 'text-emerald-400' : 'text-red-400'}`}>
                      {leg.option_type}
                    </span>
                    <span className="text-xs font-black text-white font-mono-data">{leg.strike}</span>
                    <span className="text-xs text-zinc-500 font-mono-data">Γé╣{leg.premium}</span>
                    <button onClick={() => removeLeg(i)} className="ml-auto p-1 text-zinc-600 hover:text-rose-400 transition-colors">
                      <Trash2 size={12} />
                    </button>
                  </motion.div>
                ))}
                
                <button onClick={analyzeStrategy} disabled={analyzing}
                  className="w-full mt-4 py-3 bg-gradient-to-r from-orange-500 to-red-500 text-white font-black text-xs uppercase tracking-widest rounded-xl hover:opacity-90 transition-all disabled:opacity-50 flex items-center justify-center gap-2">
                  {analyzing ? <Loader2 size={14} className="animate-spin" /> : <BarChart2 size={14} />}
                  {analyzing ? 'Analyzing...' : 'Analyze Strategy'}
                </button>
                
                <button onClick={() => { setLegs([]); setAnalysis(null); }}
                  className="w-full py-2 text-xs font-bold text-zinc-600 hover:text-white transition-colors">
                  Clear All
                </button>
              </div>
            )}
          </div>

          {/* Analysis Results */}
          {analysis && (
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
              className="glass-panel p-5 space-y-4">
              <div className="flex items-center gap-2">
                <Zap size={14} className="text-orange-400" />
                <h3 className="text-xs font-black text-accent uppercase tracking-[0.2em]">{analysis.strategy_name}</h3>
              </div>
              
              <div className="grid grid-cols-2 gap-2">
                <div className="p-3 bg-emerald-500/[0.05] rounded-xl border border-emerald-500/10">
                  <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Max Profit</p>
                  <p className="text-lg font-black text-emerald-400 font-mono-data">
                    {analysis.max_profit > 100000 ? 'Unlimited' : `Γé╣${analysis.max_profit.toLocaleString()}`}
                  </p>
                </div>
                <div className="p-3 bg-rose-500/[0.05] rounded-xl border border-rose-500/10">
                  <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Max Loss</p>
                  <p className="text-lg font-black text-rose-400 font-mono-data">Γé╣{Math.abs(analysis.max_loss).toLocaleString()}</p>
                </div>
              </div>
              
              <div className="grid grid-cols-3 gap-2">
                <div className="text-center p-2 bg-white/[0.02] rounded-lg">
                  <p className="text-[9px] text-zinc-600 font-bold uppercase mb-0.5">PoP</p>
                  <p className="text-sm font-black text-white">{analysis.probability_of_profit}%</p>
                </div>
                <div className="text-center p-2 bg-white/[0.02] rounded-lg">
                  <p className="text-[9px] text-zinc-600 font-bold uppercase mb-0.5">R:R</p>
                  <p className="text-sm font-black text-amber-400">{analysis.risk_reward_ratio}x</p>
                </div>
                <div className="text-center p-2 bg-white/[0.02] rounded-lg">
                  <p className="text-[9px] text-zinc-600 font-bold uppercase mb-0.5">Net Γé╣</p>
                  <p className={`text-sm font-black ${analysis.net_premium >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                    {analysis.net_premium >= 0 ? '+' : ''}Γé╣{analysis.net_premium.toLocaleString()}
                  </p>
                </div>
              </div>
              
              {analysis.breakevens.length > 0 && (
                <div className="p-3 bg-amber-500/[0.03] rounded-xl border border-amber-500/10">
                  <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Breakeven(s)</p>
                  <p className="text-sm font-black text-amber-400 font-mono-data">
                    {analysis.breakevens.map(b => `Γé╣${b.toLocaleString()}`).join(' | ')}
                  </p>
                </div>
              )}
              
              <div className="p-3 bg-white/[0.02] rounded-xl">
                <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-2">Greeks</p>
                <div className="grid grid-cols-3 gap-2 text-xs">
                  <div><span className="text-zinc-600">╬ö</span> <span className="font-bold text-white">{analysis.greeks.delta}</span></div>
                  <div><span className="text-zinc-600">╬ÿ</span> <span className="font-bold text-white">{analysis.greeks.theta}</span></div>
                  <div><span className="text-zinc-600">V</span> <span className="font-bold text-white">{analysis.greeks.vega}</span></div>
                </div>
              </div>
            </motion.div>
          )}
        </div>
      </div>

      {/* P&L Payoff Chart */}
      {analysis && (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
          className="glass-panel p-6">
          <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
            <BarChart2 size={14} className="text-orange-400" /> P&L Payoff Diagram ΓÇö {analysis.strategy_name}
          </h3>
          <ResponsiveContainer width="100%" height={350}>
            <AreaChart data={analysis.payoff}>
              <defs>
                <linearGradient id="profitGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#10b981" stopOpacity={0.3} />
                  <stop offset="40%" stopColor="#10b981" stopOpacity={0.05} />
                  <stop offset="60%" stopColor="#ef4444" stopOpacity={0.05} />
                  <stop offset="100%" stopColor="#ef4444" stopOpacity={0.3} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
              <XAxis dataKey="spot" tick={{ fontSize: 10, fill: '#52525b' }}
                tickFormatter={v => `Γé╣${v.toLocaleString()}`} interval={10} />
              <YAxis tick={{ fontSize: 10, fill: '#52525b' }}
                tickFormatter={v => `Γé╣${v.toLocaleString()}`} />
              <Tooltip contentStyle={{ background: '#0a0a0f', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 12, fontSize: 12 }}
                formatter={(v) => [`Γé╣${v.toLocaleString()}`, 'P&L']}
                labelFormatter={(v) => `Spot: Γé╣${v.toLocaleString()}`} />
              <ReferenceLine y={0} stroke="rgba(255,255,255,0.1)" strokeWidth={1} />
              <ReferenceLine x={analysis.spot_price} stroke="#f59e0b" strokeDasharray="5 5" label={{ value: 'Current', fill: '#f59e0b', fontSize: 10 }} />
              {analysis.breakevens.map((be, i) => (
                <ReferenceLine key={i} x={be} stroke="#8b5cf6" strokeDasharray="3 3" />
              ))}
              <Area type="monotone" dataKey="pnl" stroke="#0ea5e9" strokeWidth={2.5} fill="url(#profitGrad)" />
            </AreaChart>
          </ResponsiveContainer>
          <div className="flex items-center justify-center gap-6 mt-3 text-[10px] font-bold text-zinc-600">
            <span className="flex items-center gap-1"><div className="w-3 h-[2px] bg-[#f59e0b]" /> Current Price</span>
            <span className="flex items-center gap-1"><div className="w-3 h-[2px] bg-[#8b5cf6] border-dashed" /> Breakeven</span>
            <span className="flex items-center gap-1"><div className="w-3 h-3 rounded bg-emerald-500/20" /> Profit Zone</span>
            <span className="flex items-center gap-1"><div className="w-3 h-3 rounded bg-rose-500/20" /> Loss Zone</span>
          </div>
        </motion.div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { RefreshCw, ClipboardList, Filter, XCircle, CheckCircle2, Clock, ArrowUpRight, ArrowDownRight, Hash, FileText, ChevronDown, Search, Zap, User as UserIcon } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useToast } from '../components/Toast';
import { useUser } from '../context/UserContext';
import axios from 'axios';
import { API_BASE_URL } from '../config';

export default function OrderBook() {
  const toast = useToast();
  const { user, isLiveMode } = useUser();
  const [orders, setOrders] = useState([]);
  const [gttOrders, setGttOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState('ALL');
  const [activeTab, setActiveTab] = useState('orders'); // orders | gtt
  const [searchTerm, setSearchTerm] = useState('');

  const fetchOrders = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const [ordersRes, gttRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/api/orders?status=${activeFilter}&user_id=${user.id}`),
        axios.get(`${API_BASE_URL}/api/gtt/list?user_id=${user.id}`)
      ]);
      setOrders(ordersRes.data.orders || []);
      setGttOrders(gttRes.data.gtt_orders || []);
    } catch (err) {
      console.error('Order fetch error', err);
      toast.error('Failed to fetch orders');
    } finally {
      setLoading(false);
    }
  }, [user, activeFilter]);

  useEffect(() => {
    fetchOrders();
  }, [fetchOrders, isLiveMode]);

  const handleCancel = async (orderId, isGtt = false) => {
    if (!user) return;
    try {
      const endpoint = isGtt ? '/api/gtt/cancel' : '/api/orders/cancel';
      await axios.post(`${API_BASE_URL}${endpoint}?user_id=${user.id}`, { order_id: orderId });
      toast.success(`Order ${orderId} cancelled`);
      fetchOrders();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Cancel failed');
    }
  };

  const statusColors = {
    'EXECUTED': { bg: 'bg-emerald-500/10', text: 'text-emerald-400', border: 'border-emerald-500/20' },
    'PENDING': { bg: 'bg-amber-500/10', text: 'text-amber-400', border: 'border-amber-500/20' },
    'CANCELLED': { bg: 'bg-zinc-500/10', text: 'text-zinc-400', border: 'border-zinc-500/20' },
    'REJECTED': { bg: 'bg-red-500/10', text: 'text-red-400', border: 'border-red-500/20' },
    'ACTIVE': { bg: 'bg-blue-500/10', text: 'text-blue-400', border: 'border-blue-500/20' },
    'TRIGGERED': { bg: 'bg-purple-500/10', text: 'text-purple-400', border: 'border-purple-500/20' },
  };

  const filters = ['ALL', 'EXECUTED', 'PENDING', 'CANCELLED', 'REJECTED'];

  const filteredOrders = orders.filter(o => 
    !searchTerm || o.symbol?.toLowerCase().includes(searchTerm.toLowerCase()) || o.order_id?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const filteredGtt = gttOrders.filter(o => 
    !searchTerm || o.symbol?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const orderStats = {
    total: orders.length,
    executed: orders.filter(o => o.status === 'EXECUTED').length,
    pending: orders.filter(o => o.status === 'PENDING').length,
    cancelled: orders.filter(o => o.status === 'CANCELLED').length,
  };

  if (!user && !loading) {
    return (
        <div className="flex flex-col items-center justify-center py-20 text-center">
            <UserIcon className="w-16 h-16 text-zinc-700 mb-4" />
            <h2 className="text-2xl font-bold text-white mb-2">Access Restricted</h2>
            <p className="text-zinc-500 mb-6">Log in to view your personalized trade history and orders.</p>
            <Link to="/login" className="px-6 py-3 bg-primary text-black font-bold rounded-xl no-underline">Go to Login</Link>
        </div>
    );
  }

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8 pb-10">
      
      {/* Page Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-extrabold text-white flex items-center gap-3">
            <span className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500/20 to-indigo-500/20 border border-white/[0.06] flex items-center justify-center">
              <ClipboardList className="w-5 h-5 text-blue-400" />
            </span>
            Order Book
            <button onClick={fetchOrders} className="p-1.5 hover:bg-white/5 rounded-lg transition-colors">
              <RefreshCw className={`w-4 h-4 text-zinc-600 ${loading ? 'animate-spin' : ''}`} />
            </button>
          </h1>
          <p className="text-sm text-zinc-500 mt-1 ml-[52px]">Managing active trades for {user?.full_name || user?.username} in {isLiveMode ? 'Live' : 'Demo'} mode</p>
        </div>
        
        <div className="flex items-center gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
            <input
              type="text"
              placeholder="Filter by asset..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="bg-white/[0.04] border border-white/[0.06] rounded-xl py-2 pl-9 pr-4 text-sm text-white focus:outline-none focus:border-blue-500/30 w-48 placeholder:text-zinc-600"
            />
          </div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'Total Orders', value: orderStats.total, icon: <ClipboardList className="w-4 h-4" />, color: 'text-blue-400', bgColor: 'bg-blue-500/10' },
          { label: 'Executed', value: orderStats.executed, icon: <CheckCircle2 className="w-4 h-4" />, color: 'text-emerald-400', bgColor: 'bg-emerald-500/10' },
          { label: 'Pending', value: orderStats.pending, icon: <Clock className="w-4 h-4" />, color: 'text-amber-400', bgColor: 'bg-amber-500/10' },
          { label: 'GTT Active', value: gttOrders.filter(g => g.status === 'ACTIVE').length, icon: <Zap className="w-4 h-4" />, color: 'text-purple-400', bgColor: 'bg-purple-500/10' },
        ].map((stat, i) => (
          <div key={i} className="glass-panel p-5 relative overflow-hidden group">
            <div className={`absolute top-0 right-0 w-16 h-16 ${stat.bgColor} rounded-full blur-[30px] group-hover:scale-125 transition-transform pointer-events-none`} />
            <div className={`w-8 h-8 ${stat.bgColor} rounded-lg flex items-center justify-center mb-3 ${stat.color} group-hover:shadow-[0_0_15px_rgba(59,130,246,0.15)] transition-all`}>
              {stat.icon}
            </div>
            <p className="text-zinc-600 text-[10px] font-bold uppercase tracking-widest mb-1">{stat.label}</p>
            <p className="text-2xl font-extrabold text-white font-mono-data">{stat.value}</p>
          </div>
        ))}
      </div>

      {/* Tab + Filter Bar */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex bg-white/[0.03] p-1 rounded-xl border border-white/[0.06]">
          <button onClick={() => setActiveTab('orders')} className={`px-4 py-2 text-xs font-bold rounded-lg transition-all ${activeTab === 'orders' ? 'bg-white/10 text-white shadow-lg' : 'text-zinc-600 hover:text-zinc-400'}`}>
            Orders History ({orders.length})
          </button>
          <button onClick={() => setActiveTab('gtt')} className={`px-4 py-2 text-xs font-bold rounded-lg transition-all ${activeTab === 'gtt' ? 'bg-white/10 text-white shadow-lg' : 'text-zinc-600 hover:text-zinc-400'}`}>
            Trigger Rules ({gttOrders.length})
          </button>
        </div>
        
        {activeTab === 'orders' && (
          <div className="flex items-center gap-2 flex-wrap">
            <Filter className="w-3.5 h-3.5 text-zinc-600" />
            {filters.map(f => (
              <button
                key={f}
                onClick={() => setActiveFilter(f)}
                className={`px-3 py-1.5 text-[10px] font-bold uppercase tracking-wider rounded-lg transition-all ${
                  activeFilter === f ? 'bg-white/10 text-white border border-white/10' : 'text-zinc-600 hover:text-zinc-400 border border-transparent'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Orders Table */}
      {activeTab === 'orders' && (
        <div className="glass-panel overflow-hidden">
          {loading ? (
            <div className="p-8 space-y-3">
              {[1,2,3,4].map(i => <div key={i} className="skeleton h-16 rounded-xl" />)}
            </div>
          ) : filteredOrders.length === 0 ? (
            <div className="p-12 text-center">
              <ClipboardList className="w-12 h-12 text-zinc-700 mx-auto mb-4" />
              <h3 className="text-lg font-bold text-zinc-400">Order trail empty for this user</h3>
              <p className="text-sm text-zinc-600 mt-1">Acquire stock to generate detailed trade logs.</p>
              <Link to="/" className="inline-block mt-4 px-5 py-2.5 bg-primary/10 border border-primary/20 text-primary text-sm font-bold rounded-xl hover:bg-primary/20 transition-all no-underline">
                Explore Markets
              </Link>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-white/[0.06] text-zinc-500 text-[10px] uppercase tracking-widest">
                    <th className="py-5 px-6 font-bold">Order Details</th>
                    <th className="py-5 px-6 font-bold">Trading Symbol</th>
                    <th className="py-5 px-6 font-bold">Transaction</th>
                    <th className="py-5 px-6 font-bold text-right">Fill Qty</th>
                    <th className="py-5 px-6 font-bold text-right">Execution Price</th>
                    <th className="py-5 px-6 font-bold text-center">Status</th>
                    <th className="py-5 px-6 font-bold text-right">Timestamp</th>
                    <th className="py-5 px-6 font-bold text-right">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredOrders.map((order, i) => {
                    const isBuy = order.transaction_type === 'BUY';
                    const sc = statusColors[order.status] || statusColors['PENDING'];
                    return (
                      <motion.tr
                        key={order.order_id}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: i * 0.03 }}
                        className="border-b border-white/[0.04] hover:bg-white/[0.02] transition-colors group"
                      >
                        <td className="py-4 px-6">
                          <p className="text-[11px] font-mono-data text-zinc-400 font-bold tracking-tight">#{order.order_id}</p>
                          <p className="text-[9px] text-zinc-700 font-mono-data uppercase">{order.product_type} ΓÇó CNC</p>
                        </td>
                        <td className="py-4 px-6">
                          <Link to={`/stock/${order.symbol}`} className="text-sm font-bold text-white group-hover:text-primary transition-colors no-underline">{order.symbol}</Link>
                          <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-tighter">NSE ΓÇó Equity</p>
                        </td>
                        <td className="py-4 px-6">
                          <span className={`flex items-center gap-1 text-[11px] font-black tracking-wider ${isBuy ? 'text-emerald-400' : 'text-red-400'}`}>
                            {isBuy ? <ArrowUpRight className="w-3.5 h-3.5" /> : <ArrowDownRight className="w-3.5 h-3.5" />}
                            {order.transaction_type}
                          </span>
                          <p className="text-[9px] text-zinc-600 uppercase tracking-widest font-black">{order.order_type}</p>
                        </td>
                        <td className="py-4 px-6 text-right font-bold text-zinc-300 font-mono-data text-sm">
                          {order.filled_qty}<span className="text-zinc-600 mx-1">/</span>{order.quantity}
                        </td>
                        <td className="py-4 px-6 text-right font-bold text-white font-mono-data text-sm">
                          Γé╣{order.avg_fill_price?.toLocaleString('en-IN', { maximumFractionDigits: 2 }) || order.price?.toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                        </td>
                        <td className="py-4 px-6 text-center">
                          <span className={`px-2.5 py-1 rounded-md text-[10px] font-black uppercase tracking-widest border ${sc.bg} ${sc.text} ${sc.border}`}>
                            {order.status}
                          </span>
                        </td>
                        <td className="py-4 px-6 text-right">
                          <p className="text-[10px] text-zinc-500 font-mono-data">{order.placed_at?.replace('T', ' ')?.slice(0,19)}</p>
                          <p className="text-[8px] text-zinc-700 tracking-widest">GATEWAY ACTIVE</p>
                        </td>
                        <td className="py-4 px-6 text-right">
                          {order.status === 'PENDING' && (
                            <button
                              onClick={() => handleCancel(order.order_id)}
                              className="px-4 py-1.5 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-black rounded-lg hover:bg-rose-500 hover:text-black transition-all uppercase tracking-wider"
                            >
                              Abort
                            </button>
                          )}
                        </td>
                      </motion.tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {/* GTT Table */}
      {activeTab === 'gtt' && (
        <div className="glass-panel overflow-hidden">
          {filteredGtt.length === 0 ? (
            <div className="p-12 text-center">
              <Zap className="w-12 h-12 text-zinc-700 mx-auto mb-4" />
              <h3 className="text-lg font-bold text-zinc-400">Trigger set empty</h3>
              <p className="text-sm text-zinc-600 mt-1">Configure GTT triggers in stock control to automate trade execution.</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-white/[0.06] text-zinc-500 text-[10px] uppercase tracking-widest">
                    <th className="py-5 px-6 font-bold">Rule ID</th>
                    <th className="py-5 px-6 font-bold">Asset</th>
                    <th className="py-5 px-6 font-bold">Rule Type</th>
                    <th className="py-5 px-6 font-bold text-right">Trigger Threshold</th>
                    <th className="py-5 px-6 font-bold text-right">Rule Qty</th>
                    <th className="py-5 px-6 font-bold text-center">Status</th>
                    <th className="py-5 px-6 font-bold text-right">Valid Thru</th>
                    <th className="py-5 px-6 font-bold text-right">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredGtt.map((gtt, i) => {
                    const sc = statusColors[gtt.status] || statusColors['ACTIVE'];
                    return (
                      <tr key={gtt.order_id} className="border-b border-white/[0.04] hover:bg-white/[0.02] transition-colors group">
                        <td className="py-4 px-6 text-[11px] font-mono-data text-zinc-400 font-bold">#{gtt.order_id}</td>
                        <td className="py-4 px-6 text-sm font-bold text-white group-hover:text-primary transition-colors">{gtt.symbol}</td>
                        <td className="py-4 px-6">
                          <span className={`text-[10px] font-black tracking-widest ${gtt.transaction_type === 'BUY' ? 'text-emerald-400' : 'text-red-400'}`}>
                            {gtt.transaction_type}
                          </span>
                          <p className="text-[9px] text-zinc-600 font-black uppercase tracking-widest">{gtt.trigger_type}</p>
                        </td>
                        <td className="py-4 px-6 text-right font-bold text-amber-400 font-mono-data text-sm">Γé╣{gtt.trigger_price?.toLocaleString()}</td>
                        <td className="py-4 px-6 text-right font-bold text-zinc-300 font-mono-data">{gtt.quantity}</td>
                        <td className="py-4 px-6 text-center">
                          <span className={`px-2.5 py-1 rounded-md text-[10px] font-black uppercase tracking-widest border ${sc.bg} ${sc.text} ${sc.border}`}>
                            {gtt.status}
                          </span>
                        </td>
                        <td className="py-4 px-6 text-right text-[10px] text-zinc-500 font-mono-data">{gtt.expiry_date}</td>
                        <td className="py-4 px-6 text-right">
                          {gtt.status === 'ACTIVE' && (
                            <button
                              onClick={() => handleCancel(gtt.order_id, true)}
                              className="px-4 py-1.5 bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-black rounded-lg hover:bg-red-500 hover:text-white transition-all uppercase tracking-wider"
                            >
                              Discard
                            </button>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}
    </motion.div>
  );
}

import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import { RefreshCw, Briefcase, PlusCircle, AlertCircle, TrendingUp, TrendingDown, ArrowUpRight, ShieldCheck, Lock, FileText, Clock, Activity, Zap, PieChart, AlertTriangle, Info, ShieldAlert } from 'lucide-react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useToast } from '../components/Toast';
import CDSLModal from '../components/CDSLModal';
import { useUser } from '../context/UserContext';
import { API_BASE_URL } from '../config';

export default function Portfolio() {
  const toast = useToast();
  const { user, isLiveMode } = useUser();
  const [holdings, setHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cdslOpen, setCdslOpen] = useState(false);
  const [selectedHolding, setSelectedHolding] = useState(null);
  const [sellQty, setSellQty] = useState(0);
  const [mode, setMode] = useState('Demo');
  const [analysis, setAnalysis] = useState({ score: 0, insights: [], diversification: [] });

  const [summary, setSummary] = useState({ total_invested: 0, total_current: 0, total_pnl: 0, total_pnl_pct: 0 });

  const fetchLivePortfolio = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const [res, analysisRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/api/portfolio?user_id=${user.id}`),
        axios.get(`${API_BASE_URL}/api/portfolio/analysis?user_id=${user.id}`)
      ]);
      setHoldings(res.data.holdings || []);
      setSummary({
        total_invested: res.data.summary?.invested || 0,
        total_current: res.data.summary?.current || 0,
        total_pnl: res.data.summary?.pnl || 0,
        total_pnl_pct: res.data.summary?.invested > 0 ? (res.data.summary.pnl / res.data.summary.invested) * 100 : 0
      });
      setMode(res.data.mode || 'Demo');
      setAnalysis(analysisRes.data || { score: 0, insights: [], diversification: [] });
    } catch (err) {
      console.error('Failed to load portfolio data from backend', err);
      toast.error('Failed to load portfolio data');
      setHoldings([]);
    } finally {
      setLoading(false);
    }
  }, [user, toast]);

  useEffect(() => {
    fetchLivePortfolio();
  }, [fetchLivePortfolio, isLiveMode]);

  const initiateSell = (holding) => {
    setSelectedHolding(holding);
    setSellQty(holding.qty);
    setCdslOpen(true);
  };

  const handleSellExecuted = async (holdingToSell = null, qtyToSell = null) => {
    const targetHolding = holdingToSell || selectedHolding;
    if (!targetHolding || !user) return;
    const targetQty = qtyToSell || sellQty || targetHolding.qty;
    try {
      const idempotencyKey = self.crypto?.randomUUID ? self.crypto.randomUUID() : Math.random().toString(36).substring(2) + Date.now().toString(36);
      await axios.post(`${API_BASE_URL}/api/broker/order?user_id=${user.id}`, {
        ticker: targetHolding.symbol,
        quantity: targetQty,
        price: targetHolding.current_price,
        transaction_type: 'SELL',
        order_type: 'MARKET',
        product_type: 'CNC'
      }, {
        headers: { 'X-Idempotency-Key': idempotencyKey }
      });
      toast.success(`[${mode}] Sold ${targetQty} shares of ${targetHolding.symbol}`);
      fetchLivePortfolio();
    } catch (e) {
      toast.error(e.response?.data?.detail || 'Sell failed');
    }
  };

  const totalInvested = summary.total_invested;
  const totalCurrent = summary.total_current;
  const totalReturns = summary.total_pnl;
  const returnPercent = (summary.total_pnl_pct || 0).toFixed(2);
  const isProfit = totalReturns >= 0;

  const handleLiquidateAll = async () => {
    if (!user) return;
    setLoading(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/portfolio/liquidate?user_id=${user.id}`);
      toast.success(`[${mode}] Liquidated ${res.data.executed} positions.`);
      fetchLivePortfolio();
    } catch (e) {
      toast.error(e.response?.data?.detail || 'Liquidation failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8">
      
      {/* Page Header */}
      <div className="flex flex-col gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
             <h1 className="text-2xl font-extrabold text-white flex items-center gap-3">
              <span className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary/20 to-secondary/20 border border-white/[0.06] flex items-center justify-center">
                <Briefcase className="w-5 h-5 text-primary" />
              </span>
              My Portfolio
            </h1>
            <div className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest border ${mode === 'Live' ? 'bg-rose-500/10 border-rose-500/20 text-rose-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'}`}>
              {mode} Account
            </div>
            {loading && <RefreshCw className="w-4 h-4 animate-spin text-zinc-600 ml-2" />}
          </div>
          <p className="text-xs sm:text-sm text-zinc-500 ml-0 sm:ml-[52px]">Managing {holdings.length} holdings in {mode.toLowerCase()} environment</p>
        </div>
        <div className="flex flex-wrap gap-2 sm:gap-3">
          <Link to="/cdsl" className="flex items-center gap-2 text-xs font-black text-blue-400 bg-blue-500/5 hover:bg-blue-500/10 transition-all px-4 py-2.5 rounded-xl border border-blue-500/20 uppercase tracking-widest no-underline">
            <ShieldCheck className="w-4 h-4" /> CDSL E-DIS
          </Link>
          <Link to="/orders" className="flex items-center gap-2 text-xs font-black text-amber-400 bg-amber-400/5 hover:bg-amber-400/10 transition-all px-4 py-2.5 rounded-xl border border-amber-400/20 uppercase tracking-widest no-underline">
            <FileText className="w-4 h-4" /> Order Book
          </Link>
          <Link to="/" className="flex items-center gap-2 text-sm font-bold text-primary bg-primary/10 hover:bg-primary/15 transition-all px-5 py-2.5 rounded-xl border border-primary/20 no-underline">
            <PlusCircle className="w-4 h-4" /> INVEST MORE
          </Link>
          <button 
            onClick={() => {
              if (window.confirm("CRITICAL: This will sell ALL AUTHORIZED holdings at market price. Continue?")) {
                handleLiquidateAll();
              }
            }}
            disabled={loading || holdings.filter(h => h.is_authorized).length === 0}
            className="flex items-center gap-2 text-xs font-black text-rose-400 bg-rose-500/5 hover:bg-rose-500/10 transition-all px-4 py-2.5 rounded-xl border border-rose-500/20 uppercase tracking-widest disabled:opacity-30"
          >
            <ShieldAlert className="w-4 h-4" /> Liquidate All
          </button>
        </div>
      </div>

      {loading ? (
        <div className="glass-panel p-8">
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {[1, 2, 3].map(i => <div key={i} className="skeleton h-24 rounded-xl" />)}
            </div>
            <div className="skeleton h-64 rounded-xl" />
          </div>
        </div>
      ) : holdings.length === 0 ? (
        <div className="glass-panel p-8">
          <div className="flex flex-col items-center justify-center py-20 text-center">
            <div className="w-20 h-20 bg-white/[0.03] border border-white/[0.06] rounded-2xl flex items-center justify-center mb-6">
              <AlertCircle className="w-10 h-10 text-zinc-600" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-2">{mode} Portfolio is Empty</h2>
            <p className="text-zinc-500 max-w-sm mb-8">
              Start trading in {mode.toLowerCase()} mode to build your assets and track performance.
            </p>
            <Link to="/" className="px-6 py-3 bg-gradient-to-r from-primary to-emerald-400 text-black font-bold rounded-xl hover:shadow-primary/20 hover:shadow-lg transition-all no-underline">
              Explore Markets
            </Link>
          </div>
        </div>
      ) : (
        <>
          {/* Summary Cards */}
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4">
            <div className="glass-panel p-6 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-24 h-24 bg-primary/5 rounded-full blur-[40px] group-hover:bg-primary/10 transition-all" />
              <p className="text-zinc-500 font-bold text-[10px] uppercase tracking-widest mb-2">Portfolio Value</p>
              <p className="text-3xl font-extrabold text-white font-mono-data">Γé╣{totalCurrent.toLocaleString('en-IN', { maximumFractionDigits: 2 })}</p>
            </div>

            <div className="glass-panel p-6 relative overflow-hidden group">
              <div className={`absolute top-0 right-0 w-24 h-24 ${isProfit ? 'bg-emerald-500/5' : 'bg-red-500/5'} rounded-full blur-[40px] group-hover:blur-[20px] transition-all`} />
              <p className="text-zinc-500 font-bold text-[10px] uppercase tracking-widest mb-2">Total P&L</p>
              <div className="flex items-end gap-2">
                <p className={`text-3xl font-extrabold font-mono-data ${isProfit ? 'text-emerald-400' : 'text-danger'}`}>
                  {isProfit ? '+' : ''}Γé╣{(totalReturns || 0).toLocaleString('en-IN', { maximumFractionDigits: 2 })}
                </p>
                <span className={`text-sm font-bold mb-1 flex items-center gap-1 ${isProfit ? 'text-emerald-400/60' : 'text-red-400/60'}`}>
                  {isProfit ? <ArrowUpRight className="w-3.5 h-3.5" /> : <TrendingDown className="w-3.5 h-3.5" />}
                  {returnPercent}%
                </span>
              </div>
            </div>

            <div className="glass-panel p-6 relative overflow-hidden group">
              <p className="text-zinc-500 font-bold text-[10px] uppercase tracking-widest mb-2">Total Invested</p>
              <p className="text-3xl font-bold text-zinc-400 font-mono-data">Γé╣{totalInvested.toLocaleString('en-IN', { maximumFractionDigits: 2 })}</p>
            </div>

            <div className="glass-panel p-6 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-20 h-20 bg-blue-500/5 rounded-full blur-[30px]" />
              <p className="text-zinc-500 font-bold text-[10px] uppercase tracking-widest mb-2">CDSL Auth Status</p>
              <div className="flex items-end gap-2">
                <p className="text-2xl font-extrabold text-blue-400 font-mono-data">
                  {holdings.filter(h => h.is_authorized).length}/{holdings.length}
                </p>
                <span className="text-xs text-zinc-600 mb-1 font-bold">Authorized</span>
              </div>
            </div>
          </div>

          {/* Holdings Table */}
          <div className="glass-panel overflow-hidden border-white/[0.04]">
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b border-white/[0.06] text-zinc-500 text-[10px] uppercase tracking-widest">
                    <th className="py-5 px-6 font-bold">Asset</th>
                    <th className="py-5 px-6 font-bold">ISIN</th>
                    <th className="py-5 px-6 font-bold text-right">Qty</th>
                    <th className="py-5 px-6 font-bold text-right">Avg Price</th>
                    <th className="py-5 px-6 font-bold text-right">LTP</th>
                    <th className="py-5 px-6 font-bold text-right">P&L</th>
                    <th className="py-5 px-6 font-bold text-center">CDSL Status</th>
                    <th className="py-5 px-6 font-bold text-right">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {holdings.map((h, i) => {
                    const rt = h.current - h.invested;
                    const isProfitRow = rt >= 0;
                    return (
                      <tr key={i} className="border-b border-white/[0.04] hover:bg-white/[0.02] transition-colors group">
                        <td className="py-5 px-6">
                          <Link to={`/stock/${h.symbol}`} className="block no-underline">
                            <div className="flex items-center gap-3">
                               <div className="w-8 h-8 rounded-lg bg-white/[0.03] border border-white/[0.06] group-hover:border-primary/30 transition-colors">
                                  <span className="text-[10px] font-black text-zinc-400">{h.symbol.slice(0, 2)}</span>
                               </div>
                               <div>
                                  <p className="font-bold text-white group-hover:text-primary transition-colors mb-0">{h.symbol}</p>
                                  <p className="text-[10px] text-zinc-600 font-bold uppercase tracking-tighter">{h.exchange} ΓÇó {h.segment}</p>
                               </div>
                            </div>
                          </Link>
                        </td>
                        <td className="py-5 px-6 text-[10px] font-mono-data text-zinc-500 tracking-tighter">{h.isin}</td>
                        <td className="py-5 px-6 text-right font-bold text-zinc-300 font-mono-data">{h.qty || 0}</td>
                        <td className="py-5 px-6 text-right font-medium text-zinc-500 font-mono-data">Γé╣{(h.avg_price || 0).toFixed(2)}</td>
                        <td className="py-5 px-6 text-right font-bold text-white font-mono-data">Γé╣{(h.current_price || 0).toLocaleString('en-IN')}</td>
                        <td className={`py-5 px-6 text-right font-extrabold font-mono-data ${isProfitRow ? 'text-emerald-400' : 'text-danger'}`}>
                          <div className="flex flex-col items-end">
                            <span>{rt > 0 ? '+' : ''}Γé╣{(rt || 0).toLocaleString('en-IN', { maximumFractionDigits: 2 })}</span>
                            <span className="text-[10px] font-medium opacity-60 mt-0.5">{(h.pnl_pct || 0).toFixed(2)}%</span>
                          </div>
                        </td>
                        <td className="py-5 px-6 text-center">
                           {h.is_authorized ? (
                             <div className="flex flex-col items-center">
                               <span className="flex items-center gap-1 text-[10px] text-emerald-400 font-bold uppercase tracking-wider mb-0.5">
                                 <ShieldCheck className="w-3 h-3" /> Authorized
                               </span>
                               <span className="text-[9px] text-zinc-600 font-mono-data flex items-center gap-1">
                                 <Clock className="w-2.5 h-2.5" />
                                 {h.dis_slip_no ? `DIS: ${h.dis_slip_no.slice(-10)}` : 'Active'}
                               </span>
                             </div>
                           ) : (
                             <span className="flex items-center justify-center gap-1 text-[10px] text-amber-400 font-bold uppercase tracking-wider">
                               <Lock className="w-3 h-3" /> Pending E-DIS
                             </span>
                           )}
                        </td>
                        <td className="py-5 px-6 text-right">
                          <div className="flex justify-end">
                            {h.is_authorized ? (
                              <button 
                                onClick={() => {
                                  setSelectedHolding(h);
                                  setSellQty(h.qty);
                                  handleSellExecuted(h, h.qty);
                                }}
                                className="px-4 py-2 bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-emerald-500 hover:text-black transition-all shadow-lg shadow-emerald-500/10"
                              >
                                Execute Sell
                              </button>
                            ) : (
                              <button 
                                onClick={() => initiateSell(h)}
                                className="px-4 py-2 bg-amber-500/10 border border-amber-500/20 text-amber-500 text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-amber-500 hover:text-white transition-all flex items-center gap-1.5 shadow-lg shadow-amber-500/10"
                              >
                                <Lock className="w-3 h-3" /> Authorize
                              </button>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {/* ΓöÇΓöÇΓöÇ PORTFOLIO SANITIZER (AI Insights) ΓöÇΓöÇΓöÇ */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6 mt-6 sm:mt-10">
            <div className="lg:col-span-2 glass-panel p-5 sm:p-8 lg:p-10 relative overflow-hidden border-white/[0.08] shadow-[0_30px_60px_rgba(0,0,0,0.4)]">
              <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-primary/5 rounded-full blur-[120px] pointer-events-none" />
              
              <div className="flex items-center justify-between mb-10">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center shadow-lg shadow-primary/10">
                     <ShieldCheck className="w-6 h-6 text-primary" />
                  </div>
                  <div>
                    <h2 className="text-2xl font-black text-white leading-tight">Nexus AI Sanitizer</h2>
                    <p className="text-[10px] text-zinc-600 font-bold uppercase tracking-[0.2em] mt-1">Portfolio Wellness & Risk Matrix</p>
                  </div>
                </div>
                <div className="text-right">
                   <span className={`text-5xl font-black font-mono-data ${analysis.score > 80 ? 'text-emerald-400' : analysis.score > 50 ? 'text-amber-400' : 'text-red-400'}`}>
                     {analysis.score}
                   </span>
                   <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mt-1">Health Score</p>
                </div>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 sm:gap-10">
                 {/* Sector Allocation Heatmap */}
                 <div className="space-y-6">
                    <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                       <PieChart className="w-4 h-4 text-primary" /> Diversification Heatmap
                    </h3>
                    <div className="space-y-4">
                       {analysis.diversification.length > 0 ? analysis.diversification.map((d, i) => (
                          <div key={i} className="space-y-2">
                             <div className="flex justify-between text-[11px] font-bold uppercase tracking-wider text-zinc-400">
                                <span>{d.name}</span>
                                <span className="text-white">{d.value}%</span>
                             </div>
                             <div className="h-2 w-full bg-white/[0.03] rounded-full overflow-hidden border border-white/[0.04]">
                               <motion.div 
                                 initial={{ width: 0 }}
                                 animate={{ width: `${d.value}%` }}
                                 className={`h-full rounded-full ${i % 3 === 0 ? 'bg-primary shadow-[0_0_15px_rgba(0,212,170,0.4)]' : i % 3 === 1 ? 'bg-secondary' : 'bg-blue-500'}`}
                               />
                             </div>
                          </div>
                       )) : <p className="text-zinc-700 text-xs italic">Awaiting data...</p>}
                    </div>
                 </div>

                 {/* Alpha Insights */}
                 <div className="space-y-6">
                    <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                       <Activity className="w-4 h-4 text-secondary" /> Nexus Alpha Insights
                    </h3>
                    <div className="space-y-4">
                       {analysis.insights.length > 0 ? analysis.insights.map((insight, i) => (
                          <motion.div 
                             key={i} 
                             initial={{ opacity: 0, x: 20 }}
                             animate={{ opacity: 1, x: 0 }}
                             transition={{ delay: i * 0.1 }}
                             className={`p-5 rounded-2xl border flex gap-4 ${
                               insight.type === 'WARNING' ? 'bg-red-500/5 border-red-500/20 text-red-100 shadow-[0_10px_30px_rgba(239,68,68,0.05)]' : 
                               insight.type === 'SUCCESS' ? 'bg-emerald-500/5 border-emerald-500/20 text-emerald-100 shadow-[0_10px_30px_rgba(16,185,129,0.05)]' :
                               'bg-blue-500/5 border-blue-500/20 text-blue-100 shadow-[0_10px_30px_rgba(59,130,246,0.05)]'
                             }`}
                          >
                             {insight.type === 'WARNING' ? <AlertTriangle className="w-6 h-6 text-red-400 shrink-0" /> : 
                              insight.type === 'SUCCESS' ? <ShieldCheck className="w-6 h-6 text-emerald-400 shrink-0" /> :
                              <Info className="w-6 h-6 text-blue-400 shrink-0" />}
                             <p className="text-xs font-medium leading-relaxed mt-0.5">{insight.text}</p>
                          </motion.div>
                       )) : (
                          <div className="p-10 bg-white/[0.01] border border-dashed border-white/[0.08] rounded-[24px] text-center text-zinc-700 text-xs font-bold uppercase tracking-widest">
                            No active threats detected.
                          </div>
                       )}
                    </div>
                 </div>
              </div>
            </div>

            {/* Side Pulse Sidebar */}
            <div className="space-y-6">
               <div className="glass-panel p-8 border-white/[0.08] bg-gradient-to-br from-white/[0.01] to-white/[0.04] shadow-xl">
                  <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-6 flex items-center gap-2">
                     <Zap className="w-4 h-4 text-amber-400" /> Deep Analytics
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                     {[
                       { label: 'System Beta', val: '1.24', sub: 'Aggressive' },
                       { label: 'Ex-Alpha', val: '+4.2%', sub: 'Vs Sector' },
                       { label: 'Drawdown', val: '4.8%', sub: 'Max MTD' },
                       { label: 'Risk Adjusted', val: '7.8', sub: 'Sharpe Ratio' }
                     ].map((stat, i) => (
                        <div key={i} className="p-4 bg-white/[0.02] border border-white/[0.06] rounded-2xl text-center hover:bg-white/[0.05] transition-all cursor-crosshair">
                           <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1.5">{stat.label}</p>
                           <p className="text-base font-black text-white font-mono-data mb-0.5">{stat.val}</p>
                           <p className="text-[8px] font-black text-primary uppercase tracking-tighter">{stat.sub}</p>
                        </div>
                     ))}
                  </div>
               </div>

               <div className="glass-panel p-8 border-primary/20 bg-primary/5 relative overflow-hidden group">
                  <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-primary/10 rounded-full blur-[40px] group-hover:bg-primary/20 transition-all" />
                  <h3 className="text-xs font-black text-primary uppercase tracking-[0.2em] mb-3">Nexus AI Hedge Advice</h3>
                  <p className="text-xs text-zinc-400 leading-relaxed mb-6 font-medium">
                     Your energy exposure is <span className="text-white font-bold">18% above target</span>. Nexus suggests hedging with 500 units of <span className="text-white font-bold">NIFTY JUN PUT</span> or liquidating 5% of Reliance.
                  </p>
                  <button className="w-full py-3.5 bg-primary text-black font-black text-[10px] uppercase tracking-widest rounded-2xl hover:bg-emerald-400 transition-all hover:scale-[1.02] shadow-lg shadow-primary/10">Execute AI Hedge</button>
               </div>
            </div>
          </div>
        </>
      )}

      {selectedHolding && (
        <CDSLModal 
          isOpen={cdslOpen} 
          onClose={() => setCdslOpen(false)} 
          onAuthorized={() => {
            handleSellExecuted();
            setCdslOpen(false);
          }}
          stockSymbol={selectedHolding.symbol}
          quantity={sellQty || selectedHolding.qty}
        />
      )}
    </motion.div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Shield, AlertTriangle, TrendingDown, TrendingUp, Activity, Zap, BarChart2, Target, RefreshCw, ChevronRight, ArrowDownRight, ArrowUpRight, Loader2, Info, PieChart } from 'lucide-react';
import { PieChart as RechartsPie, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, RadarChart, Radar, PolarGrid, PolarAngleAxis, AreaChart, Area } from 'recharts';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { API_BASE_URL } from '../config';

class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false }; }
  static getDerivedStateFromError(error) { return { hasError: true }; }
  render() {
    if (this.state.hasError) {
      return <div className="p-8 text-center glass-panel border-rose-500/20"><AlertTriangle className="w-8 h-8 text-rose-400 mx-auto mb-4" /><h3 className="text-white font-bold mb-2">X-Ray Rendering Failed</h3><p className="text-zinc-500 text-sm">Failed to map AI insights to the dashboard. Please try refreshing.</p></div>;
    }
    return this.props.children;
  }
}

const SEVERITY_COLORS = {
  EXTREME: '#ef4444', HIGH: '#f97316', MODERATE: '#f59e0b', LOW: '#0ea5e9', POSITIVE: '#10b981',
};

export default function PortfolioXray() {
  const { user } = useUser();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');

  useEffect(() => { fetchXray(); }, []);

  const fetchXray = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/portfolio/xray?user_id=${user?.id || 1}`);
      setData(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  if (loading) return <div className="py-20 text-center"><Loader2 className="w-8 h-8 text-primary mx-auto animate-spin" /></div>;
  if (!data) return null;

  const tabs = [
    { id: 'overview', label: 'Overview', icon: <PieChart size={14} /> },
    { id: 'stress', label: 'Stress Tests', icon: <AlertTriangle size={14} /> },
    { id: 'correlation', label: 'Correlation', icon: <Activity size={14} /> },
    { id: 'rebalance', label: 'Rebalance', icon: <Target size={14} /> },
  ];

  const xrayData = data?.xray || data || {};
  const healthScore = xrayData?.health_score || 0;
  const healthColor = healthScore > 75 ? '#10b981' : healthScore > 50 ? '#f59e0b' : '#ef4444';
  const riskMetrics = xrayData?.risk_metrics || {};
  const sectorExposure = xrayData?.sector_exposure || [];
  const riskDecomp = xrayData?.risk_decomposition || [];
  const holdingsDetail = xrayData?.holdings_detail || [];
  const stressTests = xrayData?.stress_tests || [];
  const corrMatrix = xrayData?.correlation_matrix || [];
  const rebalanceSugg = xrayData?.rebalance_suggestions || [];
  const concRisk = xrayData?.concentration_risk || { score: 0, top_holding_pct: 0, hhi_index: 0 };

  return (
    <ErrorBoundary>
    <div className="space-y-8">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-black text-white flex items-center gap-3">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-violet-500/20 to-cyan-500/20 border border-violet-500/20 flex items-center justify-center">
              <Shield className="w-6 h-6 text-violet-400" />
            </div>
            Portfolio X-Ray
          </h1>
          <p className="text-zinc-500 mt-2 text-sm">Bloomberg Terminal-grade portfolio analysis ΓÇó No other Indian app has this</p>
        </div>
        <button onClick={fetchXray} className="flex items-center gap-2 px-4 py-2 bg-white/[0.04] border border-white/[0.08] rounded-xl text-xs font-bold text-zinc-400 hover:text-white transition-all">
          <RefreshCw size={14} /> Refresh
        </button>
      </div>

      {/* Health Score Hero */}
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
        className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-[#060b18] via-surface to-surface border border-white/[0.08] p-8">
        <div className="absolute top-0 right-0 w-[400px] h-[400px] rounded-full blur-[150px] pointer-events-none" style={{ background: `${healthColor}10` }} />
        
        <div className="relative z-10 flex items-center gap-10">
          {/* Health Ring */}
          <div className="relative shrink-0">
            <svg className="w-40 h-40 -rotate-90" viewBox="0 0 120 120">
              <circle cx="60" cy="60" r="54" fill="none" stroke="rgba(255,255,255,0.04)" strokeWidth="8" />
              <circle cx="60" cy="60" r="54" fill="none" stroke={healthColor} strokeWidth="8" strokeLinecap="round"
                strokeDasharray={`${healthScore * 3.39} 339`} />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center">
              <span className="text-4xl font-black text-white">{healthScore}</span>
              <span className="text-[9px] font-black uppercase tracking-[0.2em]" style={{ color: healthColor }}>Health Score</span>
            </div>
          </div>

          <div className="flex-1 grid grid-cols-5 gap-4">
            {[
              { label: 'Portfolio Value', value: `Γé╣${(xrayData?.total_value || 0).toLocaleString()}`, color: 'text-white', icon: <BarChart2 size={14} /> },
              { label: 'Volatility', value: `${riskMetrics?.volatility || 0}%`, color: (riskMetrics?.volatility || 0) > 30 ? 'text-red-400' : 'text-emerald-400', icon: <Activity size={14} /> },
              { label: 'Beta', value: riskMetrics?.beta || 1.0, color: (riskMetrics?.beta || 1) > 1.2 ? 'text-amber-400' : 'text-emerald-400', icon: <TrendingUp size={14} /> },
              { label: 'Sharpe', value: riskMetrics?.sharpe || 0, color: (riskMetrics?.sharpe || 0) > 1 ? 'text-emerald-400' : 'text-amber-400', icon: <Zap size={14} /> },
              { label: 'VaR (95%)', value: `Γé╣${(riskMetrics?.var_95 || 0).toLocaleString()}`, color: 'text-rose-400', icon: <AlertTriangle size={14} /> },
            ].map((m, i) => (
              <div key={i} className="bg-white/[0.03] rounded-2xl p-4 border border-white/[0.04]">
                <div className="flex items-center gap-2 text-zinc-600 mb-2">{m.icon}<span className="text-[9px] font-black uppercase tracking-widest">{m.label}</span></div>
                <p className={`text-xl font-black font-mono-data ${m.color}`}>{m.value}</p>
              </div>
            ))}
          </div>
        </div>
      </motion.div>

      {/* Tabs */}
      <div className="flex gap-1 border-b border-white/[0.04] pb-px">
        {tabs.map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-2 px-5 py-3 text-xs font-bold uppercase tracking-widest rounded-t-xl transition-all relative
              ${activeTab === tab.id ? 'text-primary' : 'text-zinc-600 hover:text-zinc-300 hover:bg-white/[0.02]'}`}>
            {tab.icon} {tab.label}
            {activeTab === tab.id && <motion.div layoutId="xrayTab" className="absolute bottom-0 left-2 right-2 h-[2px] bg-primary rounded-full" />}
          </button>
        ))}
      </div>

      {/* Overview Tab */}
      {activeTab === 'overview' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Sector Exposure Pie */}
          <div className="glass-panel p-6">
            <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <PieChart size={14} className="text-violet-400" /> Sector Exposure
            </h3>
            <ResponsiveContainer width="100%" height={280}>
              <RechartsPie>
                <Pie data={sectorExposure} cx="50%" cy="50%" innerRadius={70} outerRadius={110}
                  dataKey="value" paddingAngle={2} strokeWidth={0}>
                  {sectorExposure.map((s, i) => <Cell key={i} fill={s.color || '#3b82f6'} />)}
                </Pie>
                <Tooltip contentStyle={{ background: '#0a0a0f', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 12, fontSize: 12 }}
                  formatter={(v) => `${v}%`} />
              </RechartsPie>
            </ResponsiveContainer>
            
            {sectorExposure.length === 0 && <p className="text-xs text-zinc-500 text-center">No sector exposure data.</p>}

            <div className="grid grid-cols-2 gap-2 mt-2">
              {sectorExposure.map((s, i) => (
                <div key={i} className="flex items-center gap-2 text-xs">
                  <div className="w-3 h-3 rounded" style={{ background: s.color || '#3b82f6' }} />
                  <span className="text-zinc-500 flex-1">{s.name || 'Unknown'}</span>
                  <span className={`font-black ${s.risk_level === 'HIGH' ? 'text-red-400' : 'text-white'}`}>{s.value || 0}%</span>
                </div>
              ))}
            </div>
          </div>

          {/* Risk Decomposition */}
          <div className="glass-panel p-6">
            <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Activity size={14} className="text-rose-400" /> Risk Decomposition
            </h3>
            <div className="space-y-4 mt-6">
              {riskDecomp.map((r, i) => (
                <div key={i}>
                  <div className="flex justify-between items-center mb-1.5">
                    <span className="text-sm font-bold text-zinc-400">{r.factor || 'Factor'}</span>
                    <span className="text-sm font-black font-mono-data" style={{ color: r.color || '#3b82f6' }}>{r.contribution || 0}%</span>
                  </div>
                  <div className="h-2.5 bg-white/[0.04] rounded-full overflow-hidden">
                    <motion.div initial={{ width: 0 }} animate={{ width: `${Math.min(100, (r.contribution || 0) * 2)}%` }}
                      transition={{ duration: 0.8, delay: i * 0.1 }}
                      className="h-full rounded-full" style={{ background: r.color || '#3b82f6' }} />
                  </div>
                </div>
              ))}
              {riskDecomp.length === 0 && <p className="text-xs text-zinc-500">Risk decomposition unavailable.</p>}
            </div>
            
            <div className="mt-6 p-4 rounded-xl bg-violet-500/[0.05] border border-violet-500/10">
              <div className="flex items-start gap-3">
                <Info size={14} className="text-violet-400 mt-0.5 shrink-0" />
                <p className="text-xs text-zinc-500 leading-relaxed">
                  <span className="text-violet-400 font-bold">Concentration Score: {concRisk.score || 0}/100</span> ΓÇö 
                  Top holding is {concRisk.top_holding_pct || 0}% of portfolio. 
                  HHI Index: {concRisk.hhi_index || 0} {(concRisk.hhi_index || 0) > 2500 ? '(Concentrated)' : '(Diversified)'}.
                </p>
              </div>
            </div>
          </div>

          {/* Holdings Breakdown */}
          <div className="glass-panel overflow-hidden lg:col-span-2">
            <div className="p-5 border-b border-white/[0.04] flex items-center justify-between">
              <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em]">Holdings Detail</h3>
              <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">{holdingsDetail.length} Positions</span>
            </div>
            {holdingsDetail.length === 0 ? (
              <div className="p-6 text-center text-xs text-zinc-500">No holdings detail found.</div>
            ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b border-white/[0.04]">
                    {['Symbol', 'Sector', 'Weight', 'Price', 'P&L', 'Beta', 'Volatility'].map(h => (
                      <th key={h} className="text-left p-4 text-[10px] font-black text-zinc-600 uppercase tracking-widest">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {holdingsDetail.map((h, i) => (
                    <motion.tr key={h.symbol} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.03 }}
                      className="border-b border-white/[0.02] hover:bg-white/[0.01] transition-colors">
                      <td className="p-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-lg flex items-center justify-center text-xs font-black"
                            style={{ background: `hsl(${(i * 47) % 360}, 50%, 20%)`, color: `hsl(${(i * 47) % 360}, 70%, 60%)` }}>
                            {h.symbol.slice(0, 2)}
                          </div>
                          <span className="font-bold text-white">{h.symbol}</span>
                        </div>
                      </td>
                      <td className="p-4 text-xs text-zinc-500">{h.sector}</td>
                      <td className="p-4">
                        <div className="flex items-center gap-2">
                          <div className="w-16 h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                            <div className="h-full bg-primary rounded-full" style={{ width: `${h.weight}%` }} />
                          </div>
                          <span className="text-xs font-black text-white font-mono-data">{h.weight}%</span>
                        </div>
                      </td>
                      <td className="p-4 font-mono-data text-xs text-white">Γé╣{h.current_price.toLocaleString()}</td>
                      <td className={`p-4 font-mono-data text-xs font-bold ${h.pnl >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {h.pnl >= 0 ? '+' : ''}{h.pnl_pct}%
                      </td>
                      <td className={`p-4 font-mono-data text-xs font-bold ${h.beta > 1.2 ? 'text-amber-400' : 'text-emerald-400'}`}>{h.beta || 1}</td>
                      <td className={`p-4 font-mono-data text-xs font-bold ${h.volatility > 35 ? 'text-rose-400' : 'text-emerald-400'}`}>{h.volatility || 0}%</td>
                    </motion.tr>
                  ))}
                </tbody>
              </table>
            </div>
            )}
          </div>
        </div>
      )}

      {/* Stress Tests Tab */}
      {activeTab === 'stress' && (
        <div className="space-y-4">
          <div className="glass-panel p-5 bg-rose-500/[0.02] border-rose-500/10">
            <div className="flex items-start gap-3">
              <AlertTriangle size={18} className="text-rose-400 mt-0.5" />
              <div>
                <h3 className="text-sm font-black text-white mb-1">Stress Testing Engine</h3>
                <p className="text-xs text-zinc-500">Simulating historical crisis events against your current portfolio to estimate potential impact.</p>
              </div>
            </div>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {stressTests.length === 0 && <p className="text-xs text-zinc-500">No stress tests available.</p>}
            {stressTests.map((test, i) => (
              <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}
                className={`glass-panel p-6 relative overflow-hidden border ${
                  test.severity === 'POSITIVE' ? 'border-emerald-500/20' : 'border-white/[0.04]'
                }`}>
                <div className="absolute top-0 right-0 w-24 h-24 rounded-full blur-[60px] pointer-events-none"
                  style={{ background: `${SEVERITY_COLORS[test.severity] || '#fff'}10` }} />
                
                <div className="relative z-10">
                  <div className="flex items-center gap-2 mb-3">
                    <span className="text-[9px] font-black px-2 py-0.5 rounded-lg uppercase tracking-widest"
                      style={{ background: `${SEVERITY_COLORS[test.severity] || '#fff'}15`, color: SEVERITY_COLORS[test.severity] || '#fff' }}>
                      {test.severity || 'UNKNOWN'}
                    </span>
                  </div>
                  <h4 className="text-sm font-bold text-white mb-4">{test.scenario || 'Scenario'}</h4>
                  
                  <div className="flex items-end gap-3">
                    <div>
                      <p className="text-[10px] text-zinc-600 font-bold uppercase tracking-widest mb-1">Impact</p>
                      <p className={`text-2xl font-black font-mono-data ${(test.impact || 0) >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {(test.impact || 0) >= 0 ? '+' : ''}Γé╣{Math.abs(test.impact || 0).toLocaleString()}
                      </p>
                    </div>
                    <div className="mb-1">
                      <span className={`text-sm font-black font-mono-data px-2 py-1 rounded-lg ${
                        (test.impact_pct || 0) >= 0 ? 'text-emerald-400 bg-emerald-500/10' : 'text-rose-400 bg-rose-500/10'
                      }`}>
                        {(test.impact_pct || 0) >= 0 ? '+' : ''}{test.impact_pct || 0}%
                      </span>
                    </div>
                  </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      )}

      {/* Correlation Tab */}
      {activeTab === 'correlation' && (
        <div className="glass-panel p-6 overflow-x-auto">
          <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Correlation Matrix</h3>
          <p className="text-xs text-zinc-600 mb-6">Higher correlation = less diversification benefit. Aim for low or negative correlations between holdings.</p>
          
          {corrMatrix.length === 0 ? (
            <p className="text-xs text-zinc-500">Correlation data unavailable.</p>
          ) : (
          <table className="w-full">
            <thead>
              <tr>
                <th className="p-3 text-[10px] font-black text-zinc-600 uppercase tracking-widest text-left"></th>
                {corrMatrix.map(row => (
                  <th key={row.symbol} className="p-3 text-[10px] font-black text-zinc-400 uppercase tracking-widest">{row.symbol}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {corrMatrix.map((row, ri) => (
                <tr key={row.symbol}>
                  <td className="p-3 text-xs font-bold text-zinc-400">{row.symbol}</td>
                  {corrMatrix.map((col, ci) => {
                    const val = row[col.symbol];
                    const bg = val === 1 ? 'bg-white/[0.04]' :
                      val > 0.5 ? 'bg-red-500/10' : val > 0.3 ? 'bg-amber-500/10' : 'bg-emerald-500/10';
                    const color = val === 1 ? 'text-zinc-500' :
                      val > 0.5 ? 'text-red-400' : val > 0.3 ? 'text-amber-400' : 'text-emerald-400';
                    return (
                      <td key={ci} className={`p-3 text-center font-mono-data text-xs font-bold ${bg} ${color} border border-white/[0.02]`}>
                        {val?.toFixed(2) || '-'}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
          )}
        </div>
      )}

      {/* Rebalance Tab */}
      {activeTab === 'rebalance' && (
        <div className="space-y-4">
          {rebalanceSugg.length > 0 ? rebalanceSugg.map((s, i) => (
            <motion.div key={i} initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.1 }}
              className={`glass-panel p-6 border-l-4 ${
                s.urgency === 'HIGH' ? 'border-l-rose-500' : s.urgency === 'MEDIUM' ? 'border-l-amber-500' : 'border-l-blue-500'
              }`}>
              <div className="flex items-start gap-4">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 ${
                  s.type === 'REDUCE' ? 'bg-rose-500/10 text-rose-400' :
                  s.type === 'DIVERSIFY' ? 'bg-amber-500/10 text-amber-400' : 'bg-blue-500/10 text-blue-400'
                }`}>
                  {s.type === 'REDUCE' ? <TrendingDown size={18} /> : s.type === 'DIVERSIFY' ? <Target size={18} /> : <Shield size={18} />}
                </div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="text-xs font-black text-white uppercase tracking-wider">{s.type}</span>
                    <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase ${
                      s.urgency === 'HIGH' ? 'bg-rose-500/10 text-rose-400' : 'bg-amber-500/10 text-amber-400'
                    }`}>{s.urgency}</span>
                  </div>
                  <p className="text-sm text-zinc-400">{s.reason}</p>
                  {s.symbol !== 'MULTIPLE' && (
                    <p className="text-xs text-zinc-600 mt-1 font-mono-data">Symbol: {s.symbol}</p>
                  )}
                </div>
                <button className="px-4 py-2 bg-primary/10 text-primary text-xs font-black rounded-xl hover:bg-primary/20 transition-all uppercase tracking-widest">
                  Apply
                </button>
              </div>
            </motion.div>
          )) : (
            <div className="glass-panel p-12 text-center">
              <Shield className="w-12 h-12 text-emerald-400 mx-auto mb-4" />
              <h3 className="text-lg font-black text-white mb-2">Portfolio is Well-Balanced ≡ƒÄë</h3>
              <p className="text-sm text-zinc-500">No rebalancing actions needed at this time.</p>
            </div>
          )}
        </div>
      )}
    </div>
    </ErrorBoundary>
  );
}

