import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Target, TrendingUp, Users, Cpu, Search, ArrowUpRight, ArrowDownRight, Star, RefreshCw, BarChart2, AlertTriangle } from 'lucide-react';
import axios from 'axios';
import { API_BASE_URL } from '../config';

class ErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false }; }
  static getDerivedStateFromError(error) { return { hasError: true }; }
  render() {
    if (this.state.hasError) {
      return <div className="p-8 text-center glass-panel border-rose-500/20"><AlertTriangle className="w-8 h-8 text-rose-400 mx-auto mb-4" /><h3 className="text-white font-bold mb-2">Targets Rendering Failed</h3><p className="text-zinc-500 text-sm">Failed to map AI insights to the dashboard. Please try refreshing.</p></div>;
    }
    return this.props.children;
  }
}

const fadeUp = { hidden: { opacity: 0, y: 20 }, show: { opacity: 1, y: 0, transition: { duration: 0.5 } } };

export default function PriceTargets() {
  const [symbol, setSymbol] = useState('RELIANCE');
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchInput, setSearchInput] = useState('RELIANCE');

  const fetchTargets = (sym) => {
    setLoading(true);
    axios.get(`${API_BASE_URL}/api/stock/targets/${sym}`)
      .then(res => { setData(res.data); setSymbol(sym); })
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchTargets('RELIANCE'); }, []);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchInput.trim()) fetchTargets(searchInput.trim().toUpperCase());
  };

  if (loading) {
    return (
      <div className="h-96 flex items-center justify-center flex-col gap-4">
        <RefreshCw className="w-8 h-8 text-cyan-400 animate-spin" />
        <p className="text-zinc-400 font-bold animate-pulse text-sm">Aggregating analyst targets...</p>
      </div>
    );
  }
  if (!data) return null;

  return (
    <ErrorBoundary>
    <motion.div variants={fadeUp} initial="hidden" animate="show" className="space-y-8">
      {/* Header */}
      <div className="relative overflow-hidden rounded-[28px] border border-white/[0.06] bg-gradient-to-br from-[#040a14] via-surface to-surface p-8 md:p-12">
        <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-cyan-500/10 rounded-full blur-[150px] pointer-events-none" />
        <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-cyan-500/20 to-teal-500/20 border border-cyan-500/20 flex items-center justify-center">
              <Target className="w-7 h-7 text-cyan-400" />
            </div>
            <div>
              <h1 className="text-3xl md:text-4xl font-black text-white">AI Price Targets</h1>
              <p className="text-zinc-500 text-sm mt-0.5">Multi-source consensus from analysts, AI, and the crowd</p>
            </div>
          </div>
          <form onSubmit={handleSearch} className="flex gap-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input value={searchInput} onChange={e => setSearchInput(e.target.value.toUpperCase())} placeholder="Enter symbol..."
                className="bg-white/[0.03] border border-white/[0.08] rounded-xl px-4 pl-10 py-3 text-sm font-bold text-white focus:outline-none focus:border-cyan-500/40 w-48" />
            </div>
            <button type="submit" className="px-6 py-3 bg-cyan-500/15 border border-cyan-500/30 text-cyan-400 font-black text-xs uppercase tracking-widest rounded-xl hover:bg-cyan-500/25 transition-all">
              Analyze
            </button>
          </form>
        </div>
      </div>

      {data && (
        <>
          {/* Price Target Visual Range */}
          <div className="glass-panel p-8 border border-white/[0.04]">
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-xs font-black text-white uppercase tracking-widest flex items-center gap-2">
                <BarChart2 className="w-4 h-4 text-cyan-400" /> {data.symbol} Target Range
              </h3>
              <span className="text-lg font-black text-white font-mono-data">CMP: Γé╣{data.current_price?.toLocaleString()}</span>
            </div>

            {/* Visual Range Bar */}
            <div className="relative py-12">
              {/* Range bar */}
              <div className="relative h-3 bg-white/[0.04] rounded-full overflow-visible">
                {/* Colored range */}
                {(() => {
                  const low = data.consensus?.low_target || 0;
                  const high = data.consensus?.high_target || 0;
                  const range = (high - low) || 1; // prevent divide by zero
                  const currentPrice = data.current_price || 0;
                  const leftPct = 5;
                  const widthPct = 90;
                  return (
                    <>
                      <div className="absolute h-full bg-gradient-to-r from-red-500/30 via-emerald-500/30 to-emerald-500/50 rounded-full"
                        style={{ left: `${leftPct}%`, width: `${widthPct}%` }} />
                      
                      {/* Current Price Marker */}
                      <div className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 z-20"
                        style={{ left: `${Math.min(Math.max(leftPct + ((currentPrice - low) / range) * widthPct, 0), 100)}%` }}>
                        <div className="w-5 h-5 rounded-full bg-white border-2 border-white shadow-[0_0_20px_rgba(255,255,255,0.3)]" />
                        <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 whitespace-nowrap">
                          <p className="text-[10px] font-black text-white bg-white/10 px-2 py-0.5 rounded">CMP Γé╣{currentPrice.toLocaleString()}</p>
                        </div>
                      </div>

                      {/* AI Target Marker */}
                      <div className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 z-10"
                        style={{ left: `${Math.min(Math.max(leftPct + (((data.ai_target?.price || 0) - low) / range) * widthPct, 0), 100)}%` }}>
                        <div className="w-4 h-4 rounded-full bg-violet-500 border-2 border-violet-400 shadow-[0_0_15px_rgba(139,92,246,0.4)]" />
                        <div className="absolute -top-8 left-1/2 -translate-x-1/2 whitespace-nowrap">
                          <p className="text-[9px] font-black text-violet-400 bg-violet-500/10 px-2 py-0.5 rounded">AI Γé╣{(data.ai_target?.price || 0).toLocaleString()}</p>
                        </div>
                      </div>

                      {/* Low / High labels */}
                      <div className="absolute -bottom-8 left-0"><p className="text-[9px] font-black text-red-400">Γé╣{low?.toLocaleString()}</p></div>
                      <div className="absolute -bottom-8 right-0"><p className="text-[9px] font-black text-emerald-400">Γé╣{high?.toLocaleString()}</p></div>
                    </>
                  );
                })()}
              </div>
            </div>

            {/* Consensus Cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6">
              {[
                { label: 'Mean Target', value: `Γé╣${(data.consensus?.mean_target || 0).toLocaleString()}`, upside: (((data.consensus?.mean_target || 0) - (data.current_price || 1)) / (data.current_price || 1) * 100).toFixed(1) },
                { label: 'Median Target', value: `Γé╣${(data.consensus?.median_target || 0).toLocaleString()}`, upside: (((data.consensus?.median_target || 0) - (data.current_price || 1)) / (data.current_price || 1) * 100).toFixed(1) },
                { label: 'AI Target', value: `Γé╣${(data.ai_target?.price || 0).toLocaleString()}`, upside: data.ai_target?.upside || 0 },
                { label: 'Crowd Target', value: `Γé╣${(data.crowd_consensus?.target || 0).toLocaleString()}`, upside: data.crowd_consensus?.upside || 0 },
              ].map((c, i) => (
                <div key={i} className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.04] text-center">
                  <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-2">{c.label}</p>
                  <p className="text-lg font-black text-white font-mono-data">{c.value}</p>
                  <p className={`text-xs font-black mt-1 ${c.upside >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                    {c.upside > 0 ? '+' : ''}{c.upside}% upside
                  </p>
                </div>
              ))}
            </div>
          </div>

          {/* Rating Distribution */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="glass-panel p-6 border border-white/[0.04] flex flex-col items-center">
              <h3 className="text-xs font-black text-zinc-500 uppercase tracking-widest mb-4">Rating Distribution</h3>
              <div className="flex gap-4 items-end h-32">
                {[
                  { label: 'BUY', count: data.consensus?.buy_count || 0, color: 'bg-emerald-500' },
                  { label: 'HOLD', count: data.consensus?.hold_count || 0, color: 'bg-amber-500' },
                  { label: 'SELL', count: data.consensus?.sell_count || 0, color: 'bg-red-500' },
                ].map((r, i) => (
                  <div key={i} className="flex flex-col items-center gap-2">
                    <span className="text-lg font-black text-white">{r.count}</span>
                    <motion.div
                      initial={{ height: 0 }}
                      animate={{ height: `${Math.max(10, (r.count / Math.max(data.consensus?.total_analysts || 1, 1)) * 100)}%` }}
                      className={`w-14 ${r.color}/60 rounded-t-lg`}
                    />
                    <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">{r.label}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* AI Target Details */}
            <div className="glass-panel p-6 border border-white/[0.04]">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 rounded-xl bg-violet-500/15 flex items-center justify-center">
                  <Cpu className="w-5 h-5 text-violet-400" />
                </div>
                <div>
                  <h3 className="text-xs font-black text-white uppercase tracking-widest">NexusAI Target</h3>
                  <p className="text-[9px] text-zinc-600 font-bold">{data.ai_target?.model || 'Alpha'}</p>
                </div>
              </div>
              <p className="text-3xl font-black text-violet-400 font-mono-data mb-2">Γé╣{(data.ai_target?.price || 0).toLocaleString()}</p>
              <p className={`text-sm font-black ${(data.ai_target?.upside || 0) >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {(data.ai_target?.upside || 0) > 0 ? '+' : ''}{data.ai_target?.upside || 0}% upside
              </p>
              <div className="mt-4 flex items-center gap-2">
                <div className="flex-1 h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                  <div className="h-full bg-violet-500/60 rounded-full" style={{ width: `${data.ai_target?.confidence || 0}%` }} />
                </div>
                <span className="text-[10px] font-black text-zinc-500">{data.ai_target?.confidence || 0}% conf</span>
              </div>
              <p className="text-[9px] text-zinc-600 font-bold mt-2">Timeframe: {data.ai_target?.timeframe || 'N/A'}</p>
            </div>

            {/* Crowd Consensus */}
            <div className="glass-panel p-6 border border-white/[0.04]">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 rounded-xl bg-amber-500/15 flex items-center justify-center">
                  <Users className="w-5 h-5 text-amber-400" />
                </div>
                <div>
                  <h3 className="text-xs font-black text-white uppercase tracking-widest">Crowd Consensus</h3>
                  <p className="text-[9px] text-zinc-600 font-bold">{(data.crowd_consensus?.total_votes || 0).toLocaleString()} votes</p>
                </div>
              </div>
              <p className="text-3xl font-black text-amber-400 font-mono-data mb-2">Γé╣{(data.crowd_consensus?.target || 0).toLocaleString()}</p>
              <p className={`text-sm font-black ${(data.crowd_consensus?.upside || 0) >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {(data.crowd_consensus?.upside || 0) > 0 ? '+' : ''}{data.crowd_consensus?.upside || 0}% upside
              </p>
              <div className="mt-4">
                <div className="flex items-center justify-between mb-1">
                  <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Bullish</span>
                  <span className="text-[9px] font-black text-emerald-400">{data.crowd_consensus?.bullish_pct || 0}%</span>
                </div>
                <div className="h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                  <div className="h-full bg-emerald-500/50 rounded-full" style={{ width: `${data.crowd_consensus?.bullish_pct || 0}%` }} />
                </div>
              </div>
            </div>
          </div>

          {/* Analyst Breakdown Table */}
          <div className="glass-panel p-6 border border-white/[0.04]">
            <h3 className="text-xs font-black text-white uppercase tracking-widest mb-5 flex items-center gap-2">
              <Star className="w-4 h-4 text-amber-400" /> Analyst Breakdown
            </h3>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-white/[0.04]">
                    {['Firm', 'Tier', 'Target', 'Upside', 'Rating', 'Confidence', 'Updated'].map(h => (
                      <th key={h} className="text-[9px] font-black text-zinc-600 uppercase tracking-widest py-3 px-4 text-left">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {(!data.analyst_targets || data.analyst_targets.length === 0) && (
                    <tr><td colSpan="7" className="text-center py-6 text-zinc-500 text-xs">No analyst data available</td></tr>
                  )}
                  {data.analyst_targets?.map((t, i) => (
                    <tr key={i} className="border-b border-white/[0.02] hover:bg-white/[0.02] transition-colors">
                      <td className="py-3 px-4 flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full" style={{ backgroundColor: t.color || '#fff' }} />
                        <span className="text-sm font-bold text-white">{t.firm || 'Unknown'}</span>
                      </td>
                      <td className="py-3 px-4">
                        <span className={`text-[9px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest ${
                          t.tier === 'GLOBAL' ? 'bg-sky-500/10 text-sky-400' : t.tier === 'ASIA' ? 'bg-violet-500/10 text-violet-400' : 'bg-zinc-500/10 text-zinc-400'
                        }`}>{t.tier || 'LOCAL'}</span>
                      </td>
                      <td className="py-3 px-4 text-sm font-black text-white font-mono-data">Γé╣{(t.target_price || 0).toLocaleString()}</td>
                      <td className="py-3 px-4">
                        <span className={`text-sm font-black ${(t.upside || 0) >= 0 ? 'text-emerald-400' : 'text-red-400'} flex items-center gap-1`}>
                          {(t.upside || 0) >= 0 ? <ArrowUpRight className="w-3 h-3" /> : <ArrowDownRight className="w-3 h-3" />}
                          {(t.upside || 0) > 0 ? '+' : ''}{t.upside || 0}%
                        </span>
                      </td>
                      <td className="py-3 px-4">
                        <span className={`text-[9px] font-black px-2 py-1 rounded uppercase tracking-widest ${
                          (t.rating || '').includes('BUY') ? 'bg-emerald-500/10 text-emerald-400' : (t.rating || '') === 'HOLD' ? 'bg-amber-500/10 text-amber-400' : 'bg-red-500/10 text-red-400'
                        }`}>{t.rating || 'N/A'}</span>
                      </td>
                      <td className="py-3 px-4">
                        <div className="flex items-center gap-2">
                          <div className="w-12 h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                            <div className="h-full bg-cyan-500/50 rounded-full" style={{ width: `${t.confidence || 0}%` }} />
                          </div>
                          <span className="text-[10px] font-bold text-zinc-500">{t.confidence || 0}%</span>
                        </div>
                      </td>
                      <td className="py-3 px-4 text-[10px] text-zinc-600 font-bold">{t.date_updated || '-'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Historical Accuracy */}
          <div className="glass-panel p-6 border border-white/[0.04]">
            <h3 className="text-xs font-black text-white uppercase tracking-widest mb-5">Historical Target Accuracy</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {(!data.historical_accuracy || data.historical_accuracy.length === 0) && (
                <p className="text-zinc-500 text-xs col-span-full">No historical accuracy data</p>
              )}
              {data.historical_accuracy?.map((h, i) => (
                <div key={i} className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.04] text-center">
                  <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-2">{h.quarter || 'Q?'}</p>
                  <p className={`text-2xl font-black font-mono-data ${(h.accuracy_pct || 0) > 85 ? 'text-emerald-400' : (h.accuracy_pct || 0) > 70 ? 'text-amber-400' : 'text-red-400'}`}>
                    {h.accuracy_pct || 0}%
                  </p>
                  <p className="text-[9px] text-zinc-600 font-bold mt-1">Accuracy</p>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </motion.div>
    </ErrorBoundary>
  );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { User, Mail, Phone, Calendar, Shield, Award, TrendingUp, History, Settings, LogOut, ChevronRight, Activity, Zap, ShieldCheck, CheckCircle2, CreditCard, Building2, MapPin, AlertCircle, Lock } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import { API_BASE_URL } from '../config';
import BillingTab from '../components/BillingTab';
import { getDisplayName, getAvatarInitials, shortenWallet } from '../utils/identity';

export default function Profile() {
  const { user, profile: contextProfile, logout, refreshUser } = useUser();
  const [profileData, setProfileData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');
  const [copied, setCopied] = useState(false);
  const toast = useToast();
  const navigate = useNavigate();

  const handleCopyWallet = () => {
    if (user?.walletAddress) {
      navigator.clipboard.writeText(user.walletAddress);
      setCopied(true);
      toast.success('Wallet address copied to clipboard');
      setTimeout(() => setCopied(false), 2000);
    }
  };

  useEffect(() => {
    const fetchProfile = async () => {
      if (!user) return;
      try {
        const res = await axios.get(`${API_BASE_URL}/api/auth/me?user_id=${user.id}`);
        setProfileData(res.data);
      } catch (e) {
        console.error("Failed to fetch profile", e);
      } finally {
        setLoading(false);
      }
    };
    fetchProfile();
  }, [user]);

  if (loading || !profileData) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="flex flex-col items-center gap-4 text-zinc-500 animate-pulse">
            <div className="w-12 h-12 rounded-full border-t-2 border-primary animate-spin" />
            <div className="text-[10px] font-bold uppercase tracking-widest">Loading Artificial Intelligence Profile...</div>
        </div>
      </div>
    );
  }

  const { user: userDetails, profile: kycDetails } = profileData;
  const isKycVerified = userDetails.kyc_status === 'VERIFIED';

  return (
    <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="max-w-6xl mx-auto space-y-8 pb-20">
      {/* Header Profile Section */}
      <div className="relative rounded-2xl sm:rounded-3xl lg:rounded-[40px] overflow-hidden border border-white/[0.06] bg-[#060b18] p-5 sm:p-8 md:p-12 shadow-2xl">
        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/[0.04] rounded-full blur-[150px] pointer-events-none" />
        
        <div className="relative z-10 flex flex-col items-center md:flex-row md:items-center gap-8 sm:gap-12">
          <div className="relative group">
            <div className="w-24 h-24 sm:w-32 sm:h-32 md:w-40 md:h-40 rounded-2xl sm:rounded-3xl md:rounded-[48px] bg-gradient-to-br from-primary to-secondary p-1 rotate-3 group-hover:rotate-0 transition-transform duration-700 shadow-2xl">
              <div className="w-full h-full bg-[#060b18] rounded-2xl sm:rounded-3xl md:rounded-[44px] flex items-center justify-center p-2 sm:p-3">
                <div className="w-full h-full bg-zinc-900/50 rounded-xl sm:rounded-2xl md:rounded-[38px] flex items-center justify-center overflow-hidden">
                   {userDetails.avatar_url ? (
                     <img src={userDetails.avatar_url} alt="Profile" className="w-full h-full object-cover" />
                   ) : (
                     <span className="text-4xl sm:text-5xl md:text-6xl font-black text-primary/80 uppercase tracking-tighter">
                       {getAvatarInitials(userDetails)}
                     </span>
                   )}
                </div>
              </div>
            </div>
            {isKycVerified && (
              <div className="absolute -bottom-2 -right-2 bg-emerald-500 w-10 h-10 rounded-2xl border-4 border-[#060b18] shadow-lg flex items-center justify-center">
                 <ShieldCheck className="w-6 h-6 text-white" />
              </div>
            )}
          </div>

          <div className="text-center md:text-left space-y-6 flex-1">
            <div className="space-y-1">
              <div className="flex flex-wrap items-center justify-center md:justify-start gap-4">
                <h1 className="text-4xl font-black text-white tracking-tight">{getDisplayName(userDetails)}</h1>
                <div className={`px-3 py-1 rounded-full border text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-2 ${isKycVerified ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400' : 'bg-amber-500/10 border-amber-500/20 text-amber-500'}`}>
                   {isKycVerified ? <CheckCircle2 size={12} /> : <AlertCircle size={12} />}
                   {userDetails.kyc_status}
                </div>
              </div>
              <p className="text-zinc-500 font-bold uppercase tracking-[0.3em] text-[11px]">{userDetails.account_type || 'Retail'} Trading Member ΓÇó ID: {userDetails.id?.toString().padStart(6, '0') || 'N/A'}</p>
            </div>

            <div className="flex flex-wrap justify-center md:justify-start gap-3">
              {(userDetails.email || userDetails.phone) ? (
                <>
                  {userDetails.email && (
                    <div className="flex items-center gap-3 px-5 py-2.5 bg-white/[0.03] border border-white/[0.06] rounded-2xl group hover:bg-white/[0.06] transition-all">
                      <Mail className="w-4 h-4 text-zinc-500 group-hover:text-primary transition-colors" />
                      <span className="text-sm font-bold text-zinc-300">{userDetails.email}</span>
                    </div>
                  )}
                  {userDetails.phone && (
                    <div className="flex items-center gap-3 px-5 py-2.5 bg-white/[0.03] border border-white/[0.06] rounded-2xl group hover:bg-white/[0.06] transition-all">
                      <Phone className="w-4 h-4 text-zinc-500 group-hover:text-primary transition-colors" />
                      <span className="text-sm font-bold text-zinc-300">{userDetails.phone}</span>
                    </div>
                  )}
                </>
              ) : userDetails.walletAddress ? (
                <button 
                  onClick={handleCopyWallet}
                  className="flex items-center gap-3 px-5 py-2.5 bg-primary/10 border border-primary/20 rounded-2xl group hover:bg-primary/20 transition-all text-primary"
                >
                  <Activity className="w-4 h-4 text-primary group-hover:animate-pulse" />
                  <span className="text-sm font-bold font-mono-data tracking-wider">
                    Connected: {shortenWallet(userDetails.walletAddress)}
                  </span>
                  {copied ? <CheckCircle2 className="w-4 h-4 ml-1" /> : <ChevronRight className="w-4 h-4 opacity-50 ml-1 group-hover:opacity-100 group-hover:translate-x-1 transition-all" />}
                </button>
              ) : null}
              
              <div className="flex items-center gap-3 px-5 py-2.5 bg-white/[0.03] border border-white/[0.06] rounded-2xl">
                <Calendar className="w-4 h-4 text-zinc-600" />
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">
                  Joined {userDetails.created_at ? new Date(userDetails.created_at).toLocaleDateString('en-IN', { month: 'long', year: 'numeric' }) : 'Recently'}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Tabs Navigation */}
      <div className="flex items-center gap-4 border-b border-white/[0.06] mb-8 pb-4">
        <button 
          onClick={() => setActiveTab('overview')} 
          className={`px-4 py-2 text-sm font-bold uppercase tracking-widest rounded-xl transition-all ${activeTab === 'overview' ? 'bg-primary/10 text-primary border border-primary/20' : 'text-zinc-500 hover:text-white'}`}
        >
          Overview
        </button>
        <button 
          onClick={() => setActiveTab('billing')} 
          className={`px-4 py-2 text-sm font-bold uppercase tracking-widest rounded-xl transition-all ${activeTab === 'billing' ? 'bg-amber-500/10 text-amber-500 border border-amber-500/20' : 'text-zinc-500 hover:text-white'}`}
        >
          Billing & Subscription
        </button>
      </div>

      {activeTab === 'overview' ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 sm:gap-8">
         <div className="lg:col-span-2 space-y-8">
            <div className="glass-panel p-10 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-40 h-40 bg-primary/5 rounded-full blur-[60px] group-hover:bg-primary/10 transition-all" />
               <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-10 pb-6 border-b border-white/[0.06]">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-12 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center">
                        <CreditCard className="w-6 h-6 text-primary" />
                     </div>
                     <div>
                        <h3 className="text-xl font-black text-white">Identity Matrix</h3>
                        <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mt-1">Verified Government Credentials</p>
                     </div>
                  </div>
                  {isKycVerified && (
                     <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/5 border border-emerald-500/10 rounded-xl">
                        <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                        <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">KYC COMPLIANT</span>
                     </div>
                  )}
               </div>

                {!isKycVerified && (
                  <div className="flex flex-col md:flex-row items-center justify-between gap-6 p-8 bg-amber-500/5 border border-amber-500/10 rounded-[32px] mb-10">
                    <div className="flex items-center gap-4 text-amber-500">
                      <AlertCircle className="w-8 h-8" />
                      <div>
                        <h4 className="text-lg font-black uppercase tracking-widest text-white">KYC Required</h4>
                        <p className="text-xs font-bold text-amber-500/80 uppercase tracking-widest mt-1">Unlock live trading & payouts</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => navigate('/kyc')}
                      className="px-8 py-3.5 bg-amber-500 text-black font-black uppercase tracking-widest rounded-2xl hover:bg-amber-400 transition-all shadow-lg shadow-amber-500/20"
                    >
                      Complete Verification Now
                    </button>
                  </div>
                )}

               <div className="grid grid-cols-1 sm:grid-cols-2 gap-5 sm:gap-8">
                  <div className="p-6 bg-white/[0.02] border border-white/[0.04] rounded-3xl space-y-4">
                     <div className="flex items-center gap-2 mb-2">
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Primary Tax ID (PAN)</span>
                        {kycDetails.pan && <CheckCircle2 size={12} className="text-emerald-500" />}
                     </div>
                     <p className="text-2xl font-black text-white font-mono-data tracking-[0.2em]">{kycDetails.pan || 'UNAVAILABLE'}</p>
                     <div className="flex items-center gap-2 text-[10px] font-bold text-zinc-600">
                        <Shield size={12} /> SECURED STORAGE
                     </div>
                  </div>

                  <div className="p-6 bg-white/[0.02] border border-white/[0.04] rounded-3xl space-y-4">
                     <div className="flex items-center gap-2 mb-2">
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">National ID (Aadhaar)</span>
                        {kycDetails.aadhaar && <CheckCircle2 size={12} className="text-emerald-500" />}
                     </div>
                     <p className="text-2xl font-black text-white font-mono-data tracking-[0.2em]">{kycDetails.aadhaar ? `ΓÇóΓÇóΓÇóΓÇó ΓÇóΓÇóΓÇóΓÇó ${kycDetails.aadhaar.slice(-4)}` : 'UNAVAILABLE'}</p>
                     <div className="flex items-center gap-2 text-[10px] font-bold text-zinc-600">
                        <Lock size={12} /> DIGILOCKER SYNCED
                     </div>
                  </div>
               </div>
            </div>

            <div className="glass-panel p-10 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-40 h-40 bg-secondary/5 rounded-full blur-[60px] group-hover:bg-secondary/10 transition-all" />
               <div className="flex items-center gap-4 mb-8">
                  <div className="w-12 h-12 rounded-2xl bg-secondary/10 border border-secondary/20 flex items-center justify-center">
                     <Building2 className="w-6 h-6 text-secondary" />
                  </div>
                  <div>
                     <h3 className="text-xl font-black text-white">Fiscal Connectivity</h3>
                     <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mt-1">Linked Bank Primary Node</p>
                  </div>
               </div>

               <div className="p-5 sm:p-8 bg-gradient-to-br from-white/[0.03] to-white/[0.01] border border-white/[0.08] rounded-2xl sm:rounded-[32px] flex flex-col sm:flex-row items-center gap-5 sm:gap-8">
                  <div className="w-20 h-20 bg-secondary text-black rounded-3xl flex items-center justify-center font-black text-3xl shadow-xl shadow-secondary/20 shrink-0">
                     {kycDetails.bank_name?.charAt(0) || 'B'}
                  </div>
                  <div className="flex-1 space-y-4 text-center md:text-left">
                     <div>
                        <h4 className="text-2xl font-black text-white">{kycDetails.bank_name || 'No Bank Linked'}</h4>
                        <p className="text-zinc-500 font-bold uppercase tracking-widest text-[10px] mt-1">IFSC: {kycDetails.bank_ifsc || 'XXXX0000000'}</p>
                     </div>
                     <div className="flex items-center justify-center md:justify-start gap-4">
                        <div className="flex flex-col">
                           <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Account Type</span>
                           <span className="text-sm font-bold text-zinc-400">SAVINGS</span>
                        </div>
                        <div className="w-px h-6 bg-white/[0.08]" />
                        <div className="flex flex-col">
                           <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">Account Number</span>
                           <span className="text-sm font-bold text-zinc-400 font-mono-data tracking-widest">ΓÇóΓÇóΓÇóΓÇó ΓÇóΓÇóΓÇóΓÇó {kycDetails.bank_acc_no?.slice(-4) || '0000'}</span>
                        </div>
                     </div>
                  </div>
                  <button className="px-6 py-3 bg-secondary/10 border border-secondary/20 text-secondary text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-secondary hover:text-black transition-all">Change Mode</button>
               </div>
            </div>
         </div>

         <div className="space-y-6">
            <div className="glass-panel p-8 space-y-6">
               <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] flex items-center gap-2">
                  <Activity size={16} /> Strategy Matrix
               </h3>
               {[
                  { label: 'Risk Profile', val: 'Aggressive', color: 'text-amber-400' },
                  { label: 'Market Segment', val: 'FnO Active', color: 'text-emerald-400' },
                  { label: 'Broker Status', val: 'Connected', color: 'text-primary' },
                  { label: 'Payout Cycle', val: 'Quarterly', color: 'text-zinc-400' }
               ].map((item, i) => (
                  <div key={i} className="flex justify-between items-center py-4 border-b border-white/[0.04] last:border-0">
                     <span className="text-xs font-bold text-zinc-500">{item.label}</span>
                     <span className={`text-xs font-black uppercase tracking-widest ${item.color}`}>{item.val}</span>
                  </div>
               ))}
            </div>

            <div className="glass-panel p-8 bg-gradient-to-br from-primary/10 to-transparent border-primary/20 relative overflow-hidden group">
               <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-primary/20 rounded-full blur-[40px] group-hover:scale-125 transition-transform" />
               <Zap className="w-8 h-8 text-primary mb-4" />
               <h4 className="text-lg font-black text-white">Upgrade to Pro+</h4>
               <p className="text-xs text-zinc-500 mt-2 leading-relaxed mb-6">Unlock deep-learning portfolio rebalancing and multi-broker routing.</p>
               <button className="w-full py-3.5 bg-primary text-black font-black text-[10px] uppercase tracking-widest rounded-2xl hover:bg-emerald-400 transition-all shadow-lg shadow-primary/20">Analyze ROI</button>
            </div>

            <button onClick={logout} className="w-full py-4 bg-rose-500/5 border border-rose-500/10 text-rose-500 font-black text-xs uppercase tracking-widest rounded-3xl hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-3">
               <LogOut size={16} /> Terminate Session
            </button>
         </div>
      </div>
      ) : (
        <BillingTab />
      )}
    </motion.div>
  );
}

import React, { useState, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate, Link } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import {
  UserPlus, User, Mail, Lock, UserCircle, ArrowRight, ShieldCheck,
  CreditCard, Building2, Smartphone, CheckCircle2, AlertCircle,
  RefreshCw, ChevronLeft, Eye, EyeOff, AtSign, Fingerprint
} from 'lucide-react';
import GoogleSignInButton from '../components/GoogleSignInButton';

export default function Register() {
  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: '',
    confirmPassword: '',
    full_name: '',
    pan: '',
    aadhaar: '',
    bank_name: '',
    bank_acc_no: '',
    bank_ifsc: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const { register } = useUser();
  const navigate = useNavigate();
  const toast = useToast();

  const updateField = (name, val) => {
    setFormData({ ...formData, [name]: val });
    if (errors[name]) {
      setErrors({ ...errors, [name]: null });
    }
  };

  // Password strength calculator
  const passwordStrength = useMemo(() => {
    const p = formData.password;
    if (!p) return { score: 0, label: '', color: '' };
    let score = 0;
    if (p.length >= 8) score++;
    if (p.length >= 12) score++;
    if (/[a-z]/.test(p) && /[A-Z]/.test(p)) score++;
    if (/\d/.test(p)) score++;
    if (/[!@#$%^&*(),.?":{}|<>]/.test(p)) score++;

    const labels = ['', 'Weak', 'Fair', 'Good', 'Strong', 'Excellent'];
    const colors = ['', '#ef4444', '#f59e0b', '#eab308', '#22c55e', '#00d09c'];
    return { score, label: labels[score] || 'Weak', color: colors[score] || '#ef4444' };
  }, [formData.password]);

  // Validate email format
  const isValidEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  // Validate PAN format
  const isValidPAN = (pan) => /^[A-Z]{5}[0-9]{4}[A-Z]$/.test(pan.toUpperCase());

  // Validate step before proceeding
  const validateStep = (stepIndex) => {
    const newErrors = {};

    if (stepIndex === 0) {
      if (!formData.full_name.trim()) newErrors.full_name = 'Full name is required';
      if (!formData.username.trim()) newErrors.username = 'Username is required';
      else if (formData.username.length < 3) newErrors.username = 'Username must be at least 3 characters';
      if (!formData.email.trim()) newErrors.email = 'Email is required';
      else if (!isValidEmail(formData.email)) newErrors.email = 'Invalid email format';
      if (!formData.password) newErrors.password = 'Password is required';
      else if (formData.password.length < 6) newErrors.password = 'Password must be at least 6 characters';
      if (formData.password !== formData.confirmPassword) newErrors.confirmPassword = 'Passwords do not match';
    }

    if (stepIndex === 1) {
      if (formData.pan && !isValidPAN(formData.pan)) newErrors.pan = 'Invalid PAN format (e.g. ABCDE1234F)';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNextStep = () => {
    if (validateStep(step)) {
      setStep(prev => prev + 1);
    }
  };

  const handlePrevStep = () => setStep(prev => prev - 1);

  const handleSubmit = async (e) => {
    if (e) e.preventDefault();
    setLoading(true);
    const { confirmPassword, ...submitData } = formData;
    const result = await register(submitData);
    setLoading(false);

    if (result.success) {
      toast.success('Account created! Welcome to NexusAI.');
      navigate('/login');
    } else {
      toast.error(result.error);
    }
  };

  const stepsMetadata = [
    { title: 'Account Creation', sub: 'Identity & Security', icon: <UserPlus size={18} /> },
    { title: 'PAN Verification', sub: 'Legal Identity', icon: <CreditCard size={18} /> },
    { title: 'DigiLocker Sync', sub: 'National ID', icon: <Fingerprint size={18} /> },
    { title: 'Bank Linkage', sub: 'Settlement Setup', icon: <Building2 size={18} /> }
  ];

  const InputError = ({ error }) => error ? (
    <motion.p initial={{ opacity: 0, y: -5 }} animate={{ opacity: 1, y: 0 }} className="text-[10px] text-red-400 font-bold mt-1.5 ml-1 flex items-center gap-1">
      <AlertCircle size={10} /> {error}
    </motion.p>
  ) : null;

  return (
    <div className="flex items-center justify-center min-h-[85vh] py-10 relative overflow-hidden">
      <div className="fixed top-0 right-0 w-[800px] h-[800px] bg-primary/[0.03] rounded-full blur-[200px] -z-10 pointer-events-none" />
      <div className="fixed bottom-0 left-0 w-[600px] h-[600px] bg-secondary/[0.03] rounded-full blur-[150px] -z-10 pointer-events-none" />

      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-xl"
      >
        <div className="glass-card p-8 md:p-10 relative overflow-hidden">
          {/* Decorative glow */}
          <div className="absolute -top-16 -right-16 w-40 h-40 bg-primary/10 blur-[60px] rounded-full pointer-events-none" />

          {/* Step Indicator */}
          <div className="flex items-center gap-2 mb-10 overflow-x-auto no-scrollbar pb-2">
            {stepsMetadata.map((m, idx) => (
              <div key={idx} className="flex-1 min-w-[60px] flex items-center gap-2">
                <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-xs font-black transition-all duration-300 ${
                  idx < step ? 'bg-primary text-black shadow-lg shadow-primary/20' :
                  idx === step ? 'bg-primary/20 text-primary border border-primary/30' :
                  'bg-white/[0.04] text-zinc-600 border border-white/[0.06]'
                }`}>
                  {idx < step ? <CheckCircle2 size={14} /> : m.icon}
                </div>
                {idx < 3 && <div className={`flex-1 h-px transition-all duration-500 ${idx < step ? 'bg-primary' : 'bg-white/[0.06]'}`} />}
              </div>
            ))}
          </div>

          <div className="mb-8">
            <h2 className="text-2xl md:text-3xl font-black text-white leading-tight">{stepsMetadata[step].title}</h2>
            <p className="text-zinc-600 text-[10px] font-black uppercase tracking-[0.2em] mt-1.5">{stepsMetadata[step].sub}</p>
          </div>

          <AnimatePresence mode="wait">
            {/* STEP 0: Account Basics */}
            {step === 0 && (
              <motion.form
                key="s0" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}
                className="space-y-4" onSubmit={(e) => { e.preventDefault(); handleNextStep(); }}
              >
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest ml-1">Full Name</label>
                    <div className="relative">
                      <UserCircle className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                      <input
                        type="text" id="reg-fullname" value={formData.full_name}
                        onChange={(e) => updateField('full_name', e.target.value)}
                        className={`w-full bg-white/[0.03] border ${errors.full_name ? 'border-red-500/50' : 'border-white/[0.08]'} rounded-xl py-3 pl-11 pr-4 text-white focus:border-primary/50 outline-none transition-all placeholder:text-zinc-700 text-sm`}
                        placeholder="John Doe"
                      />
                    </div>
                    <InputError error={errors.full_name} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest ml-1">Username</label>
                    <div className="relative">
                      <AtSign className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                      <input
                        type="text" id="reg-username" value={formData.username}
                        onChange={(e) => updateField('username', e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, ''))}
                        className={`w-full bg-white/[0.03] border ${errors.username ? 'border-red-500/50' : 'border-white/[0.08]'} rounded-xl py-3 pl-11 pr-4 text-white focus:border-primary/50 outline-none transition-all placeholder:text-zinc-700 text-sm`}
                        placeholder="johndoe123"
                      />
                    </div>
                    <InputError error={errors.username} />
                  </div>
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest ml-1">Email</label>
                  <div className="relative">
                    <Mail className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                    <input
                      type="email" id="reg-email" value={formData.email}
                      onChange={(e) => updateField('email', e.target.value)}
                      className={`w-full bg-white/[0.03] border ${errors.email ? 'border-red-500/50' : 'border-white/[0.08]'} rounded-xl py-3 pl-11 pr-4 text-white focus:border-primary/50 outline-none transition-all placeholder:text-zinc-700 text-sm`}
                      placeholder="john@example.com"
                    />
                  </div>
                  <InputError error={errors.email} />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest ml-1">Password</label>
                  <div className="relative">
                    <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                    <input
                      type={showPassword ? 'text' : 'password'} id="reg-password" value={formData.password}
                      onChange={(e) => updateField('password', e.target.value)}
                      className={`w-full bg-white/[0.03] border ${errors.password ? 'border-red-500/50' : 'border-white/[0.08]'} rounded-xl py-3 pl-11 pr-12 text-white focus:border-primary/50 outline-none transition-all placeholder:text-zinc-700 text-sm`}
                      placeholder="Min 6 characters"
                    />
                    <button type="button" onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-3.5 top-1/2 -translate-y-1/2 text-zinc-600 hover:text-zinc-400 transition-colors">
                      {showPassword ? <EyeOff size={15} /> : <Eye size={15} />}
                    </button>
                  </div>
                  {formData.password && (
                    <div className="flex items-center gap-2 mt-2 ml-1">
                      <div className="flex gap-1 flex-1">
                        {[1,2,3,4,5].map(i => (
                          <div key={i} className="h-1 flex-1 rounded-full transition-all duration-300"
                            style={{ backgroundColor: i <= passwordStrength.score ? passwordStrength.color : 'rgba(255,255,255,0.06)' }} />
                        ))}
                      </div>
                      <span className="text-[9px] font-black uppercase tracking-wider" style={{ color: passwordStrength.color }}>
                        {passwordStrength.label}
                      </span>
                    </div>
                  )}
                  <InputError error={errors.password} />
                </div>

                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest ml-1">Confirm Password</label>
                  <div className="relative">
                    <Lock className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-600" />
                    <input
                      type="password" id="reg-confirm-password" value={formData.confirmPassword}
                      onChange={(e) => updateField('confirmPassword', e.target.value)}
                      className={`w-full bg-white/[0.03] border ${errors.confirmPassword ? 'border-red-500/50' : formData.confirmPassword && formData.password === formData.confirmPassword ? 'border-primary/40' : 'border-white/[0.08]'} rounded-xl py-3 pl-11 pr-12 text-white focus:border-primary/50 outline-none transition-all placeholder:text-zinc-700 text-sm`}
                      placeholder="Re-enter password"
                    />
                    {formData.confirmPassword && formData.password === formData.confirmPassword && (
                      <CheckCircle2 size={14} className="absolute right-3.5 top-1/2 -translate-y-1/2 text-primary" />
                    )}
                  </div>
                  <InputError error={errors.confirmPassword} />
                </div>

                <button type="submit" id="reg-next-btn"
                  className="w-full py-4 bg-primary text-black font-black uppercase tracking-widest rounded-xl hover:scale-[1.01] active:scale-[0.99] transition-all flex items-center justify-center gap-2 shadow-lg shadow-primary/20 text-sm mt-2">
                  Continue Setup <ArrowRight className="w-4 h-4" />
                </button>

                {/* Google Signup Integration */}
                {!!import.meta.env.VITE_GOOGLE_CLIENT_ID && (
                  <>
                    <div className="flex items-center my-4">
                      <div className="flex-1 h-px bg-white/[0.06]" />
                      <span className="text-[10px] uppercase tracking-widest text-zinc-600 px-3 font-black">or</span>
                      <div className="flex-1 h-px bg-white/[0.06]" />
                    </div>
                    <GoogleSignInButton
                      label="Sign up with Google"
                      onSuccess={() => navigate('/')}
                    />
                  </>
