export default function SIPCalculator() {
  const [mode, setMode] = useState('sip'); // sip | goal
  const [monthly, setMonthly] = useState(25000);
  const [years, setYears] = useState(15);
  const [rate, setRate] = useState(12);
  const [sipData, setSipData] = useState(null);
  const [goalAmount, setGoalAmount] = useState(10000000);
  const [goalData, setGoalData] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (mode === 'sip') fetchSIP();
    else fetchGoal();
  }, [monthly, years, rate, mode, goalAmount]);

  const fetchSIP = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/calculator/sip?monthly=${monthly}&years=${years}&rate=${rate}`);
      setSipData(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const fetchGoal = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/calculator/goal?goal_amount=${goalAmount}&years=${years}&rate=${rate}`);
      setGoalData(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const formatCurrency = (val) => {
    if (val >= 10000000) return `Γé╣${(val / 10000000).toFixed(2)} Cr`;
    if (val >= 100000) return `Γé╣${(val / 100000).toFixed(2)} L`;
    return `Γé╣${val.toLocaleString('en-IN')}`;
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-black text-white flex items-center gap-3">
          <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-500/20 to-cyan-500/20 border border-blue-500/20 flex items-center justify-center">
            <Calculator className="w-6 h-6 text-blue-400" />
          </div>
          SIP Calculator & Goal Planner
        </h1>
        <p className="text-zinc-500 mt-2 text-sm">Plan your investments with AI-powered projections</p>
      </div>

      {/* Mode Toggle */}
      <div className="flex gap-2 bg-white/[0.02] border border-white/[0.06] rounded-2xl p-1.5 w-fit">
        {[
          { id: 'sip', label: 'SIP Calculator', icon: <TrendingUp size={14} /> },
          { id: 'goal', label: 'Goal Planner', icon: <Target size={14} /> },
        ].map(m => (
          <button key={m.id} onClick={() => setMode(m.id)}
            className={`px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all ${
              mode === m.id ? 'bg-primary text-black shadow-lg' : 'text-zinc-500 hover:text-white'
            }`}>
            {m.icon} {m.label}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Controls */}
        <div className="glass-panel p-6 space-y-6">
          <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em]">Parameters</h3>
          
          {mode === 'sip' ? (
            <div className="space-y-6">
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Monthly Investment</label>
                  <span className="text-primary font-black font-mono-data">Γé╣{monthly.toLocaleString()}</span>
                </div>
                <input type="range" min={500} max={200000} step={500} value={monthly} onChange={e => setMonthly(+e.target.value)}
                  className="w-full accent-[#00D09C] h-1.5 rounded-full bg-white/10" />
                <div className="flex justify-between text-[9px] text-zinc-700 mt-1"><span>Γé╣500</span><span>Γé╣2,00,000</span></div>
              </div>
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Duration (Years)</label>
                  <span className="text-white font-black">{years}Y</span>
                </div>
                <input type="range" min={1} max={40} value={years} onChange={e => setYears(+e.target.value)}
                  className="w-full accent-[#00D09C] h-1.5 rounded-full bg-white/10" />
                <div className="flex justify-between text-[9px] text-zinc-700 mt-1"><span>1 Year</span><span>40 Years</span></div>
              </div>
            </div>
          ) : (
            <div className="space-y-5">
              <div>
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-3 block">Select Goal</label>
                <div className="grid grid-cols-2 gap-2">
                  {GOALS.map(g => (
                    <button key={g.id} onClick={() => { setGoalAmount(g.amount); setYears(g.years); }}
                      className={`p-3 rounded-xl border text-left transition-all ${
                        goalAmount === g.amount ? 'border-primary bg-primary/10' : 'border-white/[0.06] hover:bg-white/[0.03]'
                      }`}>
                      <div style={{ color: g.color }} className="text-lg mb-1">{g.icon}</div>
                      <p className="text-xs font-bold text-white">{g.name}</p>
                      <p className="text-[10px] text-zinc-600">{formatCurrency(g.amount)}</p>
                    </button>
                  ))}
                </div>
              </div>
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Target Amount</label>
                  <span className="text-primary font-black font-mono-data">{formatCurrency(goalAmount)}</span>
                </div>
                <input type="range" min={500000} max={100000000} step={500000} value={goalAmount} onChange={e => setGoalAmount(+e.target.value)}
                  className="w-full accent-[#00D09C] h-1.5 rounded-full bg-white/10" />
              </div>
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Duration</label>
                  <span className="text-white font-black">{years} Years</span>
                </div>
                <input type="range" min={1} max={40} value={years} onChange={e => setYears(+e.target.value)}
                  className="w-full accent-[#00D09C] h-1.5 rounded-full bg-white/10" />
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between mb-2">
              <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Expected Return (% p.a.)</label>
              <span className="text-amber-400 font-black">{rate}%</span>
            </div>
            <input type="range" min={4} max={30} step={0.5} value={rate} onChange={e => setRate(+e.target.value)}
              className="w-full accent-[#f59e0b] h-1.5 rounded-full bg-white/10" />
            <div className="flex justify-between text-[9px] text-zinc-700 mt-1"><span>4%</span><span>30%</span></div>
          </div>
        </div>

        {/* Results */}
        <div className="lg:col-span-2 space-y-6">
          {mode === 'sip' && sipData && (
            <>
              <div className="grid grid-cols-3 gap-4">
                <div className="glass-panel p-5 text-center">
                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Total Invested</p>
                  <p className="text-2xl font-black text-white font-mono-data">{formatCurrency(sipData.sip.total_invested)}</p>
                </div>
                <div className="glass-panel p-5 text-center border-primary/20">
                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Future Value</p>
                  <p className="text-2xl font-black text-primary font-mono-data">{formatCurrency(sipData.sip.future_value)}</p>
                </div>
                <div className="glass-panel p-5 text-center">
                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Wealth Gained</p>
                  <p className="text-2xl font-black text-emerald-400 font-mono-data">{formatCurrency(sipData.sip.wealth_gained)}</p>
                </div>
              </div>

              {/* Growth Chart */}
              <div className="glass-panel p-6">
                <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Year-by-Year Growth</h3>
                <ResponsiveContainer width="100%" height={300}>
                  <AreaChart data={sipData.yearly_breakdown}>
                    <defs>
                      <linearGradient id="investedGrad" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="valueGrad" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#00D09C" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#00D09C" stopOpacity={0} />
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                    <XAxis dataKey="year" tick={{ fontSize: 10, fill: '#52525b' }} tickFormatter={v => `Y${v}`} />
                    <YAxis tick={{ fontSize: 10, fill: '#52525b' }} tickFormatter={v => v >= 10000000 ? `${(v/10000000).toFixed(0)}Cr` : v >= 100000 ? `${(v/100000).toFixed(0)}L` : v} />
                    <Tooltip contentStyle={{ background: '#0a0a0f', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 12 }}
                      formatter={(v) => [formatCurrency(v)]} labelFormatter={v => `Year ${v}`} />
                    <Area type="monotone" dataKey="invested" stroke="#3b82f6" fill="url(#investedGrad)" strokeWidth={2} name="Invested" />
                    <Area type="monotone" dataKey="value" stroke="#00D09C" fill="url(#valueGrad)" strokeWidth={2} name="Portfolio Value" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>

              {/* SIP vs Lumpsum */}
              <div className="glass-panel p-6">
                <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">SIP vs Lumpsum Comparison</h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-primary/5 border border-primary/10 rounded-2xl p-5 text-center">
                    <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">SIP Returns</p>
                    <p className="text-2xl font-black text-primary font-mono-data">{formatCurrency(sipData.sip.future_value)}</p>
                    <p className="text-xs text-emerald-400 mt-1">Wealth Gained: {formatCurrency(sipData.sip.wealth_gained)}</p>
                  </div>
                  <div className="bg-blue-500/5 border border-blue-500/10 rounded-2xl p-5 text-center">
                    <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Lumpsum Returns</p>
                    <p className="text-2xl font-black text-blue-400 font-mono-data">{formatCurrency(sipData.lumpsum.future_value)}</p>
                    <p className="text-xs text-blue-400 mt-1">Wealth Gained: {formatCurrency(sipData.lumpsum.wealth_gained)}</p>
                  </div>
                </div>
              </div>
            </>
          )}

          {mode === 'goal' && goalData && (
            <>
              <div className="glass-panel p-8 text-center border-primary/20 bg-primary/[0.02]">
                <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Start a SIP of</p>
                <p className="text-5xl font-black text-primary font-mono-data mb-2">Γé╣{goalData.required_monthly_sip?.toLocaleString('en-IN')}<span className="text-lg text-zinc-600">/month</span></p>
                <p className="text-sm text-zinc-500">to reach <span className="text-white font-bold">{formatCurrency(goalData.goal_amount)}</span> in {goalData.duration_years} years at {goalData.return_rate}% p.a.</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="glass-panel p-5 text-center">
                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">You'll Invest</p>
                  <p className="text-xl font-black text-white font-mono-data">{formatCurrency(goalData.total_invested)}</p>
                </div>
                <div className="glass-panel p-5 text-center">
                  <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">Market Will Add</p>
                  <p className="text-xl font-black text-emerald-400 font-mono-data">{formatCurrency(goalData.wealth_gained)}</p>
                </div>
              </div>

              {/* Milestones */}
              <div className="glass-panel p-6">
                <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Goal Milestones</h3>
                <div className="space-y-3">
                  {goalData.milestones?.map((m, i) => (
                    <div key={i} className="flex items-center gap-4">
                      <div className="w-12 h-12 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center shrink-0">
                        <span className="text-primary font-black text-sm">{m.percent}%</span>
                      </div>
                      <div className="flex-1">
                        <div className="h-2 bg-white/5 rounded-full overflow-hidden mb-1">
                          <motion.div initial={{ width: 0 }} animate={{ width: `${m.percent}%` }} transition={{ delay: i * 0.2, duration: 0.8 }}
                            className="h-full bg-gradient-to-r from-primary to-emerald-400 rounded-full" />
                        </div>
                        <p className="text-xs text-zinc-500">{formatCurrency(m.amount)} in <span className="text-white font-bold">{m.years} years</span> ({m.months} months)</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Radio, TrendingUp, TrendingDown, Flame, MessageCircle, Heart, Search, ArrowUp, Loader2, BarChart2, Globe, Zap, ThumbsUp, ThumbsDown, Minus } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';
import axios from 'axios';
import { API_BASE_URL } from '../config';
import { useNavigate } from 'react-router-dom';

const TREND_CONFIG = {
  SURGING: { color: '#10b981', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20', label: '≡ƒöÑ SURGING' },
  RISING: { color: '#0ea5e9', bg: 'bg-sky-500/10', border: 'border-sky-500/20', label: '≡ƒôê RISING' },
  STABLE: { color: '#a1a1aa', bg: 'bg-zinc-500/10', border: 'border-zinc-500/20', label: 'Γ₧í∩╕Å STABLE' },
  VOLATILE: { color: '#f59e0b', bg: 'bg-amber-500/10', border: 'border-amber-500/20', label: 'ΓÜí VOLATILE' },
};

export default function SentimentRadar() {
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedSymbol, setSelectedSymbol] = useState('');
  const [searchInput, setSearchInput] = useState('');
  const [detail, setDetail] = useState(null);
  const [detailLoading, setDetailLoading] = useState(false);

  useEffect(() => { fetchRadar(); }, []);

  const fetchRadar = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/sentiment/radar`);
      setData(res.data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const fetchDetail = async (symbol) => {
    setSelectedSymbol(symbol);
    setDetailLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/sentiment/radar?symbol=${symbol}`);
      setDetail(res.data.detail);
    } catch (e) { console.error(e); }
    finally { setDetailLoading(false); }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchInput.trim()) fetchDetail(searchInput.trim().toUpperCase());
  };

  if (loading) return <div className="py-20 text-center"><Loader2 className="w-8 h-8 text-primary mx-auto animate-spin" /></div>;

  return (
    <div className="space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-black text-white flex items-center gap-3">
          <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-pink-500/20 to-purple-500/20 border border-pink-500/20 flex items-center justify-center">
            <Radio className="w-6 h-6 text-pink-400" />
          </div>
          Social Sentiment Radar
        </h1>
        <p className="text-zinc-500 mt-2 text-sm">Live social media sentiment tracking ΓÇó Exclusive to NexusAI ΓÇö no other Indian app has this</p>
      </div>

      {/* Market Mood Banner */}
      {data?.market_mood && (
        <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
          className="relative overflow-hidden rounded-3xl bg-gradient-to-r from-pink-500/5 via-purple-500/5 to-cyan-500/5 border border-pink-500/10 p-6 flex items-center gap-8">
          <div className="absolute top-0 left-0 w-64 h-64 bg-pink-500/5 rounded-full blur-[100px]" />
          <div className="relative z-10 flex items-center gap-6 flex-1">
            <div className="relative">
              <svg className="w-24 h-24 -rotate-90" viewBox="0 0 120 120">
                <circle cx="60" cy="60" r="50" fill="none" stroke="rgba(255,255,255,0.04)" strokeWidth="8" />
                <circle cx="60" cy="60" r="50" fill="none" stroke="#ec4899" strokeWidth="8" strokeLinecap="round"
                  strokeDasharray={`${data.market_mood.overall_score * 3.14} 314`} />
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-2xl font-black text-white">{data.market_mood.overall_score}</span>
                <span className="text-[8px] font-black text-pink-400 uppercase tracking-widest">MOOD</span>
              </div>
            </div>
            <div>
              <p className="text-[10px] font-black text-zinc-600 uppercase tracking-[0.2em] mb-1">Overall Market Sentiment</p>
              <p className="text-2xl font-black text-white mb-1">{data.market_mood.label}</p>
              <p className="text-xs text-zinc-500">Aggregated from 50,000+ social media posts across Twitter, Reddit & financial forums</p>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-pink-500 animate-pulse" />
            <span className="text-[10px] font-black text-pink-400 uppercase tracking-widest">LIVE</span>
          </div>
        </motion.div>
      )}

      {/* Search */}
      <form onSubmit={handleSearch} className="glass-panel p-4 flex gap-3 items-center">
        <Search className="w-5 h-5 text-zinc-600 shrink-0" />
        <input value={searchInput} onChange={e => setSearchInput(e.target.value.toUpperCase())}
          placeholder="Search any stock for detailed sentiment analysis..."
          className="flex-1 bg-transparent text-white text-sm focus:outline-none placeholder:text-zinc-700" />
        <button type="submit"
          className="px-5 py-2.5 bg-gradient-to-r from-pink-500 to-purple-500 text-white font-black text-xs uppercase tracking-widest rounded-xl hover:opacity-90 transition-all">
          Analyze
        </button>
      </form>

      {/* Trending Stocks Grid */}
      <div>
        <h2 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
          <Flame size={14} className="text-orange-400" /> Trending on Social Media
        </h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
          {data?.trending?.map((stock, i) => {
            const config = TREND_CONFIG[stock.trend] || TREND_CONFIG.STABLE;
            return (
              <motion.div key={stock.symbol} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.05 }}
                onClick={() => fetchDetail(stock.symbol)}
                className={`glass-panel p-5 cursor-pointer hover:border-white/15 transition-all group relative overflow-hidden ${
                  selectedSymbol === stock.symbol ? 'border-pink-500/30 bg-pink-500/[0.02]' : ''
                }`}>
                <div className="absolute top-0 right-0 w-16 h-16 rounded-full blur-[40px] pointer-events-none" style={{ background: `${config.color}10` }} />
                
                <div className="relative z-10">
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 rounded-lg flex items-center justify-center text-xs font-black"
                        style={{ background: `${config.color}20`, color: config.color }}>
                        {stock.symbol.slice(0, 2)}
                      </div>
                      <div>
                        <p className="text-sm font-black text-white group-hover:text-primary transition-colors">{stock.symbol}</p>
                        <p className="text-[10px] text-zinc-600">{stock.name}</p>
                      </div>
                    </div>
                    <span className={`text-[9px] font-black px-2 py-0.5 rounded-lg ${config.bg} ${config.border} border`}
                      style={{ color: config.color }}>
                      {config.label}
                    </span>
                  </div>
                  
                  <div className="flex items-end justify-between">
                    <div>
                      <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest mb-0.5">Sentiment</p>
                      <div className="flex items-center gap-2">
                        <div className="w-20 h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                          <div className="h-full rounded-full" style={{ width: `${stock.sentiment_score}%`, background: config.color }} />
                        </div>
                        <span className="text-xs font-black font-mono-data" style={{ color: config.color }}>{stock.sentiment_score}</span>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-[9px] text-zinc-600 font-bold uppercase tracking-widest mb-0.5">Mentions</p>
                      <p className="text-xs font-black text-white font-mono-data">{(stock.mentions / 1000).toFixed(1)}K</p>
                    </div>
                  </div>
                  
                  <div className="flex items-center justify-between mt-3 pt-3 border-t border-white/[0.04]">
                    <span className="text-xs font-bold text-white font-mono-data">Γé╣{stock.price.toLocaleString()}</span>
                    <span className={`text-xs font-black font-mono-data ${stock.positive ? 'text-emerald-400' : 'text-rose-400'}`}>
                      {stock.positive ? '+' : ''}{stock.change_pct}%
                    </span>
                  </div>
                </div>
              </motion.div>
            );
          })}
        </div>
      </div>

      {/* Detail Panel */}
      <AnimatePresence>
        {(detail || detailLoading) && (
          <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}
            className="overflow-hidden">
            {detailLoading ? (
              <div className="glass-panel p-12 text-center">
                <Loader2 className="w-8 h-8 text-pink-400 mx-auto animate-spin mb-4" />
                <p className="text-sm text-zinc-500">Analyzing social sentiment for {selectedSymbol}...</p>
              </div>
            ) : detail && (
              <div className="space-y-6">
                {/* Detail Header */}
                <div className="glass-panel p-6 bg-gradient-to-r from-pink-500/[0.03] to-purple-500/[0.03] border-pink-500/10">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-4">
                      <h2 className="text-xl font-black text-white">{detail.symbol} Sentiment Analysis</h2>
                      <span className={`text-xs font-black px-3 py-1 rounded-lg ${
                        detail.sentiment_label.includes('BULLISH') ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' :
                        detail.sentiment_label === 'BEARISH' ? 'bg-rose-500/10 text-rose-400 border border-rose-500/20' :
                        'bg-zinc-500/10 text-zinc-400 border border-zinc-500/20'
                      }`}>{detail.sentiment_label}</span>
                    </div>
                    <button onClick={() => { setDetail(null); setSelectedSymbol(''); }}
                      className="text-xs font-bold text-zinc-500 hover:text-white px-3 py-1.5 bg-white/[0.04] rounded-lg border border-white/[0.06]">CLOSE</button>
                  </div>
                  
                  <div className="grid grid-cols-4 gap-4">
                    <div className="bg-white/[0.03] rounded-xl p-4 border border-white/[0.04]">
                      <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Overall Score</p>
                      <p className="text-2xl font-black text-pink-400 font-mono-data">{detail.overall_score}</p>
                    </div>
                    <div className="bg-white/[0.03] rounded-xl p-4 border border-white/[0.04]">
                      <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">24h Mentions</p>
                      <p className="text-2xl font-black text-white font-mono-data">{(detail.total_mentions_24h / 1000).toFixed(1)}K</p>
                    </div>
                    <div className="bg-white/[0.03] rounded-xl p-4 border border-white/[0.04]">
                      <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Mentions Change</p>
                      <p className={`text-2xl font-black font-mono-data ${detail.mentions_change >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                        {detail.mentions_change >= 0 ? '+' : ''}{detail.mentions_change}%
                      </p>
                    </div>
                    <div className="bg-white/[0.03] rounded-xl p-4 border border-white/[0.04]">
                      <p className="text-[9px] font-black text-zinc-600 uppercase tracking-widest mb-1">Breakdown</p>
                      <div className="flex items-center gap-1">
                        <ThumbsUp size={12} className="text-emerald-400" />
                        <span className="text-xs font-black text-emerald-400">{detail.breakdown.bullish}%</span>
                        <Minus size={12} className="text-zinc-600 mx-1" />
                        <ThumbsDown size={12} className="text-rose-400" />
                        <span className="text-xs font-black text-rose-400">{detail.breakdown.bearish}%</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {/* Sentiment Timeline */}
                  <div className="glass-panel p-6">
                    <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">24h Sentiment Timeline</h3>
                    <ResponsiveContainer width="100%" height={220}>
                      <AreaChart data={detail.timeline}>
                        <defs>
                          <linearGradient id="sentGrad" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#ec4899" stopOpacity={0.2} />
                            <stop offset="95%" stopColor="#ec4899" stopOpacity={0} />
                          </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                        <XAxis dataKey="hour" tick={{ fontSize: 9, fill: '#52525b' }} interval={3} />
                        <YAxis tick={{ fontSize: 9, fill: '#52525b' }} domain={[0, 100]} />
                        <Tooltip contentStyle={{ background: '#0a0a0f', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 12 }} />
                        <Area type="monotone" dataKey="score" stroke="#ec4899" fill="url(#sentGrad)" strokeWidth={2} />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>

                  {/* Source Breakdown */}
                  <div className="glass-panel p-6">
                    <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Source Breakdown</h3>
                    <div className="space-y-3">
                      {detail.source_breakdown.map((src, i) => (
                        <div key={i} className="flex items-center gap-4 p-3 bg-white/[0.02] rounded-xl">
                          <span className="text-xl">{src.icon}</span>
                          <div className="flex-1">
                            <p className="text-sm font-bold text-white">{src.source}</p>
                            <p className="text-[10px] text-zinc-600">{src.mentions.toLocaleString()} mentions</p>
                          </div>
                          <div className="w-24 h-1.5 bg-white/[0.04] rounded-full overflow-hidden">
                            <div className="h-full bg-pink-500 rounded-full" style={{ width: `${src.sentiment}%` }} />
                          </div>
                          <span className="text-xs font-black font-mono-data text-pink-400">{src.sentiment}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Social Posts */}
                <div className="glass-panel p-6">
                  <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                    <MessageCircle size={14} className="text-purple-400" /> Latest Social Posts
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                    {detail.posts.map((post, i) => (
                      <motion.div key={i} initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: i * 0.05 }}
                        className="bg-white/[0.02] rounded-xl p-4 border border-white/[0.04] hover:border-white/[0.08] transition-all">
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">{post.platform}</span>
                          <span className={`text-[9px] font-black px-2 py-0.5 rounded ${
                            post.sentiment === 'BULLISH' ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'
                          }`}>{post.sentiment}</span>
                        </div>
                        <p className="text-sm text-zinc-300 mb-3 leading-relaxed">{post.text}</p>
                        <div className="flex items-center justify-between text-[10px] text-zinc-600">
                          <span className="flex items-center gap-1"><Heart size={10} /> {post.likes}</span>
                          <span>{post.time}</span>
                        </div>
                      </motion.div>
                    ))}
                  </div>
                </div>

                {/* AI Summary */}
                <div className="glass-panel p-5 bg-purple-500/[0.02] border-purple-500/10 flex items-start gap-4">
                  <Zap className="w-5 h-5 text-purple-400 mt-0.5 shrink-0" />
                  <div>
                    <p className="text-xs font-black text-purple-400 uppercase tracking-[0.2em] mb-1">AI Sentiment Summary</p>
                    <p className="text-sm text-zinc-400 leading-relaxed">{detail.ai_summary}</p>
                  </div>
                </div>

                {/* Word Cloud */}
                <div className="glass-panel p-6">
                  <h3 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Trending Keywords</h3>
                  <div className="flex flex-wrap gap-2 justify-center py-4">
                    {detail.word_cloud.map((word, i) => (
                      <motion.span key={i} initial={{ opacity: 0, scale: 0.5 }} animate={{ opacity: 1, scale: 1 }}
                        transition={{ delay: i * 0.05 }}
                        className="px-3 py-1.5 rounded-xl bg-white/[0.03] border border-white/[0.06] font-bold transition-all hover:bg-pink-500/10 hover:border-pink-500/20 hover:text-pink-400 cursor-default"
                        style={{ fontSize: Math.max(11, Math.min(24, word.value / 8)), color: `hsl(${(i * 30) % 360}, 60%, 65%)` }}>
                        {word.text}
                      </motion.span>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Bell, BellRing, Plus, Trash2, Sparkles, TrendingUp, TrendingDown, Target, Zap, ChevronDown, X, AlertTriangle } from 'lucide-react';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import { API_BASE_URL } from '../config';

const CONDITIONS = {
  CROSSES_ABOVE: { label: 'Crosses Above', icon: <TrendingUp size={14} />, color: '#10b981' },
  CROSSES_BELOW: { label: 'Crosses Below', icon: <TrendingDown size={14} />, color: '#ef4444' },
  PERCENT_CHANGE: { label: '% Change Alert', icon: <Zap size={14} />, color: '#f59e0b' },
  RSI_ABOVE: { label: 'RSI Above 70', icon: <AlertTriangle size={14} />, color: '#8b5cf6' },
  RSI_BELOW: { label: 'RSI Below 30', icon: <Target size={14} />, color: '#0ea5e9' },
};

export default function SmartAlerts() {
  const { user } = useUser();
  const toast = useToast();
  const [alerts, setAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [symbol, setSymbol] = useState('');
  const [condition, setCondition] = useState('CROSSES_ABOVE');
  const [targetPrice, setTargetPrice] = useState('');
  const [note, setNote] = useState('');
  const [aiSuggestions, setAiSuggestions] = useState(null);
  const [suggestLoading, setSuggestLoading] = useState(false);

  useEffect(() => { fetchAlerts(); }, []);

  const fetchAlerts = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/alerts?user_id=${user?.id || 1}`);
      setAlerts(res.data.alerts);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const createAlert = async () => {
    if (!symbol || !targetPrice) return toast.error('Please fill symbol and price');
    try {
      await axios.post(`${API_BASE_URL}/api/alerts/create?user_id=${user?.id || 1}`, {
        symbol, condition, target_price: parseFloat(targetPrice), note
      });
      toast.success(`Alert created for ${symbol.toUpperCase()}`);
      setShowCreate(false);
      setSymbol(''); setTargetPrice(''); setNote('');
      fetchAlerts();
    } catch (e) { toast.error('Failed to create alert'); }
  };

  const deleteAlert = async (id) => {
    try {
      await axios.delete(`${API_BASE_URL}/api/alerts/${id}?user_id=${user?.id || 1}`);
      setAlerts(prev => prev.filter(a => a.id !== id));
      toast.success('Alert deleted');
    } catch (e) { toast.error('Failed'); }
  };

  const fetchAISuggestions = async () => {
    if (!symbol) return toast.error('Enter a symbol first');
    setSuggestLoading(true);
    try {
      const res = await axios.get(`${API_BASE_URL}/api/alerts/ai-suggest/${symbol}`);
      setAiSuggestions(res.data);
    } catch (e) { toast.error('Failed to get suggestions'); }
    finally { setSuggestLoading(false); }
  };

  const applySuggestion = (s) => {
    setCondition(s.condition);
    setTargetPrice(String(s.price));
    setNote(s.note);
  };

  const activeAlerts = alerts.filter(a => a.status === 'ACTIVE');
  const triggeredAlerts = alerts.filter(a => a.status === 'TRIGGERED');

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-black text-white flex items-center gap-3">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-amber-500/20 to-orange-500/20 border border-amber-500/20 flex items-center justify-center">
              <BellRing className="w-6 h-6 text-amber-400" />
            </div>
            Smart Price Alerts
          </h1>
          <p className="text-zinc-500 mt-2 text-sm">AI-powered alerts with support/resistance detection</p>
        </div>
        <button onClick={() => setShowCreate(true)}
          className="flex items-center gap-2 px-6 py-3 bg-primary text-black font-black rounded-2xl hover:bg-primary-hover transition-all shadow-lg shadow-primary/20 uppercase tracking-widest text-xs">
          <Plus size={16} /> New Alert
        </button>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-3 gap-4">
        {[
          { label: 'Active Alerts', value: activeAlerts.length, color: 'text-emerald-400', bg: 'bg-emerald-500/10' },
          { label: 'Triggered Today', value: triggeredAlerts.length, color: 'text-amber-400', bg: 'bg-amber-500/10' },
          { label: 'Total Created', value: alerts.length, color: 'text-blue-400', bg: 'bg-blue-500/10' },
        ].map((s, i) => (
          <div key={i} className="glass-panel p-5 text-center">
            <p className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2">{s.label}</p>
            <p className={`text-3xl font-black ${s.color}`}>{s.value}</p>
          </div>
        ))}
      </div>

      {/* Active Alerts */}
      <div>
        <h2 className="text-xs font-black text-zinc-500 uppercase tracking-[0.2em] mb-4">Active Alerts</h2>
        <div className="space-y-3">
          {activeAlerts.length === 0 ? (
            <div className="glass-panel p-12 text-center">
              <Bell className="w-12 h-12 text-zinc-700 mx-auto mb-3" />
              <p className="text-zinc-600 text-sm font-bold">No active alerts. Create one to get started!</p>
            </div>
          ) : activeAlerts.map((a, i) => (
            <motion.div key={a.id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.05 }}
              className="glass-panel p-5 flex items-center gap-5 group hover:border-white/10 transition-all">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${a.condition.includes('ABOVE') ? 'bg-emerald-500/10' : 'bg-rose-500/10'}`}>
                {a.condition.includes('ABOVE') ? <TrendingUp className="w-5 h-5 text-emerald-400" /> : <TrendingDown className="w-5 h-5 text-rose-400" />}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-3 mb-1">
                  <span className="text-white font-black text-lg">{a.symbol}</span>
                  <span className="text-[9px] font-black px-2 py-0.5 rounded-full bg-white/5 text-zinc-500 uppercase tracking-widest">
                    {CONDITIONS[a.condition]?.label || a.condition}
                  </span>
                  {a.ai_suggested && <span className="text-[9px] font-black px-2 py-0.5 rounded-full bg-purple-500/10 text-purple-400">AI SUGGESTED</span>}
                </div>
                <div className="flex items-center gap-4 text-sm">
                  <span className="text-zinc-500">Target: <span className="text-white font-bold font-mono-data">Γé╣{a.target_price.toLocaleString()}</span></span>
                  <span className="text-zinc-500">CMP: <span className={`font-bold font-mono-data ${a.change_pct >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>Γé╣{a.current_price?.toLocaleString()}</span></span>
                  <span className="text-zinc-600 text-xs">Distance: {a.distance_pct}%</span>
                </div>
                {a.note && <p className="text-xs text-zinc-600 mt-1 italic">{a.note}</p>}
              </div>
              <button onClick={() => deleteAlert(a.id)} className="p-2 text-zinc-700 hover:text-rose-400 opacity-0 group-hover:opacity-100 transition-all">
                <Trash2 size={16} />
              </button>
            </motion.div>
          ))}
        </div>
      </div>

      {/* Triggered Alerts */}
      {triggeredAlerts.length > 0 && (
        <div>
          <h2 className="text-xs font-black text-amber-400 uppercase tracking-[0.2em] mb-4">≡ƒöö Triggered Alerts</h2>
          <div className="space-y-3">
            {triggeredAlerts.map(a => (
              <div key={a.id} className="glass-panel p-5 border-amber-500/20 bg-amber-500/[0.02] flex items-center gap-5">
                <div className="w-10 h-10 rounded-xl bg-amber-500/10 flex items-center justify-center">
                  <BellRing className="w-5 h-5 text-amber-400" />
                </div>
                <div className="flex-1">
                  <span className="text-white font-bold">{a.symbol}</span>
                  <span className="text-zinc-500 ml-3 text-sm">hit Γé╣{a.target_price.toLocaleString()}</span>
                </div>
                <button onClick={() => deleteAlert(a.id)} className="text-zinc-600 hover:text-rose-400"><Trash2 size={14} /></button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Create Alert Modal */}
      <AnimatePresence>
        {showCreate && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowCreate(false)} className="absolute inset-0 bg-black/70 backdrop-blur-md" />
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
              className="relative w-full max-w-lg bg-[#0a0a0f] border border-white/[0.08] rounded-3xl overflow-hidden shadow-2xl">
              <div className="p-6 border-b border-white/[0.04] flex items-center justify-between">
                <h3 className="text-lg font-black text-white">Create Price Alert</h3>
                <button onClick={() => setShowCreate(false)} className="p-2 hover:bg-white/5 rounded-full text-zinc-500"><X size={18} /></button>
              </div>
              <div className="p-6 space-y-5">
                {/* Symbol */}
                <div>
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2 block">Stock Symbol</label>
                  <div className="flex gap-2">
                    <input value={symbol} onChange={e => setSymbol(e.target.value.toUpperCase())} placeholder="e.g. RELIANCE"
                      className="flex-1 bg-white/[0.04] border border-white/[0.06] rounded-xl py-3 px-4 text-white text-sm focus:outline-none focus:border-primary/30" />
                    <button onClick={fetchAISuggestions} disabled={suggestLoading}
                      className="px-4 bg-purple-500/10 border border-purple-500/20 text-purple-400 rounded-xl flex items-center gap-2 text-xs font-black hover:bg-purple-500/20 transition-all">
                      <Sparkles size={14} /> AI Suggest
                    </button>
                  </div>
                </div>

                {/* AI Suggestions */}
                <AnimatePresence>
                  {aiSuggestions && (
                    <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }}
                      className="bg-purple-500/5 border border-purple-500/10 rounded-2xl p-4 overflow-hidden">
                      <p className="text-[10px] font-black text-purple-400 uppercase tracking-widest mb-3">≡ƒñû AI Suggested Levels for {aiSuggestions.symbol} (CMP: Γé╣{aiSuggestions.current_price?.toLocaleString()})</p>
                      <div className="grid grid-cols-2 gap-2">
                        {aiSuggestions.suggestions?.map((s, i) => (
                          <button key={i} onClick={() => applySuggestion(s)}
                            className="p-3 bg-white/[0.03] border border-white/[0.06] rounded-xl text-left hover:border-purple-500/30 transition-all">
                            <p className="text-xs font-bold text-zinc-400 mb-1">{s.label}</p>
                            <p className="text-lg font-black text-white font-mono-data">Γé╣{s.price.toLocaleString()}</p>
                            <p className="text-[9px] text-zinc-600 mt-1">{s.confidence}% confidence</p>
                          </button>
                        ))}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>

                {/* Condition */}
                <div>
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2 block">Alert Condition</label>
                  <div className="grid grid-cols-3 gap-2">
                    {Object.entries(CONDITIONS).slice(0, 3).map(([key, val]) => (
                      <button key={key} onClick={() => setCondition(key)}
                        className={`p-3 rounded-xl border text-xs font-bold flex items-center justify-center gap-2 transition-all ${
                          condition === key ? 'border-primary bg-primary/10 text-primary' : 'border-white/[0.06] text-zinc-500 hover:bg-white/[0.03]'
                        }`}>
                        {val.icon} {val.label}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Target Price */}
                <div>
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2 block">Target Price (Γé╣)</label>
                  <input type="number" value={targetPrice} onChange={e => setTargetPrice(e.target.value)} placeholder="e.g. 2500"
                    className="w-full bg-white/[0.04] border border-white/[0.06] rounded-xl py-3 px-4 text-white text-sm focus:outline-none focus:border-primary/30 font-mono-data" />
                </div>

                {/* Note */}
                <div>
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest mb-2 block">Note (Optional)</label>
                  <input value={note} onChange={e => setNote(e.target.value)} placeholder="e.g. Buy at support level"
                    className="w-full bg-white/[0.04] border border-white/[0.06] rounded-xl py-3 px-4 text-white text-sm focus:outline-none focus:border-primary/30" />
                </div>

                <button onClick={createAlert}
                  className="w-full py-4 bg-primary text-black font-black uppercase tracking-widest rounded-2xl hover:bg-primary-hover transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2">
                  <Bell size={16} /> Create Alert
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ShoppingBag, Zap, TrendingUp, Info, ChevronRight, Check, AlertTriangle, Users, Sparkles, ArrowRight, X } from 'lucide-react';
import axios from 'axios';
import { useUser } from '../context/UserContext';
import { useToast } from '../components/Toast';
import { API_BASE_URL } from '../config';

export default function SmartBaskets() {
  const { user } = useUser();
  const { addToast } = useToast();
  const [baskets, setBaskets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBasket, setSelectedBasket] = useState(null);
  const [investAmount, setInvestAmount] = useState('');
  const [buying, setBuying] = useState(false);
  const [buyResult, setBuyResult] = useState(null);

  useEffect(() => {
    fetchBaskets();
  }, []);

  const fetchBaskets = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/api/baskets`);
      setBaskets(res.data.baskets);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleBuy = async () => {
    if (!selectedBasket || !investAmount) return;
    setBuying(true);
    try {
      const res = await axios.post(`${API_BASE_URL}/api/baskets/buy?user_id=${user?.id || 1}`, {
        basket_id: selectedBasket.id,
        investment_amount: parseFloat(investAmount),
      });
      setBuyResult(res.data);
      addToast('success', res.data.message);
    } catch (err) {
      addToast('error', err.response?.data?.detail || 'Purchase failed');
    } finally {
      setBuying(false);
    }
  };

  const handleRebalance = async (basketId) => {
    try {
      const res = await axios.post(`${API_BASE_URL}/api/baskets/rebalance?user_id=${user?.id || 1}`, {
        basket_id: basketId,
        investment_amount: 0 // Not used for rebalance
      });
      addToast('success', res.data.message);
      fetchBaskets();
    } catch (err) {
      addToast('error', err.response?.data?.detail || 'Rebalance failed');
    }
  };

  const riskColor = (risk) => {
    if (risk === 'Low') return 'text-emerald-400 bg-emerald-500/10';
    if (risk === 'Moderate') return 'text-amber-400 bg-amber-500/10';
    return 'text-red-400 bg-red-500/10';
  };

  if (loading) {
    return (
      <div className="h-96 flex items-center justify-center flex-col gap-4">
        <div className="w-12 h-12 border-4 border-primary border-t-transparent rounded-full animate-spin" />
        <p className="text-zinc-500 text-sm">Loading Smart Baskets...</p>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {/* Hero */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="relative overflow-hidden rounded-2xl p-8"
        style={{ background: 'linear-gradient(135deg, rgba(245,158,11,0.12), rgba(236,72,153,0.08))' }}
      >
        <div className="absolute top-0 right-0 w-80 h-80 bg-amber-500/10 rounded-full blur-[120px]" />
        <div className="relative">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-amber-500 to-pink-500 flex items-center justify-center shadow-xl shadow-amber-500/20">
              <ShoppingBag className="w-7 h-7 text-white" />
            </div>
            <div>
              <h1 className="text-3xl font-black text-white">Smart Baskets</h1>
              <p className="text-zinc-400 text-sm">Thematic one-click investing ΓÇö diversify in seconds</p>
            </div>
          </div>
          <div className="flex flex-wrap gap-3 mt-4">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-full">
              <Sparkles size={12} className="text-amber-400" />
              <span className="text-xs text-zinc-400">AI-Curated</span>
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-full">
              <Zap size={12} className="text-blue-400" />
              <span className="text-xs text-zinc-400">One-Click Buy</span>
            </div>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-white/5 border border-white/10 rounded-full">
              <TrendingUp size={12} className="text-emerald-400" />
              <span className="text-xs text-zinc-400">Auto-Weighted</span>
            </div>
          </div>
        </div>
      </motion.div>

      {/* Baskets Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {baskets.map((basket, i) => (
          <motion.div
            key={basket.id}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.08 }}
            className="glass-panel overflow-hidden group hover:border-white/15 transition-all cursor-pointer"
            onClick={() => { setSelectedBasket(basket); setInvestAmount(String(basket.min_investment)); setBuyResult(null); }}
          >
            {/* Color Bar */}
            <div className="h-1" style={{ background: `linear-gradient(90deg, ${basket.color}, transparent)` }} />
            
            <div className="p-6">
              {/* Header */}
              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center gap-3">
                  <span className="text-3xl">{basket.icon}</span>
                  <div>
                    <h3 className="text-lg font-bold text-white group-hover:text-primary transition-colors">{basket.name}</h3>
                    <p className="text-[10px] font-bold text-zinc-600 uppercase tracking-widest">{basket.created_by}</p>
                  </div>
                </div>
              </div>

              <p className="text-xs text-zinc-500 mb-5 leading-relaxed">{basket.description}</p>

              {/* Metrics */}
              <div className="grid grid-cols-3 gap-3 mb-5">
                <div className="bg-white/[0.03] rounded-lg p-2.5 text-center">
                  <p className="text-lg font-black text-emerald-400">{basket.returns_1y}</p>
                  <p className="text-[9px] text-zinc-600 font-bold uppercase">1Y Returns</p>
                </div>
                <div className="bg-white/[0.03] rounded-lg p-2.5 text-center">
                  <p className={`text-sm font-bold px-2 py-0.5 rounded-full inline-block ${riskColor(basket.risk)}`}>{basket.risk}</p>
                  <p className="text-[9px] text-zinc-600 font-bold uppercase mt-1">Risk</p>
                </div>
                <div className="bg-white/[0.03] rounded-lg p-2.5 text-center">
                  <p className="text-sm font-bold text-white">{basket.stocks.length}</p>
                  <p className="text-[9px] text-zinc-600 font-bold uppercase">Stocks</p>
                </div>
              </div>

              {/* Stocks Preview */}
              <div className="space-y-2 mb-5">
                {basket.stocks.slice(0, 3).map((s, j) => (
                  <div key={j} className="flex items-center justify-between text-xs">
                    <div className="flex items-center gap-2">
                      <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: basket.color }} />
                      <span className="text-zinc-400">{s.name}</span>
                    </div>
                    <div className="flex items-center gap-3">
                      <span className="text-zinc-600">{s.weight}%</span>
                      <span className="font-mono text-zinc-300">Γé╣{s.price > 0 ? s.price.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 }) : 'ΓÇö'}</span>
                    </div>
                  </div>
                ))}
                {basket.stocks.length > 3 && (
                  <p className="text-[10px] text-zinc-600 text-center">+{basket.stocks.length - 3} more stocks</p>
                )}
              </div>

              {/* Footer */}
              <div className="flex items-center justify-between pt-4 border-t border-white/[0.04]">
                <div className="flex items-center gap-1.5 text-zinc-600">
                  <Users size={12} />
                  <span className="text-[10px] font-bold">{basket.subscribers?.toLocaleString()} subscribers</span>
                </div>
                <div className="flex items-center gap-3">
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleRebalance(basket.id); }}
                    className="flex items-center gap-1.5 text-[10px] font-black uppercase tracking-widest text-emerald-400 hover:text-emerald-300 transition-colors bg-emerald-500/10 px-2 py-1 rounded-md"
                  >
                    <Zap size={10} className="fill-emerald-400" /> AI Rebalance
                  </button>
                  <div className="flex items-center gap-1.5 text-xs font-bold text-primary group-hover:translate-x-1 transition-transform">
                    Invest Now <ChevronRight size={14} />
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        ))}
      </div>

      {/* Buy Modal */}
      <AnimatePresence>
        {selectedBasket && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
            onClick={() => setSelectedBasket(null)}
          >
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="relative w-full max-w-lg bg-[#0d0d12] border border-white/[0.08] rounded-2xl shadow-2xl overflow-hidden"
              onClick={e => e.stopPropagation()}
            >
              {/* Modal Header */}
              <div className="p-6 border-b border-white/[0.04]">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <span className="text-3xl">{selectedBasket.icon}</span>
                    <div>
                      <h3 className="text-xl font-bold text-white">{selectedBasket.name}</h3>
                      <p className="text-xs text-zinc-500">{selectedBasket.stocks.length} stocks ΓÇó {selectedBasket.risk} Risk</p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedBasket(null)} className="p-2 hover:bg-white/5 rounded-lg transition-colors">
                    <X size={18} className="text-zinc-500" />
                  </button>
                </div>
              </div>

              {buyResult ? (
                /* Success State */
                <div className="p-8 text-center">
                  <div className="w-16 h-16 rounded-full bg-emerald-500/10 flex items-center justify-center mx-auto mb-4">
                    <Check size={32} className="text-emerald-400" />
                  </div>
                  <h3 className="text-xl font-bold text-white mb-2">Basket Purchased! ≡ƒÄë</h3>
                  <p className="text-sm text-zinc-500 mb-6">
                    Invested Γé╣{buyResult.total_invested?.toLocaleString(undefined, { minimumFractionDigits: 2 })} across {buyResult.orders?.length} stocks
                  </p>
                  <div className="space-y-2 mb-6">
                    {buyResult.orders?.map((o, i) => (
                      <div key={i} className="flex items-center justify-between text-sm bg-white/[0.02] rounded-lg px-4 py-2.5">
                        <span className="font-bold text-white">{o.symbol}</span>
                        <span className="text-zinc-500">{o.qty} shares</span>
                        <span className="text-zinc-300 font-mono">Γé╣{o.amount?.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                      </div>
                    ))}
                  </div>
                  <button
                    onClick={() => setSelectedBasket(null)}
                    className="w-full py-3 bg-primary text-black font-bold rounded-xl hover:bg-primary/80 transition-colors"
                  >
                    Done
                  </button>
                </div>
              ) : (
                /* Investment Form */
                <div className="p-6 space-y-6">
                  {/* Stock Allocation */}
                  <div>
                    <h4 className="text-xs font-black text-zinc-500 uppercase tracking-widest mb-3">Stock Allocation</h4>
                    <div className="space-y-2">
                      {selectedBasket.stocks.map((s, i) => (
                        <div key={i} className="flex items-center justify-between text-sm bg-white/[0.02] rounded-lg px-4 py-2.5">
                          <div className="flex items-center gap-3">
                            <div className="w-1.5 h-8 rounded-full" style={{ backgroundColor: selectedBasket.color, opacity: 1 - (i * 0.15) }} />
                            <div>
                              <p className="font-bold text-white">{s.symbol}</p>
                              <p className="text-[10px] text-zinc-600">{s.name}</p>
                            </div>
                          </div>
                          <div className="text-right">
                            <p className="text-sm font-bold" style={{ color: selectedBasket.color }}>{s.weight}%</p>
                            <p className="text-[10px] text-zinc-500 font-mono">Γé╣{s.price > 0 ? s.price.toFixed(2) : 'ΓÇö'}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Weight Bar */}
                  <div className="flex h-2 rounded-full overflow-hidden bg-white/[0.03]">
                    {selectedBasket.stocks.map((s, i) => (
                      <div key={i} style={{ width: `${s.weight}%`, backgroundColor: selectedBasket.color, opacity: 1 - (i * 0.15) }} />
                    ))}
                  </div>

                  {/* Investment Input */}
                  <div>
                    <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-2 block">Investment Amount (Γé╣)</label>
                    <input
                      type="number"
                      value={investAmount}
                      onChange={(e) => setInvestAmount(e.target.value)}
                      min={selectedBasket.min_investment}
                      className="w-full bg-white/[0.03] border border-white/[0.08] rounded-xl py-3.5 px-4 text-xl font-bold text-white focus:outline-none focus:border-primary/40 focus:ring-2 focus:ring-primary/10 transition-all"
                      placeholder={`Min Γé╣${selectedBasket.min_investment}`}
                    />
                    <p className="text-[10px] text-zinc-600 mt-1.5 flex items-center gap-1">
                      <Info size={10} /> Minimum: Γé╣{selectedBasket.min_investment.toLocaleString()}
                    </p>
                  </div>

                  {/* Quick Amount Buttons */}
                  <div className="flex gap-2">
                    {[5000, 10000, 25000, 50000].map(amt => (
                      <button
                        key={amt}
                        onClick={() => setInvestAmount(String(amt))}
                        className={`flex-1 py-2 text-xs font-bold rounded-lg border transition-all ${
                          investAmount === String(amt)
                            ? 'bg-primary/10 border-primary/30 text-primary'
                            : 'bg-white/[0.02] border-white/[0.06] text-zinc-500 hover:text-white hover:bg-white/[0.04]'
                        }`}
                      >
                        Γé╣{(amt/1000)}K
                      </button>
                    ))}
                  </div>

                  {/* Buy Button */}
                  <button
                    onClick={handleBuy}
                    disabled={buying || !investAmount || parseFloat(investAmount) < selectedBasket.min_investment}
                    className="w-full py-4 bg-gradient-to-r from-amber-500 to-pink-500 text-white font-black rounded-xl flex items-center justify-center gap-2 hover:opacity-90 transition-opacity disabled:opacity-30 shadow-lg shadow-amber-500/20 text-sm"
                  >
                    {buying ? (
                      <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> Processing...</>
                    ) : (
                      <><ShoppingBag size={16} /> Invest Γé╣{Number(investAmount || 0).toLocaleString()} in {selectedBasket.name}</>
                    )}
                  </button>

                  <p className="text-[9px] text-zinc-600 text-center flex items-center justify-center gap-1">
                    <AlertTriangle size={9} /> Investment is subject to market risks. Read all documents carefully.
                  </p>
                </div>
              )}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { TrendingUp, TrendingDown, ArrowUpRight, ArrowDownRight, Zap, Globe, Building, BarChart2, RefreshCw, ArrowRight, AlertTriangle } from 'lucide-react';
import axios from 'axios';
import { API_BASE_URL } from '../config';
import { AreaChart, Area, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell } from 'recharts';

const fadeUp = { hidden: { opacity: 0, y: 20 }, show: { opacity: 1, y: 0, transition: { duration: 0.5 } } };

export default function SmartMoneyFlow() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [period, setPeriod] = useState('1M');

  useEffect(() => {
    setLoading(true);
    axios.get(`${API_BASE_URL}/api/smartmoney/flow?period=${period}`)
      .then(res => setData(res.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [period]);

  const CustomTooltip = ({ active, payload }) => {
    if (active && payload && payload.length) {
      const d = payload[0].payload;
      return (
        <div className="bg-[#0a0a12]/95 backdrop-blur-xl border border-white/10 p-4 rounded-2xl shadow-2xl min-w-[200px]">
          <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2">{d.date}</p>
          <div className="space-y-1.5">
            <div className="flex justify-between"><span className="text-xs text-sky-400 font-bold">FII Net</span><span className={`text-xs font-black ${d.fii_net >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>Γé╣{d.fii_net?.toLocaleString()} Cr</span></div>
            <div className="flex justify-between"><span className="text-xs text-amber-400 font-bold">DII Net</span><span className={`text-xs font-black ${d.dii_net >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>Γé╣{d.dii_net?.toLocaleString()} Cr</span></div>
          </div>
        </div>
      );
    }
    return null;
  };

  if (loading) {
    return (
      <div className="h-96 flex items-center justify-center flex-col gap-4">
        <RefreshCw className="w-8 h-8 text-sky-400 animate-spin" />
        <p className="text-zinc-400 font-bold animate-pulse text-sm">Tracking institutional flows...</p>
      </div>
    );
  }

  if (!data) return null;

  return (
    <motion.div variants={fadeUp} initial="hidden" animate="show" className="space-y-8">
      {/* Header */}
      <div className="relative overflow-hidden rounded-[28px] border border-white/[0.06] bg-gradient-to-br from-[#020a18] via-surface to-surface p-8 md:p-12">
        <div className="absolute top-0 right-0 w-[400px] h-[400px] bg-sky-500/10 rounded-full blur-[150px] pointer-events-none" />
        <div className="absolute bottom-0 left-0 w-[250px] h-[250px] bg-amber-500/5 rounded-full blur-[100px] pointer-events-none" />
        <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-14 h-14 rounded-2xl bg-gradient-to-br from-sky-500/20 to-blue-600/20 border border-sky-500/20 flex items-center justify-center">
              <Building className="w-7 h-7 text-sky-400" />
            </div>
            <div>
              <h1 className="text-3xl md:text-4xl font-black text-white">Smart Money Flow</h1>
              <p className="text-zinc-500 text-sm mt-0.5">Track FII/DII institutional movements in real-time</p>
            </div>
          </div>
          
          {/* Period Selector */}
          <div className="flex gap-2">
            {['1W', '1M', '3M', '6M', '1Y'].map(p => (
              <button key={p} onClick={() => setPeriod(p)}
                className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all border ${
                  period === p ? 'bg-sky-500/15 border-sky-500/30 text-sky-400' : 'bg-white/[0.02] border-white/[0.06] text-zinc-500 hover:text-white'
                }`}>{p}</button>
            ))}
          </div>
        </div>
      </div>

      {/* AI Signal Banner */}
      <div className={`rounded-2xl border p-6 flex items-center gap-6 ${
        data.ai_signal?.includes('ACCUMULATION') || data.ai_signal?.includes('RALLY') ? 'bg-emerald-500/5 border-emerald-500/20' :
        data.ai_signal?.includes('EXODUS') ? 'bg-red-500/5 border-red-500/20' : 'bg-amber-500/5 border-amber-500/20'
      }`}>
        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center ${
          data.ai_signal?.includes('ACCUMULATION') || data.ai_signal?.includes('RALLY') ? 'bg-emerald-500/15' :
          data.ai_signal?.includes('EXODUS') ? 'bg-red-500/15' : 'bg-amber-500/15'
        }`}>
          <Zap className={`w-7 h-7 ${
            data.ai_signal?.includes('ACCUMULATION') || data.ai_signal?.includes('RALLY') ? 'text-emerald-400' :
            data.ai_signal?.includes('EXODUS') ? 'text-red-400' : 'text-amber-400'
          }`} />
        </div>
        <div className="flex-1">
          <h3 className="text-lg font-black text-white">{data.ai_signal}</h3>
          <p className="text-sm text-zinc-400 mt-1">{data.ai_detail}</p>
        </div>
        <div className="live-dot" />
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'FII Net Flow', value: `Γé╣${Math.abs(data.summary?.total_fii_net).toLocaleString()} Cr`, positive: data.summary?.total_fii_net >= 0, trend: data.summary?.fii_trend, icon: <Globe className="w-4 h-4" />, color: 'sky' },
          { label: 'DII Net Flow', value: `Γé╣${Math.abs(data.summary?.total_dii_net).toLocaleString()} Cr`, positive: data.summary?.total_dii_net >= 0, trend: data.summary?.dii_trend, icon: <Building className="w-4 h-4" />, color: 'amber' },
          { label: 'Total Net', value: `Γé╣${Math.abs(data.summary?.total_net).toLocaleString()} Cr`, positive: data.summary?.total_net >= 0, icon: <BarChart2 className="w-4 h-4" />, color: 'violet' },
          { label: 'Block Deals', value: data.block_deals?.length || 0, icon: <AlertTriangle className="w-4 h-4" />, color: 'rose', positive: true },
        ].map((m, i) => (
          <div key={i} className="glass-panel p-5 border border-white/[0.04] group hover:border-white/[0.1] transition-all">
            <div className={`flex items-center gap-2 mb-3 text-${m.color}-400`}>
              {m.icon}
              <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest">{m.label}</span>
            </div>
            <p className="text-xl font-black text-white font-mono-data flex items-center gap-2">
              {m.positive !== undefined && (m.positive ?
                <ArrowUpRight className="w-4 h-4 text-emerald-400" /> :
                <ArrowDownRight className="w-4 h-4 text-red-400" />
              )}
              {m.value}
            </p>
            {m.trend && <p className={`text-[10px] font-black uppercase tracking-widest mt-1 ${m.positive ? 'text-emerald-400' : 'text-red-400'}`}>{m.trend}</p>}
          </div>
        ))}
      </div>

      {/* Cumulative Flow Chart */}
      <div className="glass-panel p-6 border border-white/[0.04]">
        <h3 className="text-xs font-black text-white uppercase tracking-widest mb-6 flex items-center gap-2">
          <BarChart2 className="w-4 h-4 text-sky-400" /> Cumulative Flow
        </h3>
        <div className="h-[350px]">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={data.daily_flow} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
              <defs>
                <linearGradient id="fiiGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#0ea5e9" stopOpacity={0} />
                </linearGradient>
                <linearGradient id="diiGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
                  <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#ffffff08" vertical={false} />
              <XAxis dataKey="date" stroke="#52525b" tick={{ fill: '#71717a', fontSize: 10 }} minTickGap={40} />
              <YAxis stroke="#52525b" tick={{ fill: '#71717a', fontSize: 10 }} tickFormatter={v => `Γé╣${v}`} />
              <ReferenceLine y={0} stroke="#ffffff15" strokeDasharray="3 3" />
              <Tooltip content={<CustomTooltip />} />
              <Area type="monotone" dataKey="cumulative_fii" name="FII Cumulative" stroke="#0ea5e9" strokeWidth={2.5} fill="url(#fiiGrad)" />
              <Area type="monotone" dataKey="cumulative_dii" name="DII Cumulative" stroke="#f59e0b" strokeWidth={2.5} fill="url(#diiGrad)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
        <div className="flex items-center gap-6 mt-4 justify-center">
          <div className="flex items-center gap-2"><div className="w-3 h-1 bg-sky-500 rounded-full" /><span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">FII Flow</span></div>
          <div className="flex items-center gap-2"><div className="w-3 h-1 bg-amber-500 rounded-full" /><span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">DII Flow</span></div>
        </div>
      </div>

      {/* Daily Net Flow Bar Chart */}
      <div className="glass-panel p-6 border border-white/[0.04]">
        <h3 className="text-xs font-black text-white uppercase tracking-widest mb-6 flex items-center gap-2">
          <TrendingUp className="w-4 h-4 text-emerald-400" /> Daily Net Flow
        </h3>
        <div className="h-[250px]">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data.daily_flow?.slice(-22)} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#ffffff08" vertical={false} />
              <XAxis dataKey="date" stroke="#52525b" tick={{ fill: '#71717a', fontSize: 9 }} minTickGap={30} />
              <YAxis stroke="#52525b" tick={{ fill: '#71717a', fontSize: 10 }} />
              <ReferenceLine y={0} stroke="#ffffff15" />
              <Tooltip content={<CustomTooltip />} />
              <Bar dataKey="total_net" radius={[4, 4, 0, 0]}>
                {data.daily_flow?.slice(-22).map((entry, index) => (
                  <Cell key={index} fill={entry.total_net >= 0 ? '#10b981' : '#ef4444'} fillOpacity={0.7} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Sector Flow + Block Deals */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
