                  <span className="text-[10px] text-zinc-500 font-bold">{deal.buyer} ΓÇó {deal.quantity?.toLocaleString()} qty</span>
                  <span className="text-sm font-black text-amber-400">Γé╣{deal.value_cr} Cr</span>
                </div>
              </div>
            ))}
          </div>
