                          }`}>{entry.type}</span>
                        </td>
                        <td className="px-5 py-3 text-xs text-zinc-400 font-mono">{entry.quantity}</td>
                        <td className="px-5 py-3 text-xs text-zinc-300 font-mono">Γé╣{entry.price?.toFixed(2)}</td>
                        <td className="px-5 py-3 text-xs text-white font-mono font-bold">Γé╣{entry.amount?.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
